#[test]
fn observations_for_prompt_persists_largest_items_before_tail_fallback() {
    let dir = std::env::temp_dir().join(format!("synthchat-observation-budget-{}", new_id("test")));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    let mut config = store.config().unwrap();
    config.chat.tool_observation_turn_budget_chars = 900;
    config.chat.tool_observation_tail_budget_chars = 300;
    config.chat.tool_result_preview_chars = 80;
    store.set_config(config).unwrap();

    let observations = vec![
        "small observation A".to_string(),
        format!("large observation\n{}", "x".repeat(2_000)),
        "small observation B".to_string(),
    ];
    let compacted = observations_for_prompt(&store, "run-observation-budget", &observations)
        .unwrap()
        .join("\n");

    assert!(compacted.contains("largest observations were persisted individually"));
    assert!(compacted.contains("reason=\"turn-budget\""));
    assert!(compacted.contains("small observation A"));
    assert!(compacted.contains("small observation B"));

    let _ = fs::remove_dir_all(dir);
}

#[tokio::test]
async fn process_tool_uses_configured_output_tail_limit() {
    let dir = std::env::temp_dir().join(format!("synthchat-process-tail-{}", new_id("test")));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    let mut config = store.config().unwrap();
    config.chat.tool_output_max_lines = 2;
    store.set_config(config).unwrap();
    let mut agent = AgentDefinition::default();
    agent.workspace_dir = dir.to_string_lossy().to_string();
    #[cfg(windows)]
    let command = "1..5 | ForEach-Object { Write-Output $_ }";
    #[cfg(not(windows))]
    let command = "for i in 1 2 3 4 5; do echo $i; done";

    let started = process_tool(
        &store,
        &agent,
        "conv-process-tail",
        "run-process-tail",
        &json!({
            "action": "start",
            "command": command,
            "label": "tail-test",
            "notifyOnComplete": true
        }),
        None,
    )
    .await
    .unwrap();
    let started: Value = serde_json::from_str(&started).unwrap();
    assert_eq!(started["conversation_id"], "conv-process-tail");
    assert_eq!(started["run_id"], "run-process-tail");
    let process_id = started["id"].as_str().unwrap();
    let listed = process_tool(
        &store,
        &agent,
        "conv-process-tail",
        "run-process-tail",
        &json!({"action": "list", "runId": "run-process-tail"}),
        None,
    )
    .await
    .unwrap();
    let listed: Value = serde_json::from_str(&listed).unwrap();
    assert_eq!(listed["action"], "list");
    assert_eq!(listed["count"], 1);
    assert_eq!(listed["processes"][0]["session_id"], process_id);
    tokio::time::sleep(std::time::Duration::from_millis(300)).await;
    let state = process_tool(
        &store,
        &agent,
        "conv-process-tail",
        "run-process-tail",
        &json!({"action": "state", "processId": process_id}),
        None,
    )
    .await
    .unwrap();
    let state: Value = serde_json::from_str(&state).unwrap();
    assert_eq!(state["tailRetentionLinesPerStream"], 2);
    assert!(state["stdoutTail"].as_array().unwrap().len() <= 2);

    let _ = fs::remove_dir_all(dir);
}

#[tokio::test]
async fn process_wait_returns_early_when_agent_run_is_aborted() {
    let dir = std::env::temp_dir().join(format!("synthchat-process-wait-abort-{}", new_id("test")));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    let persona = store.persona(None).unwrap();
    let conversation = store
        .create_conversation(Some("Process Wait Abort".into()), Some(persona.id.clone()))
        .unwrap();
    let run = store
        .save_agent_run(AgentRunRecord::new(
            conversation.id.clone(),
            persona.id,
            conversation.agent_id.clone(),
        ))
        .unwrap();
    let mut agent = AgentDefinition::default();
    agent.workspace_dir = dir.to_string_lossy().to_string();
    #[cfg(windows)]
    let command = "Start-Sleep -Seconds 5; Write-Output done";
    #[cfg(not(windows))]
    let command = "sleep 5; echo done";

    let started = process_tool(
        &store,
        &agent,
        &conversation.id,
        &run.run_id,
        &json!({
            "action": "start",
            "command": command,
            "label": "wait-abort-test"
        }),
        None,
    )
    .await
    .unwrap();
    let started: Value = serde_json::from_str(&started).unwrap();
    let process_id = started["id"].as_str().unwrap();
    store
        .abort_agent_run(&run.run_id, Some("test abort".into()))
        .unwrap();

    let wait_started = Instant::now();
    let waited = process_tool(
        &store,
        &agent,
        &conversation.id,
        &run.run_id,
        &json!({
            "action": "wait",
            "processId": process_id,
            "timeoutSeconds": 10
        }),
        None,
    )
    .await
    .unwrap();
    let waited: Value = serde_json::from_str(&waited).unwrap();

    assert!(wait_started.elapsed() < Duration::from_secs(1));
    assert_eq!(waited["waitInterrupted"], true);
    assert_eq!(waited["waitInterruptedReason"], "agent_run_aborted");
    assert_eq!(waited["waitTimedOut"], false);
    let _ = process_tool(
        &store,
        &agent,
        &conversation.id,
        &run.run_id,
        &json!({"action": "stop", "processId": process_id, "forget": true}),
        None,
    )
    .await;

    let _ = fs::remove_dir_all(dir);
}

#[tokio::test]
async fn foreground_terminal_returns_early_when_agent_run_is_aborted() {
    let _guard = CHANNEL_DIRECTORY_ENV_LOCK.lock().unwrap();
    let old_terminal_env = std::env::var_os("TERMINAL_ENV");
    std::env::set_var("TERMINAL_ENV", "local");
    let dir = std::env::temp_dir().join(format!("synthchat-terminal-abort-{}", new_id("test")));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    let persona = store.persona(None).unwrap();
    let conversation = store
        .create_conversation(Some("Terminal Abort".into()), Some(persona.id.clone()))
        .unwrap();
    let run = store
        .save_agent_run(AgentRunRecord::new(
            conversation.id.clone(),
            persona.id,
            conversation.agent_id.clone(),
        ))
        .unwrap();
    let mut agent = store.agent(None).unwrap();
    agent.workspace_dir = dir.to_string_lossy().to_string();
    #[cfg(windows)]
    let command = "Start-Sleep -Seconds 5; Write-Output done";
    #[cfg(not(windows))]
    let command = "sleep 5; echo done";
    let abort_store = store.clone();
    let abort_run_id = run.run_id.clone();
    tokio::spawn(async move {
        tokio::time::sleep(Duration::from_millis(200)).await;
        let _ = abort_store.abort_agent_run(&abort_run_id, Some("test abort".into()));
    });

    let started = Instant::now();
    let result = terminal_tool(
        &store,
        &agent,
        &json!({
            "command": command,
            "cwd": dir.to_string_lossy(),
            "runId": run.run_id,
            "timeoutSeconds": 10
        }),
    )
    .await;

    assert!(started.elapsed() < Duration::from_secs(2));
    assert!(result
        .unwrap_err()
        .to_string()
        .contains("agent run is no longer active"));

    restore_test_env("TERMINAL_ENV", old_terminal_env);
    let _ = fs::remove_dir_all(dir);
}

