#[tokio::test]
async fn backup_and_import_control_commands_return_managed_process_plans() {
    let dir = std::env::temp_dir().join(format!("synthchat-backup-control-{}", new_id("test")));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    let persona = store.persona(None).unwrap();
    let conversation = store
        .create_conversation(Some("Backup".into()), Some(persona.id.clone()))
        .unwrap();

    let backup_reply = handle_agent_control_command(
        &store,
        &conversation,
        &persona,
        "/backup --quick --label nightly --output \"D:\\backups\\hermes home.zip\"",
        None,
    )
    .await
    .unwrap()
    .unwrap();
    let backup: Value = serde_json::from_str(&backup_reply.content).unwrap();
    assert_eq!(backup["schema"], "hermes_backup_cli_plan_desktop_v1");
    assert_eq!(backup["status"], "external_cli_plan");
    assert_eq!(backup["action"], "backup");
    assert_eq!(backup["requiresApproval"], true);
    assert!(backup["boundary"]
        .as_str()
        .unwrap()
        .contains("managed-process plan"));
    let backup_command = backup["command"].as_str().unwrap();
    assert!(backup_command.contains("hermes backup --quick --label nightly --output"));
    assert!(backup_command.contains("\"D:\\backups\\hermes home.zip\""));
    assert_eq!(
        backup["managedProcessStartPayload"]["command"]
            .as_str()
            .unwrap(),
        backup_command
    );

    let import_reply = handle_agent_control_command(
        &store,
        &conversation,
        &persona,
        "/import \"D:\\backups\\hermes home.zip\" --force",
        None,
    )
    .await
    .unwrap()
    .unwrap();
    let import: Value = serde_json::from_str(&import_reply.content).unwrap();
    assert_eq!(import["schema"], "hermes_backup_cli_plan_desktop_v1");
    assert_eq!(import["status"], "external_cli_plan");
    assert_eq!(import["action"], "import");
    assert_eq!(import["requiresApproval"], true);
    assert!(import["command"]
        .as_str()
        .unwrap()
        .contains("hermes import \"D:\\backups\\hermes home.zip\" --force"));
    assert!(import["boundary"].as_str().unwrap().contains("overwrite"));
    assert_eq!(
        import["managed_process_start_payload"]["command"]
            .as_str()
            .unwrap(),
        import["command"].as_str().unwrap()
    );

    let _ = fs::remove_dir_all(dir);
}

