#[tokio::test]
async fn goal_and_subgoal_control_commands_manage_standing_goal() {
    let dir = std::env::temp_dir().join(format!("synthchat-goal-control-{}", new_id("test")));
    std::fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    let persona = store.persona(None).unwrap();
    let conversation = store
        .create_conversation(Some("Goal".into()), Some(persona.id.clone()))
        .unwrap();

    let set_reply = handle_agent_control_command(
        &store,
        &conversation,
        &persona,
        "/goal ship Hermes parity --max-turns 5",
        None,
    )
    .await
    .unwrap()
    .unwrap();
    assert!(set_reply.content.contains("standing goal"));
    let state = goal_state::agent_goal_status(&store, &conversation.id)
        .unwrap()
        .unwrap();
    assert_eq!(state.goal, "ship Hermes parity");
    assert_eq!(state.max_turns, 5);

    let subgoal_reply = handle_agent_control_command(
        &store,
        &conversation,
        &persona,
        "/subgoal preserve queue visibility",
        None,
    )
    .await
    .unwrap()
    .unwrap();
    assert!(subgoal_reply.content.contains("preserve queue visibility"));
    let state = goal_state::agent_goal_status(&store, &conversation.id)
        .unwrap()
        .unwrap();
    assert_eq!(state.subgoals, vec!["preserve queue visibility"]);

    let paused = handle_agent_control_command(&store, &conversation, &persona, "/goal pause", None)
        .await
        .unwrap()
        .unwrap();
    assert!(paused.content.contains("paused"));
    assert_eq!(
        goal_state::agent_goal_status(&store, &conversation.id)
            .unwrap()
            .unwrap()
            .status,
        "paused"
    );

    handle_agent_control_command(&store, &conversation, &persona, "/goal resume", None)
        .await
        .unwrap()
        .unwrap();
    assert_eq!(
        goal_state::agent_goal_status(&store, &conversation.id)
            .unwrap()
            .unwrap()
            .status,
        "active"
    );

    let removed =
        handle_agent_control_command(&store, &conversation, &persona, "/subgoal remove 1", None)
            .await
            .unwrap()
            .unwrap();
    assert!(removed.content.contains("没有 subgoals"));

    handle_agent_control_command(&store, &conversation, &persona, "/goal clear", None)
        .await
        .unwrap()
        .unwrap();
    assert!(goal_state::agent_goal_status(&store, &conversation.id)
        .unwrap()
        .is_none());

    let _ = std::fs::remove_dir_all(dir);
}

