#[tokio::test]
async fn python_plugin_slash_command_runs_before_planner() {
    let dir = std::env::temp_dir().join(format!("synthchat-plugin-command-{}", new_id("test")));
    let plugin_dir = dir.join("plugins").join("demo-command");
    let tool_plugin_dir = dir.join("plugins").join("demo-cross-tool");
    fs::create_dir_all(&plugin_dir).unwrap();
    fs::create_dir_all(&tool_plugin_dir).unwrap();
    fs::write(
        plugin_dir.join("__init__.py"),
        r#"
def _handle(raw_args):
    return "plugin command handled: " + raw_args

def _handle_cli(raw_args):
    return "plugin cli command handled: " + raw_args

def _handle_tool(args, **kwargs):
    return {"handled": args.get("value", ""), "extra": kwargs.get("extra", "")}

def _setup_cli(_parser):
    return None

def register(ctx):
    def _handle_inject(raw_args):
        ctx.inject_message("injected by plugin: " + raw_args)
        return "plugin injected"

    def _handle_dispatch(raw_args):
        return ctx.dispatch_tool("demo_inner_tool", {"value": raw_args}, extra="from-command")

    def _handle_cross_dispatch(raw_args):
        return ctx.dispatch_tool("demo_cross_tool", {"value": raw_args}, extra="from-cross-command")

    def _handle_builtin_dispatch(raw_args):
        return ctx.dispatch_tool("kanban_list", {"limit": 5})

    def _handle_builtin_mutation(raw_args):
        return ctx.dispatch_tool("kanban_create", {"taskId": "kb-plugin-denied", "title": "Denied"})

    ctx.register_tool(
        name="demo_inner_tool",
        toolset="demo",
        schema={"type": "object", "properties": {"value": {"type": "string"}}},
        handler=_handle_tool,
    )
    ctx.register_command(
        "demo-plugin",
        handler=_handle,
        description="Demo command",
    )
    ctx.register_command(
        "demo-inject",
        handler=_handle_inject,
        description="Demo injected command",
    )
    ctx.register_command(
        "demo-dispatch",
        handler=_handle_dispatch,
        description="Demo dispatch command",
    )
    ctx.register_command(
        "demo-cross-dispatch",
        handler=_handle_cross_dispatch,
        description="Demo cross-plugin dispatch command",
    )
    ctx.register_command(
        "demo-kanban-list",
        handler=_handle_builtin_dispatch,
        description="Demo built-in dispatch command",
    )
    ctx.register_command(
        "demo-kanban-create",
        handler=_handle_builtin_mutation,
        description="Demo built-in mutation command",
    )
    ctx.register_cli_command(
        "demo-cli",
        "Demo CLI command",
        _setup_cli,
        handler_fn=_handle_cli,
    )
"#,
    )
    .unwrap();
    fs::write(
        tool_plugin_dir.join("__init__.py"),
        r#"
def _handle_cross_tool(args, **kwargs):
    return {"cross": args.get("value", ""), "extra": kwargs.get("extra", "")}

def register(ctx):
    ctx.register_tool(
        name="demo_cross_tool",
        toolset="demo",
        schema={"type": "object", "properties": {"value": {"type": "string"}}},
        handler=_handle_cross_tool,
    )
"#,
    )
    .unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    store
        .set_plugins(vec![
            crate::models::PluginSummary {
                id: "demo-command".into(),
                name: "demo-command".into(),
                description: "test plugin command".into(),
                enabled: true,
                provided_tools: vec![],
                provided_capabilities: vec![],
                missing_env: vec![],
                env_configured: true,
                provided_hooks: vec![],
                requires_env: vec![],
                version: "0.1.0".into(),
                author: "test".into(),
                source: "test".into(),
                homepage_url: String::new(),
                kind: "standalone".into(),
                path: plugin_dir.display().to_string(),
                manifest_path: plugin_dir.join("plugin.yaml").display().to_string(),
                entry_point: String::new(),
            },
            crate::models::PluginSummary {
                id: "demo-cross-tool".into(),
                name: "demo-cross-tool".into(),
                description: "test cross plugin tool".into(),
                enabled: true,
                provided_tools: vec![],
                provided_capabilities: vec![],
                missing_env: vec![],
                env_configured: true,
                provided_hooks: vec![],
                requires_env: vec![],
                version: "0.1.0".into(),
                author: "test".into(),
                source: "test".into(),
                homepage_url: String::new(),
                kind: "standalone".into(),
                path: tool_plugin_dir.display().to_string(),
                manifest_path: tool_plugin_dir.join("plugin.yaml").display().to_string(),
                entry_point: String::new(),
            },
        ])
        .unwrap();
    let persona = store.persona(None).unwrap();
    let conversation = store
        .create_conversation(Some("Plugin Command".into()), Some(persona.id.clone()))
        .unwrap();
    kanban_create_tool(
        &store,
        &json!({"taskId": "kb-plugin-bridge", "title": "Plugin bridge task"}),
    )
    .unwrap();

    let reply = handle_agent_control_command(
        &store,
        &conversation,
        &persona,
        "/demo-plugin hello world",
        None,
    )
    .await
    .unwrap()
    .unwrap();
    assert_eq!(reply.content, "plugin command handled: hello world");

    let injected_reply = handle_agent_control_command(
        &store,
        &conversation,
        &persona,
        "/demo-inject hello injected",
        None,
    )
    .await
    .unwrap()
    .unwrap();
    assert_eq!(injected_reply.content, "plugin injected");
    let messages = store.messages(&conversation.id, None).unwrap();
    assert!(messages.iter().any(|message| message.role == "user"
        && message.content == "injected by plugin: hello injected"
        && message.source == "python-plugin"));

    let dispatch_reply = handle_agent_control_command(
        &store,
        &conversation,
        &persona,
        "/demo-dispatch hello dispatch",
        None,
    )
    .await
    .unwrap()
    .unwrap();
    assert!(dispatch_reply
        .content
        .contains("\"handled\": \"hello dispatch\""));
    assert!(dispatch_reply
        .content
        .contains("\"extra\": \"from-command\""));

    let cross_dispatch_reply = handle_agent_control_command(
        &store,
        &conversation,
        &persona,
        "/demo-cross-dispatch hello cross",
        None,
    )
    .await
    .unwrap()
    .unwrap();
    assert!(cross_dispatch_reply
        .content
        .contains("\"cross\": \"hello cross\""));
    assert!(cross_dispatch_reply
        .content
        .contains("\"extra\": \"from-cross-command\""));

    let builtin_dispatch_reply =
        handle_agent_control_command(&store, &conversation, &persona, "/demo-kanban-list", None)
            .await
            .unwrap()
            .unwrap();
    assert!(builtin_dispatch_reply
        .content
        .contains("Plugin bridge task"));
    assert!(builtin_dispatch_reply.content.contains("kb-plugin-bridge"));

    let denied_builtin_mutation =
        handle_agent_control_command(&store, &conversation, &persona, "/demo-kanban-create", None)
            .await
            .expect_err("plugin command bridge should reject mutating tools without run context");
    assert!(denied_builtin_mutation
        .to_string()
        .contains("requires agent run context"));

    let cli_reply =
        handle_agent_control_command(&store, &conversation, &persona, "/demo-cli hello cli", None)
            .await
            .unwrap()
            .unwrap();
    assert_eq!(cli_reply.content, "plugin cli command handled: hello cli");

    let help_reply = handle_agent_control_command(&store, &conversation, &persona, "/help", None)
        .await
        .unwrap()
        .unwrap();
    assert!(help_reply.content.contains("Plugin commands"));
    assert!(help_reply.content.contains("/demo-plugin"));
    assert!(help_reply.content.contains("/demo-cli"));

    let unknown = handle_agent_control_command(
        &store,
        &conversation,
        &persona,
        "/unknown-plugin hello world",
        None,
    )
    .await
    .unwrap();
    assert!(unknown.is_none());

    let _ = fs::remove_dir_all(dir);
}

#[tokio::test]
async fn direct_skill_bundle_slash_command_installs_bundle_before_planner() {
    let dir = std::env::temp_dir().join(format!("synthchat-bundle-slash-{}", new_id("test")));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    store
        .set_skills(vec![
            test_skill_summary(
                "research/web",
                "Research Web",
                "Inspect web sources.",
                false,
                dir.join("research-web").to_string_lossy().to_string(),
            ),
            test_skill_summary(
                "research/sources",
                "Research Sources",
                "Cross-check source claims.",
                false,
                dir.join("research-sources").to_string_lossy().to_string(),
            ),
            test_skill_summary(
                "writing/notes",
                "Writing Notes",
                "Draft concise notes.",
                false,
                dir.join("notes").to_string_lossy().to_string(),
            ),
        ])
        .unwrap();
    let persona = store.persona(None).unwrap();
    let conversation = store
        .create_conversation(Some("Bundle Slash".into()), Some(persona.id.clone()))
        .unwrap();

    let reply = handle_agent_control_command(&store, &conversation, &persona, "/research", None)
        .await
        .unwrap()
        .unwrap();

    assert!(reply.content.contains("已通过 /research 加载 skill bundle"));
    assert!(reply.content.contains("research/web"));
    assert!(reply.content.contains("research/sources"));
    let agent = store.agent(Some(&conversation.agent_id)).unwrap();
    assert_eq!(
        agent.enabled_skills,
        vec!["research/web", "research/sources"]
    );

    let unknown =
        handle_agent_control_command(&store, &conversation, &persona, "/missing-bundle", None)
            .await
            .unwrap();
    assert!(unknown.is_none());

    let _ = fs::remove_dir_all(dir);
}

