    let persona = store.persona(None).unwrap();
    let conversation = store
        .create_conversation(Some("Plugin Tool Bridge".into()), Some(persona.id.clone()))
        .unwrap();
    let bridge_run_id = "run-python-plugin-bridge-tool-test";
