#[test]
fn agent_auxiliary_tasks_include_builtin_and_plugin_defaults() {
    let dir = std::env::temp_dir().join(format!("synthchat-agent-aux-{}", new_id("test")));
    let plugin_dir = dir.join("plugins").join("demo-agent-aux");
    fs::create_dir_all(&plugin_dir).unwrap();
    fs::write(
        plugin_dir.join("__init__.py"),
        r#"
def register(ctx):
    ctx.register_auxiliary_task(
        key="demo_agent_aux",
        display_name="Demo agent auxiliary",
        description="Demo full auxiliary catalog task",
        defaults={"provider": "demo-provider", "model": "demo-model", "timeout": 45},
    )
"#,
    )
    .unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    store
        .set_plugins(vec![crate::models::PluginSummary {
            id: "demo-agent-aux".into(),
            name: "demo-agent-aux".into(),
            description: "test full auxiliary task".into(),
            enabled: true,
            provided_tools: vec![],
            provided_capabilities: vec![],
            missing_env: vec![],
            env_configured: true,
            provided_hooks: vec![],
            requires_env: vec![],
            version: "0.1.0".into(),
            author: "test".into(),
            source: "test".into(),
            homepage_url: String::new(),
            kind: "standalone".into(),
            path: plugin_dir.display().to_string(),
            manifest_path: plugin_dir.join("plugin.yaml").display().to_string(),
            entry_point: String::new(),
        }])
        .unwrap();

    let tasks = list_agent_auxiliary_tasks(&store).unwrap();
    let compression = tasks
        .iter()
        .find(|task| task.key == "compression")
        .expect("compression auxiliary task should be listed");
    assert_eq!(compression.source, "builtin");
    assert_eq!(compression.display_name, "Compression");
    assert_eq!(compression.defaults["provider"], "auto");
    assert_eq!(compression.defaults["timeout"], 120);
    assert_eq!(
        agent_auxiliary_task_defaults(&store, "vision").unwrap()["timeout"],
        120
    );
    assert_eq!(
        agent_auxiliary_task_defaults(&store, "vision").unwrap()["download_timeout"],
        30
    );
    assert_eq!(
        agent_auxiliary_task_defaults(&store, "web_extract").unwrap()["timeout"],
        360
    );
    assert_eq!(
        agent_auxiliary_task_defaults(&store, "goal_judge").unwrap()["timeout"],
        30
    );
    assert_eq!(
        agent_auxiliary_task_defaults(&store, "kanban_decomposer").unwrap()["timeout"],
        180
    );
    assert_eq!(
        agent_auxiliary_task_defaults(&store, "curator").unwrap()["timeout"],
        600
    );
    let plugin_task = tasks
        .iter()
        .find(|task| task.key == "demo_agent_aux")
        .expect("plugin auxiliary task should be included in full catalog");
    assert_eq!(plugin_task.source, "python-plugin");
    assert_eq!(plugin_task.plugin_id, "demo-agent-aux");
    assert_eq!(plugin_task.defaults["provider"], "demo-provider");
    assert_eq!(plugin_task.defaults["model"], "demo-model");
    assert_eq!(plugin_task.defaults["timeout"], 45);
    assert_eq!(
        agent_auxiliary_task_defaults(&store, "demo_agent_aux").unwrap()["model"],
        "demo-model"
    );
    let assignments = list_agent_auxiliary_task_assignments(&store).unwrap();
    let initial = assignments
        .iter()
        .find(|task| task.key == "demo_agent_aux")
        .expect("plugin auxiliary assignment should be listed");
    assert_eq!(initial.provider, "demo-provider");
    assert_eq!(initial.model, "demo-model");
    assert_eq!(initial.timeout, 45);
    let initial_curator = assignments
        .iter()
        .find(|task| task.key == "curator")
        .expect("curator auxiliary assignment should inherit Hermes defaults");
    assert_eq!(initial_curator.provider, "auto");
    assert_eq!(initial_curator.timeout, 600);

    let updated = save_agent_auxiliary_task_assignment(
        &store,
        "demo_agent_aux",
        "override-provider",
        "override-model",
        "https://aux.example/v1",
        "secret",
        Some(90),
        Some(json!({"temperature": 0.2})),
    )
    .unwrap();
    let updated_task = updated
        .iter()
        .find(|task| task.key == "demo_agent_aux")
        .expect("updated plugin auxiliary assignment should be listed");
    assert_eq!(updated_task.provider, "override-provider");
    assert_eq!(updated_task.model, "override-model");
    assert_eq!(updated_task.base_url, "https://aux.example/v1");
    assert_eq!(updated_task.api_key, "secret");
    assert_eq!(updated_task.timeout, 90);
    assert_eq!(updated_task.extra_body["temperature"], 0.2);

    let reset = reset_agent_auxiliary_task_assignments(&store).unwrap();
    let reset_task = reset
        .iter()
        .find(|task| task.key == "demo_agent_aux")
        .expect("reset plugin auxiliary assignment should be listed");
    assert_eq!(reset_task.provider, "demo-provider");
    assert_eq!(reset_task.model, "demo-model");
    assert_eq!(reset_task.timeout, 45);

    let _ = fs::remove_dir_all(dir);
}

