#[test]
fn profile_control_manages_hermes_style_desktop_snapshots() {
    let dir = std::env::temp_dir().join(format!("synthchat-profile-lifecycle-{}", new_id("test")));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    let persona = store.persona(None).unwrap();
    let conversation = store
        .create_conversation(Some("Profile Lifecycle".into()), Some(persona.id.clone()))
        .unwrap();

    let created =
        handle_profile_control_command(&store, &conversation, &persona, "create coder --clone")
            .unwrap();
    assert!(created.contains("已创建 Hermes-style desktop profile：coder"));
    assert!(dir
        .join(".hermes")
        .join("profiles")
        .join("coder")
        .join("profile.json")
        .exists());

    let listed = handle_profile_control_command(&store, &conversation, &persona, "list").unwrap();
    assert!(listed.contains("coder"));
    assert!(listed.contains("personas="));

    let mut updated_profile = store.profile().unwrap();
    updated_profile.name = "Changed User".into();
    store.set_profile(updated_profile).unwrap();

    let switched =
        handle_profile_control_command(&store, &conversation, &persona, "use coder").unwrap();
    assert!(switched.contains("coder"));
    assert_eq!(store.profile().unwrap().name, "用户");
    assert_eq!(
        fs::read_to_string(dir.join(".hermes").join("active_profile")).unwrap(),
        "coder"
    );

    let export_path = dir.join("coder-export.json");
    let exported = handle_profile_control_command(
        &store,
        &conversation,
        &persona,
        &format!("export coder {}", export_path.to_string_lossy()),
    )
    .unwrap();
    assert!(exported.contains("已导出"));
    assert!(export_path.exists());

    let imported = handle_profile_control_command(
        &store,
        &conversation,
        &persona,
        &format!("import {} reviewer", export_path.to_string_lossy()),
    )
    .unwrap();
    assert!(imported.contains("reviewer"));
    assert!(dir
        .join(".hermes")
        .join("profiles")
        .join("reviewer")
        .join("profile.json")
        .exists());

    handle_profile_control_command(&store, &conversation, &persona, "use desktop").unwrap();
    let deleted =
        handle_profile_control_command(&store, &conversation, &persona, "delete reviewer").unwrap();
    assert!(deleted.contains("reviewer"));
    assert!(!dir
        .join(".hermes")
        .join("profiles")
        .join("reviewer")
        .exists());

    let _ = fs::remove_dir_all(dir);
}

