async fn auth_status_reports_bitwarden_cached_provider_secret() {
    let _guard = CHANNEL_DIRECTORY_ENV_LOCK.lock().unwrap();
    let old_hermes_home = std::env::var_os("HERMES_HOME");
    let old_access = std::env::var_os("BWS_ACCESS_TOKEN");
    let old_project = std::env::var_os("BWS_PROJECT_ID");
    let old_server = std::env::var_os("BWS_SERVER_URL");
    let old_openrouter = std::env::var_os("OPENROUTER_API_KEY");
    let dir = std::env::temp_dir().join(format!("synthchat-auth-bws-{}", new_id("test")));
    fs::create_dir_all(dir.join("cache")).unwrap();
    std::env::set_var("HERMES_HOME", &dir);
    std::env::set_var("BWS_ACCESS_TOKEN", "bws-test-token");
    std::env::set_var("BWS_PROJECT_ID", "project-1");
    std::env::remove_var("BWS_SERVER_URL");
    std::env::remove_var("OPENROUTER_API_KEY");

    use sha2::{Digest, Sha256};
    let token_fp = Sha256::digest(b"bws-test-token");
    let cache_key = format!("{:x}|project-1|", token_fp);
    fs::write(
        dir.join("cache").join("bws_cache.json"),
        json!({
            "key": cache_key,
            "fetched_at": chrono::Utc::now().timestamp() as u64,
            "secrets": {
                "OPENROUTER_API_KEY": "sk-openrouter-from-bitwarden"
            }
        })
        .to_string(),
    )
    .unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    store
        .set_providers(vec![LlmProvider {
            id: "openrouter".into(),
            name: "OpenRouter".into(),
            provider_type: "openrouter".into(),
            preset: Some("openrouter".into()),
            base_url: "https://openrouter.ai/api/v1".into(),
            append_chat_path: true,
            api_key_env: String::new(),
            api_key: None,
            model: "anthropic/claude-sonnet-4.6".into(),
            enabled: true,
            timeout_seconds: 60,
            request_timeout_seconds: None,
            stale_timeout_seconds: None,
            models: json!({}),
            prompt_cache_mode: "auto".into(),
            prompt_cache_ttl: "5m".into(),
            prompt_cache_layout: "ephemeral-last".into(),
        }])
        .unwrap();

    let reply = handle_auth_control_command(&store, "openrouter")
        .await
        .unwrap();

    assert!(reply.contains("OpenRouter (openrouter)"));
    assert!(reply.contains("status=present"));
    assert!(reply.contains("source=bitwarden:OPENROUTER_API_KEY"));
    assert!(!reply.contains("sk-openrouter-from-bitwarden"));

    restore_test_env("OPENROUTER_API_KEY", old_openrouter);
    restore_test_env("BWS_SERVER_URL", old_server);
    restore_test_env("BWS_PROJECT_ID", old_project);
    restore_test_env("BWS_ACCESS_TOKEN", old_access);
    restore_test_env("HERMES_HOME", old_hermes_home);
    let _ = fs::remove_dir_all(dir);
}

