async fn auth_pool_control_command_removes_entry_by_label_prefix() {
    let _guard = crate::hermes_auth::HERMES_AUTH_TEST_ENV_LOCK
        .lock()
        .unwrap();
    let dir = std::env::temp_dir().join(format!("synthchat-auth-pool-remove-{}", new_id("test")));
    fs::create_dir_all(&dir).unwrap();
    fs::write(
        dir.join("auth.json"),
        serde_json::to_string_pretty(&json!({
            "credential_pool": {
                "nous": [
                    {"id": "cred-a", "label": "primary", "agent_key": "token-a", "priority": 0},
                    {"id": "cred-b", "label": "backup", "agent_key": "token-b", "priority": 1}
                ]
            }
        }))
        .unwrap(),
    )
    .unwrap();
    std::env::set_var("HERMES_HOME", &dir);
    let store = AppStore::new(dir.join("state.json")).unwrap();

    let reply = handle_auth_control_command(&store, "pool remove nous back")
        .await
        .unwrap();

    assert!(reply.contains("Removed Hermes credential pool entry"));
    assert!(reply.contains("provider: nous"));
    assert!(reply.contains("label: backup"));
    let saved =
        serde_json::from_str::<Value>(&fs::read_to_string(dir.join("auth.json")).unwrap()).unwrap();
    let entries = saved["credential_pool"]["nous"].as_array().unwrap();
    assert_eq!(entries.len(), 1);
    assert_eq!(entries[0]["label"], "primary");
    assert_eq!(entries[0]["priority"], 0);

    std::env::remove_var("HERMES_HOME");
    let _ = fs::remove_dir_all(dir);
}

