#[test]
fn agent_status_reports_hermes_session_lifecycle_and_stop_suspends_session() {
    let dir = std::env::temp_dir().join(format!("synthchat-session-lifecycle-{}", new_id("test")));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    let persona = store.persona(None).unwrap();
    let conversation = store
        .create_conversation(Some("Lifecycle".into()), Some(persona.id.clone()))
        .unwrap();

    let stopped = handle_abort_control_command(&store, &conversation, None, true).unwrap();
    assert!(stopped.contains("Hermes /stop compat"));

    let conversation = store.conversation(&conversation.id).unwrap();
    assert_eq!(
        conversation.metadata["hermesSessionLifecycle"]["schema"],
        "hermes_gateway_session_lifecycle_desktop_v1"
    );
    assert_eq!(
        conversation.metadata["hermesSessionLifecycle"]["suspended"],
        true
    );
    assert_eq!(
        conversation.metadata["hermesSessionLifecycle"]["reason"],
        "control_stop"
    );

    let status = handle_agent_status_control_command(&store, &conversation, &persona).unwrap();
    assert!(status.contains("Hermes session lifecycle"));
    assert!(status.contains("hermes_gateway_session_lifecycle_desktop_v1"));
    assert!(status.contains("\"suspended\": true"));

    let created = handle_new_control_command(&store, &persona, "Fresh").unwrap();
    let new_id = created
        .lines()
        .next()
        .and_then(|line| line.split('：').nth(1))
        .and_then(|rest| rest.split('。').next())
        .unwrap()
        .trim()
        .to_string();
    let fresh = store.conversation(&new_id).unwrap();
    assert_eq!(
        fresh.metadata["hermesSessionLifecycle"]["isFreshReset"],
        true
    );
    assert_eq!(fresh.metadata["hermesSessionLifecycle"]["suspended"], false);

    let _ = fs::remove_dir_all(dir);
}

