#[test]
fn copy_control_command_returns_recent_assistant_reply() {
    let dir = std::env::temp_dir().join(format!("synthchat-copy-control-{}", new_id("test")));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    let persona = store.persona(None).unwrap();
    let conversation = store
        .create_conversation(Some("Copy Control".into()), Some(persona.id.clone()))
        .unwrap();

    let empty = handle_copy_control_command(&store, &conversation, "").unwrap();
    assert!(empty.contains("没有可复制"));

    store
        .append_message(ChatMessage::new(
            conversation.id.clone(),
            "assistant",
            "first assistant reply".into(),
            "test",
        ))
        .unwrap();
    store
        .append_message(ChatMessage::new(
            conversation.id.clone(),
            "user",
            "ignore user content".into(),
            "test",
        ))
        .unwrap();
    store
        .append_message(ChatMessage::new(
            conversation.id.clone(),
            "assistant",
            "latest assistant reply".into(),
            "test",
        ))
        .unwrap();

    let latest = handle_copy_control_command(&store, &conversation, "").unwrap();
    assert!(latest.contains("最近第 1 条 assistant 回复"));
    assert!(latest.contains("latest assistant reply"));
    assert!(!latest.contains("ignore user content"));

    let previous = handle_copy_control_command(&store, &conversation, "2").unwrap();
    assert!(previous.contains("最近第 2 条 assistant 回复"));
    assert!(previous.contains("first assistant reply"));

    let _ = fs::remove_dir_all(dir);
}

