#[test]
fn tool_events_use_provider_response_item_id_as_call_id() {
    let payload = json!({
        "command": "pwd",
        "__agentProviderToolCall": {"response_item_id": "response-item-call"}
    });
    let event = tool_started_event("run-test", "__internal", "terminal", &payload);
    let (_, failed) = tool_failed_transition_events(
        "run-test",
        "__internal",
        "terminal",
        &payload,
        "terminal failed",
    );

    assert_eq!(event.call_id.as_deref(), Some("response-item-call"));
    assert_eq!(failed.call_id.as_deref(), Some("response-item-call"));
}

#[test]
fn tool_failed_transition_events_preserve_frontend_running_to_failed_sequence() {
    let (started, failed) = tool_failed_transition_events(
        "run-test",
        "__internal",
        "terminal",
        &json!({"command": "pwd", "__agentProviderToolCall": {"id": "tc-seq"}}),
        "guardrail stopped terminal",
    );

    assert_eq!(started.status.as_deref(), Some("running"));
    assert_eq!(failed.status.as_deref(), Some("failed"));
    assert_eq!(started.call_id.as_deref(), Some("tc-seq"));
    assert_eq!(failed.call_id.as_deref(), Some("tc-seq"));
    assert_eq!(started.run_id.as_deref(), Some("run-test"));
    assert_eq!(failed.run_id.as_deref(), Some("run-test"));
    assert_eq!(started.tool_name, "terminal");
    assert_eq!(failed.tool_name, "terminal");
}

#[test]
fn tool_failed_event_preserves_structured_reauth_error_for_ui() {
    let (_, failed) = tool_failed_transition_events(
        "run-test",
        "linear",
        "create_issue",
        &json!({"title": "test", "__agentProviderToolCall": {"id": "tc-auth"}}),
        r#"{"error":"MCP server 'linear' requires re-authentication.","needs_reauth":true,"needsReauth":true,"oauthStatus":{"state":"needs_reauth","tokenStatus":{"cacheState":"cached","refreshRisk":"expired_token"}}}"#,
    );

    assert_eq!(failed.status.as_deref(), Some("failed"));
    assert_eq!(failed.event_type, "mcp_tool");
    assert_eq!(
        failed.error.as_deref(),
        Some("MCP server 'linear' requires re-authentication.")
    );
    let raw = failed.raw.as_ref().unwrap();
    assert_eq!(raw["needsReauth"], true);
    assert_eq!(raw["errorJson"]["needs_reauth"], true);
    assert_eq!(raw["errorJson"]["oauthStatus"]["state"], "needs_reauth");
    assert_eq!(
        raw["errorJson"]["oauthStatus"]["tokenStatus"]["refreshRisk"],
        "expired_token"
    );
}

#[test]
fn iteration_budget_consumes_and_refunds() {
    let mut budget = IterationBudget::new(2);

    assert_eq!(budget.remaining(), 2);
    assert!(budget.consume());
    assert!(budget.consume());
    assert!(!budget.consume());
    assert!(budget.exhausted());
    budget.refund();
    assert_eq!(budget.used(), 1);
    assert_eq!(budget.remaining(), 1);
    assert!(budget.consume());
}

#[test]
fn tool_batch_execute_code_refund_rule_matches_hermes() {
    assert!(tool_batch_is_execute_code_only(&[(
        "execute_code".into(),
        json!({"language": "python", "code": "print('ok')"}),
    )]));
    assert!(tool_batch_is_execute_code_only(&[
        (
            "execute_code".into(),
            json!({"language": "python", "code": "print('a')"}),
        ),
        (
            "execute_code".into(),
            json!({"language": "javascript", "code": "console.log('b')"}),
        ),
    ]));
    assert!(!tool_batch_is_execute_code_only(&[]));
    assert!(!tool_batch_is_execute_code_only(&[
        (
            "execute_code".into(),
            json!({"language": "python", "code": "print('ok')"}),
        ),
        ("terminal".into(), json!({"command": "pwd"})),
    ]));
}

#[test]
fn default_tool_parallel_limit_matches_hermes_worker_cap() {
    assert_eq!(ChatConfig::default().tool_parallel_limit, 8);
    assert_eq!(ChatConfig::default().delegation_max_concurrent_children, 3);
    assert_eq!(ChatConfig::default().delegation_strategy, "auto");
    assert!(ChatConfig::default().delegation_orchestrator_enabled);
    assert!(!ChatConfig::default().delegation_subagent_auto_approve);
    assert!(ChatConfig::default().delegation_inherit_mcp_toolsets);
    assert!(ChatConfig::default()
        .delegation_subagent_provider_id
        .is_empty());
    assert!(ChatConfig::default().delegation_subagent_model.is_empty());
}

#[test]
fn tool_batch_parallelizes_independent_write_paths() {
    let dir = std::env::temp_dir().join(format!("synthchat-parallel-writes-{}", new_id("test")));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    let mut config = store.config().unwrap();
    config.chat.tool_approval_mode = "never".into();
    config.chat.tool_parallel_limit = 8;
    store.set_config(config.clone()).unwrap();
    let mut agent = AgentDefinition::default();
    agent.workspace_dir = dir.to_string_lossy().to_string();

    let requests = vec![
        (
            "write_file".into(),
            json!({"path": "a.txt", "content": "a"}),
        ),
        (
            "write_file".into(),
            json!({"path": "nested/b.txt", "content": "b"}),
        ),
    ];

    assert!(should_parallelize_tool_batch(
        &requests,
        &[],
        &agent,
        &config.chat,
        &store,
        ToolExecutionContext::Interactive
    )
    .unwrap());

    let _ = fs::remove_dir_all(dir);
}

