#[test]
fn invalid_encrypted_content_recovery_merge_keeps_concurrent_append() {
    let dir = std::env::temp_dir().join(format!(
        "synthchat-invalid-encrypted-merge-race-{}",
        new_id("test")
    ));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    let persona = store.persona(None).unwrap();
    let conversation = store
        .create_conversation(Some("Encrypted Merge".into()), Some(persona.id.clone()))
        .unwrap();
    let mut assistant = ChatMessage::new(
        conversation.id.clone(),
        "assistant",
        "answer\ncodex_reasoning_items: [secret]".into(),
        "desktop-agent",
    );
    assistant.provider_data = Some(json!({
        "responses": {
            "reasoningItems": [{
                "type": "reasoning",
                "encrypted_content": "sealed",
                "_issuerKind": "codex_backend"
            }],
            "messageItems": [{
                "type": "message",
                "role": "assistant",
                "content": [{"type": "output_text", "text": "answer"}]
            }]
        },
        "openai": {
            "reasoning_content": "hidden chain"
        }
    }));
    let assistant = store.append_message(assistant).unwrap();

    let snapshot = store.messages(&conversation.id, None).unwrap();
    let concurrent = store
        .append_message(ChatMessage::new(
            conversation.id.clone(),
            "user",
            "wechat hello".into(),
            "wechat",
        ))
        .unwrap();

    let mut cleaned = snapshot.clone();
    let note = recover_reasoning_replay_text_for_retry(&mut cleaned, "invalid_encrypted_content")
        .unwrap()
        .unwrap();
    assert!(note.contains("Recovered invalid_encrypted_content"));
    persist_recovered_messages_for_retry(&store, &conversation.id, &snapshot, &cleaned).unwrap();

    let saved = store.messages(&conversation.id, None).unwrap();
    assert_eq!(saved.len(), 2);
    let cleaned_assistant = saved
        .iter()
        .find(|message| message.id == assistant.id)
        .unwrap();
    assert_eq!(cleaned_assistant.content, "answer");
    assert!(cleaned_assistant
        .provider_data
        .as_ref()
        .unwrap()
        .pointer("/responses/reasoningItems")
        .is_none());
    assert!(saved.iter().any(|message| message.id == concurrent.id));
    assert_eq!(
        store.conversation(&conversation.id).unwrap().last_message,
        "wechat hello"
    );

    let _ = fs::remove_dir_all(dir);
}

#[test]
fn llm_context_recovery_compacts_history_for_retry() {
    let dir =
        std::env::temp_dir().join(format!("synthchat-llm-context-recovery-{}", new_id("test")));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    let persona = store.persona(None).unwrap();
    let conversation = store
        .create_conversation(Some("Context Recovery".into()), Some(persona.id.clone()))
        .unwrap();
    for index in 0..12 {
        store
            .append_message(ChatMessage::new(
                conversation.id.clone(),
                if index % 2 == 0 { "user" } else { "assistant" },
                format!("message {index} with enough content to summarize"),
                "test",
            ))
            .unwrap();
    }
    let run = store
        .save_agent_run(AgentRunRecord::new(
            conversation.id.clone(),
            persona.id.clone(),
            conversation.agent_id.clone(),
        ))
        .unwrap();
    let mut history = store.messages(&conversation.id, Some(30)).unwrap();
    let mut short_context = store.short_context(&conversation.id).unwrap();

    let note = recover_context_overflow_for_retry(
        &store,
        &run.run_id,
        &conversation.id,
        &mut history,
        &mut short_context,
        8000,
        "context_overflow",
        &AppError::Llm("context length exceeded".into()),
    )
    .unwrap()
    .unwrap();

    assert!(note.contains("Recovered context_overflow"));
    assert_eq!(history.len(), 8);
    assert_eq!(short_context.summary_messages, 4);
    assert!(short_context.summary.contains("Automatic LLM recovery"));
    assert_eq!(
        store.agent_run(&run.run_id).unwrap().checkpoints[0].state,
        "llm_context_recovered"
    );

    let _ = fs::remove_dir_all(dir);
}

#[test]
fn llm_context_error_parsers_follow_provider_reported_limits() {
    assert_eq!(
        parse_context_limit_from_error("maximum context length is 32768 tokens"),
        Some(32_768)
    );
    assert_eq!(
        parse_context_limit_from_error("context_length_exceeded: 131072"),
        Some(131_072)
    );
    assert_eq!(
        parse_context_limit_from_error("Maximum context size 32768 exceeded"),
        Some(32_768)
    );
    assert_eq!(
        parse_available_output_tokens_from_error(
            "max_tokens: 32768 > context_window: 200000 - input_tokens: 190000 = available_tokens: 10000"
        ),
        Some(10_000)
    );
    assert_eq!(
        parse_context_limit_from_error("context length exceeded but no numeric limit"),
        None
    );
    assert_eq!(
        next_max_tokens_override(
            None,
            32_768,
            "max_tokens: 32768 > context_window: 200000 - input_tokens: 190000 = available_tokens: 10000",
        ),
        Some(10_000)
    );
    assert_eq!(
        next_max_tokens_override(
            Some(8_000),
            32_768,
            "max_tokens: 32768 > context_window: 200000 - input_tokens: 190000 = available_tokens: 10000",
        ),
        Some(8_000)
    );
}

