#[test]
fn retry_control_command_requeues_last_user_message() {
    let dir = std::env::temp_dir().join(format!("synthchat-retry-control-{}", new_id("test")));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    let persona = store.persona(None).unwrap();
    let conversation = store
        .create_conversation(Some("Retry Control".into()), Some(persona.id.clone()))
        .unwrap();
    let other = store
        .create_conversation(Some("Other".into()), Some(persona.id.clone()))
        .unwrap();

    store
        .append_message(ChatMessage::new(
            other.id.clone(),
            "user",
            "do not retry this".into(),
            "test",
        ))
        .unwrap();
    store
        .append_message(ChatMessage::new(
            conversation.id.clone(),
            "user",
            "first prompt".into(),
            "test",
        ))
        .unwrap();
    store
        .append_message(ChatMessage::new(
            conversation.id.clone(),
            "assistant",
            "assistant reply".into(),
            "test",
        ))
        .unwrap();
    store
        .append_message(ChatMessage::new(
            conversation.id.clone(),
            "user",
            "retry this prompt".into(),
            "test",
        ))
        .unwrap();

    let reply = handle_retry_control_command(&store, &conversation, &persona, None).unwrap();
    assert!(reply.contains("已重试最后一条用户消息"));
    assert!(reply.contains("retry this prompt"));
    let queue = store.agent_queue().unwrap();
    assert_eq!(queue.len(), 1);
    assert_eq!(queue[0].conversation_id, conversation.id);
    assert_eq!(queue[0].content, "retry this prompt");

    let empty = store
        .create_conversation(Some("Empty".into()), Some(persona.id.clone()))
        .unwrap();
    let no_retry = handle_retry_control_command(&store, &empty, &persona, None).unwrap();
    assert!(no_retry.contains("没有可重试"));

    let _ = fs::remove_dir_all(dir);
}

#[test]
fn undo_control_command_removes_tail_and_requeues_target_user_turn() {
    let dir = std::env::temp_dir().join(format!("synthchat-undo-control-{}", new_id("test")));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    let persona = store.persona(None).unwrap();
    let conversation = store
        .create_conversation(Some("Undo Control".into()), Some(persona.id.clone()))
        .unwrap();
    let other = store
        .create_conversation(Some("Other".into()), Some(persona.id.clone()))
        .unwrap();

    store
        .append_message(ChatMessage::new(
            conversation.id.clone(),
            "user",
            "keep this prompt".into(),
            "test",
        ))
        .unwrap();
    store
        .append_message(ChatMessage::new(
            conversation.id.clone(),
            "assistant",
            "keep this response".into(),
            "test",
        ))
        .unwrap();
    store
        .append_message(ChatMessage::new(
            conversation.id.clone(),
            "user",
            "redo this prompt".into(),
            "test",
        ))
        .unwrap();
    store
        .append_message(ChatMessage::new(
            conversation.id.clone(),
            "assistant",
            "remove this response".into(),
            "test",
        ))
        .unwrap();
    store
        .append_message(ChatMessage::new(
            other.id.clone(),
            "user",
            "other untouched".into(),
            "test",
        ))
        .unwrap();

    let reply = handle_undo_control_command(&store, &conversation, &persona, "1", None).unwrap();
    assert!(reply.contains("已回退 1 个用户轮次"));
    assert!(reply.contains("redo this prompt"));

    let messages = store.messages(&conversation.id, None).unwrap();
    assert_eq!(messages.len(), 3);
    assert!(messages
        .iter()
        .any(|message| message.content == "keep this prompt"));
    assert!(messages
        .iter()
        .any(|message| message.content == "keep this response"));
    assert!(messages
        .iter()
        .any(|message| message.content == "redo this prompt"));
    assert!(!messages
        .iter()
        .any(|message| message.content == "remove this response"));
    assert_eq!(store.messages(&other.id, None).unwrap().len(), 1);

    let queue = store.agent_queue().unwrap();
    assert_eq!(queue.len(), 1);
    assert_eq!(queue[0].content, "redo this prompt");

    let no_undo = handle_undo_control_command(&store, &conversation, &persona, "5", None).unwrap();
    assert!(no_undo.contains("没有足够"));

    let _ = fs::remove_dir_all(dir);
}

#[test]
fn branch_control_command_copies_conversation_history_to_new_conversation() {
    let dir = std::env::temp_dir().join(format!("synthchat-branch-control-{}", new_id("test")));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    let persona = store.persona(None).unwrap();
    let conversation = store
        .create_conversation(Some("Main Path".into()), Some(persona.id.clone()))
        .unwrap();

    store
        .append_message(ChatMessage::new(
            conversation.id.clone(),
            "user",
            "first branch prompt".into(),
            "test",
        ))
        .unwrap();
    let mut assistant = ChatMessage::new(
        conversation.id.clone(),
        "assistant",
        "assistant branch answer".into(),
        "test",
    );
    assistant.provider_data = Some(json!({"reasoning_content": "preserved"}));
    store.append_message(assistant).unwrap();

    let reply =
        handle_branch_control_command(&store, &conversation, &persona, "Alternative Path").unwrap();
    assert!(reply.contains("已创建分支会话"));
    assert!(reply.contains("copiedMessages: 2"));

    let branch = store
        .conversations()
        .unwrap()
        .into_iter()
        .find(|item| item.id != conversation.id)
        .unwrap();
    assert_eq!(branch.title, "Alternative Path");
    assert_eq!(
        branch.metadata["branchedFromConversationId"],
        json!(conversation.id)
    );
    let branch_messages = store.messages(&branch.id, None).unwrap();
    assert_eq!(branch_messages.len(), 2);
    assert_eq!(branch_messages[0].content, "first branch prompt");
    assert_eq!(branch_messages[1].content, "assistant branch answer");
    assert_eq!(
        branch_messages[1].provider_data.as_ref().unwrap()["reasoning_content"],
        json!("preserved")
    );
    assert_ne!(branch_messages[0].conversation_id, conversation.id);

    let empty = store
        .create_conversation(Some("Empty".into()), Some(persona.id.clone()))
        .unwrap();
    let empty_reply = handle_branch_control_command(&store, &empty, &persona, "").unwrap();
    assert!(empty_reply.contains("无法创建分支"));

    let _ = fs::remove_dir_all(dir);
}

#[test]
fn new_control_command_creates_empty_conversation_for_current_persona() {
    let dir = std::env::temp_dir().join(format!("synthchat-new-control-{}", new_id("test")));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    let persona = store.persona(None).unwrap();
    let existing = store
        .create_conversation(Some("Existing".into()), Some(persona.id.clone()))
        .unwrap();

    let reply = handle_new_control_command(&store, &persona, "Fresh Session").unwrap();
    assert!(reply.contains("已创建新会话"));
    assert!(reply.contains("Fresh Session"));

    let conversations = store.conversations().unwrap();
    assert_eq!(conversations.len(), 2);
    let created = conversations
        .into_iter()
        .find(|item| item.id != existing.id)
        .unwrap();
    assert_eq!(created.title, "Fresh Session");
    assert_eq!(created.persona_id.as_deref(), Some(persona.id.as_str()));
    assert!(store.messages(&created.id, None).unwrap().is_empty());

    let _ = fs::remove_dir_all(dir);
}

#[test]
fn sessions_control_command_lists_and_filters_conversations() {
    let dir = std::env::temp_dir().join(format!("synthchat-sessions-control-{}", new_id("test")));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    let persona = store.persona(None).unwrap();
    let first = store
        .create_conversation(Some("Alpha Session".into()), Some(persona.id.clone()))
        .unwrap();
    let branch = store
        .create_conversation(Some("Beta Branch".into()), Some(persona.id.clone()))
        .unwrap();
    store
        .set_conversation_metadata_value(
            &branch.id,
            "branchedFromConversationId",
            json!(first.id.clone()),
        )
        .unwrap();
    store
        .append_message(ChatMessage::new(
            branch.id.clone(),
            "user",
            "branch last message".into(),
            "test",
        ))
        .unwrap();

    let listed = format_sessions_control_status(&store, "10").unwrap();
    assert!(listed.contains("最近会话"));
    assert!(listed.contains("Alpha Session"));
    assert!(listed.contains("Beta Branch"));
    assert!(listed.contains(&first.id));

    let filtered = format_sessions_control_status(&store, "branch").unwrap();
    assert!(filtered.contains("Beta Branch"));
    assert!(!filtered.contains("Alpha Session"));

    let missing = format_sessions_control_status(&store, "no-such-session").unwrap();
    assert!(missing.contains("没有匹配"));

    let _ = fs::remove_dir_all(dir);
}

#[test]
fn queue_control_command_cancels_and_clears_current_conversation_items() {
    let dir = std::env::temp_dir().join(format!("synthchat-queue-control-{}", new_id("test")));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    let persona = store.persona(None).unwrap();
    let conversation = store
        .create_conversation(Some("Queue Control".into()), Some(persona.id.clone()))
        .unwrap();
    let other = store
        .create_conversation(Some("Other".into()), Some(persona.id.clone()))
        .unwrap();

    let pending_message = ChatMessage::new(
        conversation.id.clone(),
        "user",
        "pending queue item".into(),
        "test",
    );
    let pending = store
        .enqueue_agent_request(
            conversation.id.clone(),
            persona.id.clone(),
            &pending_message,
        )
        .unwrap();
    let finished_message = ChatMessage::new(
        conversation.id.clone(),
        "user",
        "finished queue item".into(),
        "test",
    );
    let finished = store
        .enqueue_agent_request(
            conversation.id.clone(),
            persona.id.clone(),
            &finished_message,
        )
        .unwrap();
    store
        .complete_agent_queue_item(&finished.id, "completed", None)
        .unwrap();
    let other_message =
        ChatMessage::new(other.id.clone(), "user", "other queue item".into(), "test");
    let other_item = store
        .enqueue_agent_request(other.id.clone(), persona.id.clone(), &other_message)
        .unwrap();

    let prefix = &pending.id[..12];
    let canceled =
        cancel_agent_queue_item_for_conversation(&store, &conversation, prefix, None).unwrap();
    assert!(canceled.contains(&pending.id));
    assert_eq!(
        store
            .agent_queue()
            .unwrap()
            .into_iter()
            .find(|item| item.id == pending.id)
            .unwrap()
            .status,
        "canceled"
    );

    let other_cancel =
        cancel_agent_queue_item_for_conversation(&store, &conversation, &other_item.id[..12], None)
            .unwrap();
    assert!(other_cancel.contains("未找到匹配"));
    assert_eq!(
        store
            .agent_queue()
            .unwrap()
            .into_iter()
            .find(|item| item.id == other_item.id)
            .unwrap()
            .status,
        "pending"
    );

    let cleared =
        clear_finished_agent_queue_items_for_conversation(&store, &conversation, None).unwrap();
    assert!(cleared.contains("2 -> 0"));
    let remaining = store.agent_queue().unwrap();
    assert_eq!(remaining.len(), 1);
    assert_eq!(remaining[0].id, other_item.id);

    let _ = fs::remove_dir_all(dir);
}

#[test]
fn busy_input_modes_queue_steer_and_interrupt_active_run() {
    let dir = std::env::temp_dir().join(format!("synthchat-busy-input-{}", new_id("test")));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    let persona = store.persona(None).unwrap();
    let conversation = store
        .create_conversation(Some("Busy Input".into()), Some(persona.id.clone()))
        .unwrap();
    let mut run = AgentRunRecord::new(
        conversation.id.clone(),
        persona.id.clone(),
        conversation.agent_id.clone(),
    );
    run.run_id = "run_busy".into();
    run.state = "running".into();
    store.save_agent_run(run.clone()).unwrap();

    let queued =
        handle_busy_conversation_input(&store, &conversation, &persona, "queue this request", None)
            .unwrap()
            .unwrap();
    assert_eq!(queued.len(), 2);
    assert_eq!(store.agent_queue().unwrap().len(), 1);
    assert_eq!(store.agent_run("run_busy").unwrap().state, "running");

    let mut config = store.config().unwrap();
    config.chat.busy_input_mode = "steer".into();
    store.set_config(config).unwrap();
    let steered = handle_busy_conversation_input(
        &store,
        &conversation,
        &persona,
        "prefer browser_snapshot before clicking",
        None,
    )
    .unwrap()
    .unwrap();
    assert_eq!(steered.len(), 2);
    let mut saved = store.agent_run("run_busy").unwrap();
    assert_eq!(saved.pending_steers.len(), 1);
    let mut observations = Vec::new();
    drain_agent_steers_into_observations(&store, &mut saved, &mut observations).unwrap();
    assert!(observations[0].contains("prefer browser_snapshot"));
    let saved = store.agent_run("run_busy").unwrap();
    assert!(saved.pending_steers.is_empty());
    assert!(saved
        .phase_events
        .iter()
        .any(|event| event.phase == "steer_injected"));

    let mut config = store.config().unwrap();
    config.chat.busy_input_mode = "interrupt".into();
    store.set_config(config).unwrap();
    let interrupted = handle_busy_conversation_input(
        &store,
        &conversation,
        &persona,
        "replace with this request",
        None,
    )
    .unwrap();
    assert!(interrupted.is_none());
    assert_eq!(store.agent_run("run_busy").unwrap().state, "aborted");

    let _ = fs::remove_dir_all(dir);
}

#[test]
fn busy_input_queue_preserves_request_source_and_provider_data() {
    let dir = std::env::temp_dir().join(format!("synthchat-busy-origin-{}", new_id("test")));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    let persona = store.persona(None).unwrap();
    let conversation = store
        .create_conversation(Some("Busy Origin".into()), Some(persona.id.clone()))
        .unwrap();
    let mut run = AgentRunRecord::new(
        conversation.id.clone(),
        persona.id.clone(),
        conversation.agent_id.clone(),
    );
    run.run_id = "run_busy_origin".into();
    run.state = "running".into();
    store.save_agent_run(run).unwrap();

    let request = SendChatRequest {
        conversation_id: Some(conversation.id.clone()),
        persona_id: Some(persona.id.clone()),
        agent_id: None,
        content: "queued wechat prompt".into(),
        provider_data: Some(json!({
            "source": "wechat",
            "accountId": "wechat-account-1",
            "userId": "wechat-user-1",
            "contextToken": "ctx-1"
        })),
        queue_item_id: None,
    };
    let queued =
        handle_busy_conversation_input_for_request(&store, &conversation, &persona, &request, None)
            .unwrap()
            .unwrap();
    assert_eq!(queued.len(), 2);
    let queue = store.agent_queue().unwrap();
    assert_eq!(queue.len(), 1);
    assert_eq!(queue[0].source, "wechat");
    assert_eq!(
        queue[0].provider_data.as_ref().unwrap()["accountId"],
        "wechat-account-1"
    );
    assert_eq!(
        queue[0].provider_data.as_ref().unwrap()["contextToken"],
        "ctx-1"
    );

    let _ = fs::remove_dir_all(dir);
}

