#[tokio::test]
async fn busy_active_run_control_commands_dispatch_before_queueing() {
    let dir = std::env::temp_dir().join(format!("synthchat-busy-bypass-{}", new_id("test")));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    let persona = store.persona(None).unwrap();
    let conversation = store
        .create_conversation(Some("Busy Bypass".into()), Some(persona.id.clone()))
        .unwrap();
    let mut run = AgentRunRecord::new(
        conversation.id.clone(),
        persona.id.clone(),
        conversation.agent_id.clone(),
    );
    run.run_id = "run_busy_bypass".into();
    run.state = "running".into();
    store.save_agent_run(run).unwrap();

    let reply =
        handle_agent_control_command(&store, &conversation, &persona, "/stop@MyHermesBot", None)
            .await
            .unwrap()
            .expect("/stop should dispatch as a control command");

    assert!(reply.content.contains("已中止当前 agent run"));
    assert_eq!(store.agent_run("run_busy_bypass").unwrap().state, "aborted");
    assert!(store.agent_queue().unwrap().is_empty());

    let _ = fs::remove_dir_all(dir);
}

#[tokio::test]
