#[test]
fn plugins_control_reply_lists_and_filters_plugins() {
    let plugins = vec![
        crate::models::PluginSummary {
            id: "observability/langfuse".into(),
            name: "Langfuse".into(),
            description: "Trace and export LLM spans".into(),
            enabled: true,
            provided_tools: vec!["trace_flush".into()],
            provided_capabilities: vec![],
            missing_env: vec![],
            env_configured: true,
            provided_hooks: vec!["post_turn".into()],
            requires_env: vec!["LANGFUSE_PUBLIC_KEY".into()],
            version: "1.0.0".into(),
            author: "test".into(),
            source: "bundled".into(),
            homepage_url: String::new(),
            kind: "backend".into(),
            path: String::new(),
            manifest_path: String::new(),
            entry_point: String::new(),
        },
        crate::models::PluginSummary {
            id: "platforms/discord".into(),
            name: "Discord".into(),
            description: "Gateway platform adapter".into(),
            enabled: false,
            provided_tools: vec![],
            provided_capabilities: vec![],
            missing_env: vec![],
            env_configured: true,
            provided_hooks: vec!["platform_message".into()],
            requires_env: vec!["DISCORD_BOT_TOKEN".into()],
            version: "1.0.0".into(),
            author: "test".into(),
            source: "bundled".into(),
            homepage_url: String::new(),
            kind: "platform".into(),
            path: String::new(),
            manifest_path: String::new(),
            entry_point: String::new(),
        },
    ];

    let listed = format_plugins_control_reply(plugins.clone(), "").unwrap();
    assert!(listed.contains("enabled 1 / 2"));
    assert!(listed.contains("observability/langfuse"));
    assert!(listed.contains("platforms/discord"));
    assert!(listed.find("observability/langfuse") < listed.find("platforms/discord"));

    let filtered = format_plugins_control_reply(plugins, "discord").unwrap();
    assert!(filtered.contains("platforms/discord"));
    assert!(!filtered.contains("observability/langfuse"));
}

#[test]
fn model_control_command_updates_persona_model_id() {
    let dir = std::env::temp_dir().join(format!("synthchat-model-{}", new_id("test")));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    let mut providers = store.providers().unwrap();
    providers.push(LlmProvider {
        id: "openai-main".into(),
        name: "OpenAI Main".into(),
        provider_type: "openai_compatible".into(),
        preset: Some("openai".into()),
        base_url: "https://api.example.test/v1".into(),
        append_chat_path: true,
        api_key_env: String::new(),
        api_key: None,
        model: "gpt-default".into(),
        enabled: true,
        timeout_seconds: 60,
        request_timeout_seconds: None,
        stale_timeout_seconds: None,
        models: json!({}),
        prompt_cache_mode: "off".into(),
        prompt_cache_ttl: "5m".into(),
        prompt_cache_layout: "system_tools".into(),
    });
    store.set_providers(providers).unwrap();
    let mut persona = store.persona(None).unwrap();
    persona.llm_provider = "openai-main".into();
    persona.llm_model = "gpt-default".into();
    let persona = store.save_persona(persona).unwrap();
    let conversation = store
        .create_conversation(Some("Model Test".into()), Some(persona.id.clone()))
        .unwrap();

    let status = handle_model_control_command(&store, &conversation, &persona, "").unwrap();
    assert!(status.contains("当前模型设置"));
    assert!(status.contains("activeProvider: OpenAI Main"));

    let updated =
        handle_model_control_command(&store, &conversation, &persona, "gpt-4.1 -p openai-main")
            .unwrap();
    assert!(updated.contains("已更新当前角色的模型设置"));
    assert!(updated.contains("activeProvider: OpenAI Main"));
    assert!(updated.contains("effectiveModel: gpt-4.1"));
    let saved_persona = store.persona(Some(&persona.id)).unwrap();
    let saved_agent = store.agent(Some(&conversation.agent_id)).unwrap();
    assert_eq!(saved_persona.llm_provider, "openai-main");
    assert_eq!(saved_persona.llm_model, "gpt-4.1");
    assert_eq!(saved_agent.llm_provider, "openai-main");
    assert_eq!(saved_agent.llm_model, "gpt-4.1");

    let reset =
        handle_model_control_command(&store, &conversation, &saved_persona, "reset").unwrap();
    assert!(reset.contains("已清除当前角色的模型 ID"));
    let saved_persona = store.persona(Some(&persona.id)).unwrap();
    let saved_agent = store.agent(Some(&conversation.agent_id)).unwrap();
    assert_eq!(saved_persona.llm_provider, "openai-main");
    assert!(saved_persona.llm_model.is_empty());
    assert_eq!(saved_agent.llm_provider, "openai-main");
    assert!(saved_agent.llm_model.is_empty());

    let _ = fs::remove_dir_all(dir);
}

