#[tokio::test]
async fn feishu_drive_reaction_tool_matches_hermes_drive_v2_api() {
    let listener = tokio::net::TcpListener::bind("127.0.0.1:0").await.unwrap();
    let addr = listener.local_addr().unwrap();
    let requests = std::sync::Arc::new(Mutex::new(Vec::<String>::new()));
    let requests_for_task = requests.clone();
    tokio::spawn(async move {
        let Ok((mut stream, _)) = listener.accept().await else {
            return;
        };
        let mut buffer = vec![0; 8192];
        let mut request_bytes = Vec::new();
        loop {
            let bytes = stream.read(&mut buffer).await.unwrap_or(0);
            if bytes == 0 {
                break;
            }
            request_bytes.extend_from_slice(&buffer[..bytes]);
            if request_bytes.windows(4).any(|window| window == b"\r\n\r\n") {
                let request_text = String::from_utf8_lossy(&request_bytes);
                let content_length = request_text
                    .lines()
                    .find_map(|line| {
                        line.strip_prefix("Content-Length:")
                            .or_else(|| line.strip_prefix("content-length:"))
                            .and_then(|value| value.trim().parse::<usize>().ok())
                    })
                    .unwrap_or(0);
                let header_len = request_bytes
                    .windows(4)
                    .position(|window| window == b"\r\n\r\n")
                    .map(|index| index + 4)
                    .unwrap_or(request_bytes.len());
                if request_bytes.len().saturating_sub(header_len) >= content_length {
                    break;
                }
            }
        }
        requests_for_task
            .lock()
            .unwrap()
            .push(String::from_utf8_lossy(&request_bytes).to_string());
        let body = json!({"code": 0, "msg": "ok", "data": {"updated": true}}).to_string();
        let response = format!(
            "HTTP/1.1 200 OK\r\nContent-Type: application/json\r\nContent-Length: {}\r\n\r\n{}",
            body.len(),
            body
        );
        let _ = stream.write_all(response.as_bytes()).await;
    });

    let dir = std::env::temp_dir().join(format!("synthchat-feishu-reaction-{}", new_id("test")));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    let mut config = store.config().unwrap();
    config.feishu = json!({
        "baseUrl": format!("http://{addr}"),
        "tenantAccessToken": "tenant-token",
        "timeoutSeconds": 5
    });
    store.set_config(config).unwrap();

    let result = feishu_tool(
        &store,
        "feishu_drive_update_comment_reaction",
        &json!({
            "file_token": "doccn 123",
            "file_type": "docx",
            "reply_id": "reply-1",
            "action": "add",
            "reaction_type": "OK"
        }),
    )
    .await
    .unwrap();
    let result: Value = serde_json::from_str(&result).unwrap();
    assert_eq!(result["success"], true);
    assert_eq!(result["result"]["data"]["updated"], true);

    let requests = requests.lock().unwrap();
    let request = requests.first().unwrap();
    assert!(request
        .contains("POST /open-apis/drive/v2/files/doccn%20123/comments/reaction?file_type=docx "));
    assert!(request.contains("Authorization: Bearer tenant-token"));
    assert!(request.contains("\"action\":\"add\""));
    assert!(request.contains("\"reply_id\":\"reply-1\""));
    assert!(request.contains("\"reaction_type\":\"OK\""));

    let _ = fs::remove_dir_all(dir);
}

#[test]
fn send_message_lists_feishu_external_target_when_configured() {
    let dir =
        std::env::temp_dir().join(format!("synthchat-send-message-feishu-{}", new_id("test")));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    let conversation = store
        .create_conversation(Some("feishu".into()), None)
        .unwrap();
    let mut config = store.config().unwrap();
    config.feishu = json!({
        "baseUrl": "https://open.feishu.cn",
        "tenantAccessToken": "tenant-token",
        "homeChannel": "oc_home",
        "homeThreadId": "om_home_reply"
    });
    store.set_config(config).unwrap();

    let listed = send_message_tool(&store, &conversation.id, &json!({"action": "list"})).unwrap();
    let listed: Value = serde_json::from_str(&listed).unwrap();
    let targets = listed["externalTargets"].as_array().unwrap();
    let feishu = targets
        .iter()
        .find(|target| target["platform"].as_str() == Some("feishu"))
        .expect("missing Feishu external target");
    assert_eq!(feishu["target"], "feishu:<receive_id>");
    assert_eq!(feishu["homeTarget"], "feishu:oc_home:om_home_reply");
    assert!(feishu["notes"].as_str().unwrap().contains("MEDIA:<path>"));

    let payloads = super::communication::feishu_send_message_payloads(
        &store,
        &json!({"target": "feishu:oc_chat:om_reply", "message": "hello MEDIA:C:\\tmp\\photo.png"}),
    )
    .unwrap();
    assert_eq!(payloads[0]["receive_id"], "oc_chat");
    assert_eq!(payloads[0]["thread_id"], "om_reply");
    assert_eq!(payloads[0]["message"], "hello");
    assert_eq!(payloads[0]["media_files"][0]["path"], "C:\\tmp\\photo.png");

    let home_payloads = super::communication::feishu_send_message_payloads(
        &store,
        &json!({"target": "feishu", "message": "home hello"}),
    )
    .unwrap();
    assert_eq!(home_payloads[0]["receive_id"], "oc_home");
    assert_eq!(home_payloads[0]["thread_id"], "om_home_reply");

    let _ = fs::remove_dir_all(dir);
}

