#[test]
fn email_helpers_parse_settings_and_payload_targets() {
    let settings = email_settings(&json!({
        "address": "agent@example.com",
        "password": "secret",
        "smtpHost": "smtp.example.com",
        "smtpPort": 2525,
        "subject": "SynthChat Agent",
        "timeoutSeconds": 45
    }))
    .unwrap();
    assert_eq!(settings.address, "agent@example.com");
    assert_eq!(settings.smtp_host, "smtp.example.com");
    assert_eq!(settings.smtp_port, 2525);
    assert_eq!(settings.subject, "SynthChat Agent");
    assert_eq!(settings.timeout_seconds, 45);
    assert!(!email_configured(&json!({
        "address": "agent@example.com",
        "password": "secret"
    })));

    let dir = std::env::temp_dir().join(format!("synthchat-send-message-email-{}", new_id("test")));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    let conversation = store
        .create_conversation(Some("email".into()), None)
        .unwrap();
    let mut config = store.config().unwrap();
    config.email = json!({
        "address": "agent@example.com",
        "password": "secret",
        "smtpHost": "smtp.example.com",
        "homeAddress": "home@example.com"
    });
    store.set_config(config).unwrap();

    let listed = send_message_tool(&store, &conversation.id, &json!({"action": "list"})).unwrap();
    let listed: Value = serde_json::from_str(&listed).unwrap();
    let targets = listed["externalTargets"].as_array().unwrap();
    let email = targets
        .iter()
        .find(|target| target["platform"].as_str() == Some("email"))
        .expect("missing Email external target");
    assert_eq!(email["target"], "email:<address>");
    assert_eq!(email["homeTarget"], "email:home@example.com");

    let payloads = super::communication::email_send_message_payloads(
        &store,
        &json!({"target": "email:user@example.com", "message": "hello", "subject": "Hi"}),
    )
    .unwrap();
    assert_eq!(payloads[0]["to"], "user@example.com");
    assert_eq!(payloads[0]["subject"], "Hi");

    let media_payloads = super::communication::email_send_message_payloads(
        &store,
        &json!({"target": "email:user@example.com", "message": "hello MEDIA:C:\\tmp\\a.png"}),
    )
    .unwrap();
    assert_eq!(media_payloads[0]["message"], "hello");
    assert_eq!(
        media_payloads[0]["media_files"][0]["path"],
        "C:\\tmp\\a.png"
    );

    let attachment_path = dir.join("report.txt");
    fs::write(&attachment_path, "attachment body").unwrap();
    let message = email_build_message(
        &settings,
        "user@example.com",
        "Hi",
        "hello",
        &[attachment_path.to_string_lossy().to_string()],
    )
    .unwrap();
    let raw = String::from_utf8(message.formatted()).unwrap();
    assert!(raw.contains("multipart/mixed"));
    assert!(raw.contains("report.txt"));
    assert!(raw.contains("attachment body"));

    let _ = fs::remove_dir_all(dir);
}

#[test]
fn sms_helpers_parse_settings_and_payload_targets() {
    let settings = sms_settings(&json!({
        "accountSid": "AC123",
        "authToken": "token",
        "fromNumber": "+15551234567",
        "apiBaseUrl": "https://api.twilio.com/",
        "timeoutSeconds": 45
    }))
    .unwrap();
    assert_eq!(settings.account_sid, "AC123");
    assert_eq!(settings.auth_token, "token");
    assert_eq!(settings.from_number, "+15551234567");
    assert_eq!(settings.api_base_url, "https://api.twilio.com");
    assert_eq!(settings.timeout_seconds, 45);
    assert_eq!(
        sms_url(&settings).unwrap().as_str(),
        "https://api.twilio.com/2010-04-01/Accounts/AC123/Messages.json"
    );
    assert!(!sms_configured(&json!({
        "accountSid": "AC123",
        "authToken": "token"
    })));
    assert_eq!(
        sms_strip_markdown("**hello** [link](https://example.com)\n# title"),
        "hello link\ntitle"
    );

    let dir = std::env::temp_dir().join(format!("synthchat-send-message-sms-{}", new_id("test")));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    let conversation = store.create_conversation(Some("sms".into()), None).unwrap();
    let mut config = store.config().unwrap();
    config.sms = json!({
        "accountSid": "AC123",
        "authToken": "token",
        "fromNumber": "+15551234567",
        "homeNumber": "+15557654321"
    });
    store.set_config(config).unwrap();

    let listed = send_message_tool(&store, &conversation.id, &json!({"action": "list"})).unwrap();
    let listed: Value = serde_json::from_str(&listed).unwrap();
    let targets = listed["externalTargets"].as_array().unwrap();
    let sms = targets
        .iter()
        .find(|target| target["platform"].as_str() == Some("sms"))
        .expect("missing SMS external target");
    assert_eq!(sms["target"], "sms:<phone>");
    assert_eq!(sms["homeTarget"], "sms:+15557654321");

    let payloads = super::communication::sms_send_message_payloads(
        &store,
        &json!({"target": "sms:+15550001111", "message": "hello MEDIA:https://example.com/a.png"}),
    )
    .unwrap();
    assert_eq!(payloads[0]["to"], "+15550001111");
    assert_eq!(payloads[0]["message"], "hello");
    assert_eq!(payloads[0]["media_urls"][0], "https://example.com/a.png");
    let explicit_media_payloads = super::communication::sms_send_message_payloads(
        &store,
        &json!({
            "target": "sms:+15550001111",
            "message": "hello",
            "media_url": "https://example.com/b.png"
        }),
    )
    .unwrap();
    assert_eq!(
        explicit_media_payloads[0]["media_urls"][0],
        "https://example.com/b.png"
    );

    let media_error = super::communication::sms_send_message_payloads(
        &store,
        &json!({"target": "sms:+15550001111", "message": "hello MEDIA:C:\\tmp\\a.png"}),
    )
    .unwrap_err();
    assert!(media_error
        .to_string()
        .contains("SMS MEDIA attachments must be public http(s) URLs"));

    let _ = fs::remove_dir_all(dir);
}

#[tokio::test]
async fn sms_send_message_posts_twilio_media_urls() {
    let listener = tokio::net::TcpListener::bind("127.0.0.1:0").await.unwrap();
    let addr = listener.local_addr().unwrap();
    let api_base_url = format!("http://{addr}");
    let requests = std::sync::Arc::new(Mutex::new(Vec::<String>::new()));
    let requests_for_task = requests.clone();
    tokio::spawn(async move {
        let Ok((mut stream, _)) = listener.accept().await else {
            return;
        };
        let mut buffer = vec![0; 8192];
        let mut request_bytes = Vec::new();
        loop {
            let bytes = stream.read(&mut buffer).await.unwrap_or(0);
            if bytes == 0 {
                break;
            }
            request_bytes.extend_from_slice(&buffer[..bytes]);
            if request_bytes.windows(4).any(|window| window == b"\r\n\r\n") {
                let request_text = String::from_utf8_lossy(&request_bytes);
                let content_length = request_text
                    .lines()
                    .find_map(|line| {
                        line.strip_prefix("Content-Length:")
                            .or_else(|| line.strip_prefix("content-length:"))
                            .and_then(|value| value.trim().parse::<usize>().ok())
                    })
                    .unwrap_or(0);
                let header_len = request_bytes
                    .windows(4)
                    .position(|window| window == b"\r\n\r\n")
                    .map(|index| index + 4)
                    .unwrap_or(request_bytes.len());
                if request_bytes.len().saturating_sub(header_len) >= content_length {
                    break;
                }
            }
        }
        let request = String::from_utf8_lossy(&request_bytes).to_string();
        requests_for_task.lock().unwrap().push(request);
        let body = json!({"sid": "SM123"}).to_string();
        let response = format!(
            "HTTP/1.1 201 Created\r\nContent-Type: application/json\r\nContent-Length: {}\r\n\r\n{}",
            body.len(),
            body
        );
        let _ = stream.write_all(response.as_bytes()).await;
    });

    let dir = std::env::temp_dir().join(format!(
        "synthchat-send-message-sms-media-url-{}",
        new_id("test")
    ));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    let mut config = store.config().unwrap();
    config.sms = json!({
        "accountSid": "AC123",
        "authToken": "token",
        "fromNumber": "+15551234567",
        "apiBaseUrl": api_base_url,
        "timeoutSeconds": 5
    });
    store.set_config(config).unwrap();

    let result = sms_send_message_tool(
        &store,
        &json!({
            "to": "+15550001111",
            "message": "**hello**",
            "media_urls": ["https://example.com/photo.jpg"]
        }),
    )
    .await
    .unwrap();
    let result: Value = serde_json::from_str(&result).unwrap();
    assert_eq!(result["success"], true);
    assert_eq!(result["message_id"], "SM123");
    assert_eq!(result["media_count"], 1);

    let requests = requests.lock().unwrap().join("\n---\n");
    assert!(requests.contains("POST /2010-04-01/Accounts/AC123/Messages.json "));
    assert!(requests.contains("From=%2B15551234567"));
    assert!(requests.contains("To=%2B15550001111"));
    assert!(requests.contains("Body=hello"));
    assert!(requests.contains("MediaUrl=https%3A%2F%2Fexample.com%2Fphoto.jpg"));

    let _ = fs::remove_dir_all(dir);
}

#[test]
fn dingtalk_and_whatsapp_helpers_parse_settings_and_payload_targets() {
    let dingtalk = dingtalk_settings(&json!({
        "webhookUrl": "https://oapi.dingtalk.com/robot/send?access_token=token",
        "timeoutSeconds": 45
    }))
    .unwrap();
    assert_eq!(
        dingtalk.webhook_url,
        "https://oapi.dingtalk.com/robot/send?access_token=token"
    );
    assert_eq!(dingtalk.timeout_seconds, 45);

    let whatsapp = whatsapp_settings(&json!({
        "bridgeUrl": "http://localhost:3001/",
        "timeoutSeconds": 45
    }))
    .unwrap();
    assert_eq!(whatsapp.bridge_url, "http://localhost:3001");
    assert_eq!(whatsapp.timeout_seconds, 45);
    assert_eq!(
        whatsapp_send_url(&whatsapp).unwrap().as_str(),
        "http://localhost:3001/send"
    );
    assert_eq!(
        whatsapp_send_media_url(&whatsapp).unwrap().as_str(),
        "http://localhost:3001/send-media"
    );
    assert!(whatsapp_configured(&json!({"enabled": true})));

    let dir = std::env::temp_dir().join(format!(
        "synthchat-send-message-dingtalk-whatsapp-{}",
        new_id("test")
    ));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    let conversation = store
        .create_conversation(Some("bridges".into()), None)
        .unwrap();
    let mut config = store.config().unwrap();
    config.dingtalk = json!({
        "webhookUrl": "https://oapi.dingtalk.com/robot/send?access_token=token",
        "homeTarget": "robot"
    });
    config.whatsapp = json!({
        "enabled": true,
        "bridgeUrl": "http://localhost:3001",
        "homeChatId": "15551234567@c.us"
    });
    store.set_config(config).unwrap();

    let listed = send_message_tool(&store, &conversation.id, &json!({"action": "list"})).unwrap();
    let listed: Value = serde_json::from_str(&listed).unwrap();
    let targets = listed["externalTargets"].as_array().unwrap();
    let dingtalk = targets
        .iter()
        .find(|target| target["platform"].as_str() == Some("dingtalk"))
        .expect("missing DingTalk external target");
    assert_eq!(dingtalk["target"], "dingtalk:<target>");
    assert_eq!(dingtalk["homeTarget"], "dingtalk:robot");
    let whatsapp = targets
        .iter()
        .find(|target| target["platform"].as_str() == Some("whatsapp"))
        .expect("missing WhatsApp external target");
    assert_eq!(whatsapp["target"], "whatsapp:<chat_id>");
    assert_eq!(whatsapp["homeTarget"], "whatsapp:15551234567@c.us");

    let dingtalk_payloads = super::communication::dingtalk_send_message_payloads(
        &store,
        &json!({"target": "dingtalk:robot", "message": "hello MEDIA:https://example.com/a.png"}),
    )
    .unwrap();
    assert_eq!(dingtalk_payloads[0]["target"], "robot");
    assert_eq!(dingtalk_payloads[0]["message"], "hello");
    assert_eq!(
        dingtalk_payloads[0]["media_urls"][0],
        "https://example.com/a.png"
    );
    let dingtalk_media_error = super::communication::dingtalk_send_message_payloads(
        &store,
        &json!({"target": "dingtalk:robot", "message": "hello MEDIA:C:\\tmp\\a.png"}),
    )
    .unwrap_err();
    assert!(dingtalk_media_error
        .to_string()
        .contains("DingTalk MEDIA attachments must be public http(s) image URLs"));
    let whatsapp_payloads = super::communication::whatsapp_send_message_payloads(
        &store,
        &json!({"target": "whatsapp:15550001111@c.us", "message": "hello"}),
    )
    .unwrap();
    assert_eq!(whatsapp_payloads[0]["chat_id"], "15550001111@c.us");

    let media_payloads = super::communication::whatsapp_send_message_payloads(
        &store,
        &json!({"target": "whatsapp:15550001111@c.us", "message": "hello MEDIA:C:\\tmp\\a.png"}),
    )
    .unwrap();
    assert_eq!(media_payloads[0]["message"], "hello");
    assert_eq!(
        media_payloads[0]["media_files"][0]["path"],
        "C:\\tmp\\a.png"
    );

    let _ = fs::remove_dir_all(dir);
}

#[tokio::test]
async fn mattermost_typing_tool_matches_hermes_rest_endpoint() {
    let listener = tokio::net::TcpListener::bind("127.0.0.1:0").await.unwrap();
    let addr = listener.local_addr().unwrap();
    let requests = std::sync::Arc::new(Mutex::new(Vec::<String>::new()));
    let requests_for_task = requests.clone();
    tokio::spawn(async move {
        for index in 0..3 {
            let Ok((mut stream, _)) = listener.accept().await else {
                return;
            };
            let mut buffer = vec![0; 8192];
            let mut request_bytes = Vec::new();
            loop {
                let bytes = stream.read(&mut buffer).await.unwrap_or(0);
                if bytes == 0 {
                    break;
                }
                request_bytes.extend_from_slice(&buffer[..bytes]);
                if request_bytes.windows(4).any(|window| window == b"\r\n\r\n") {
                    let request_text = String::from_utf8_lossy(&request_bytes);
                    let content_length = request_text
                        .lines()
                        .find_map(|line| {
                            line.strip_prefix("Content-Length:")
                                .or_else(|| line.strip_prefix("content-length:"))
                                .and_then(|value| value.trim().parse::<usize>().ok())
                        })
                        .unwrap_or(0);
                    let chunked = request_text.lines().any(|line| {
                        line.to_ascii_lowercase().starts_with("transfer-encoding:")
                            && line.to_ascii_lowercase().contains("chunked")
                    });
                    let header_len = request_bytes
                        .windows(4)
                        .position(|window| window == b"\r\n\r\n")
                        .map(|position| position + 4)
                        .unwrap_or(request_bytes.len());
                    if chunked {
                        if request_bytes
                            .windows(5)
                            .any(|window| window == b"0\r\n\r\n")
                        {
                            break;
                        }
                    } else if request_bytes.len().saturating_sub(header_len) >= content_length {
                        break;
                    }
                }
            }
            let request = String::from_utf8_lossy(&request_bytes).to_string();
            requests_for_task.lock().unwrap().push(request);
            let body = match index {
                0 => json!({"id": "bot-user", "username": "synthchat"}).to_string(),
                _ => json!({"status": "OK"}).to_string(),
            };
            let response = format!(
                "HTTP/1.1 200 OK\r\nConnection: close\r\nContent-Type: application/json\r\nContent-Length: {}\r\n\r\n{}",
                body.len(),
                body
            );
            let _ = stream.write_all(response.as_bytes()).await;
        }
    });

    let dir = std::env::temp_dir().join(format!("synthchat-mattermost-typing-{}", new_id("test")));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    let mut config = store.config().unwrap();
    config.mattermost = json!({
        "enabled": true,
        "url": format!("http://{addr}"),
        "token": "mm-token",
        "timeoutSeconds": 5
    });
    store.set_config(config).unwrap();

    let result = mattermost_typing_tool(
        &store,
        &json!({
            "action": "send",
            "channel_id": "channel-1"
        }),
    )
    .await
    .unwrap();
    let result: Value = serde_json::from_str(&result).unwrap();
    assert_eq!(result["success"], true);
    assert_eq!(result["schema"], "hermes_mattermost_typing_desktop_v1");
    assert_eq!(result["chat_id"], "channel-1");
    assert_eq!(result["bot_user_id"], "bot-user");

    let stop: Value = serde_json::from_str(
        &mattermost_typing_tool(&store, &json!({"action": "stop"}))
            .await
            .unwrap(),
    )
    .unwrap();
    assert_eq!(stop["stopped"], true);

    let requests = requests.lock().unwrap().join("\n---\n");
    assert!(requests.contains("GET /api/v4/users/me "));
    assert!(requests.contains("POST /api/v4/users/bot-user/typing "));
    assert!(requests
        .to_ascii_lowercase()
        .contains("authorization: bearer mm-token"));
    assert!(requests.contains("\"channel_id\":\"channel-1\""));

    let status = platform_adapter_status(&store, Some("mattermost")).unwrap();
    assert_eq!(status["typingLifecycle"]["typingSupported"], true);
    assert_eq!(status["capabilityMatrix"]["typing"], true);

    let _ = fs::remove_dir_all(dir);
}

