#[tokio::test]
async fn google_chat_send_message_refreshes_service_account_token() {
    let listener = tokio::net::TcpListener::bind("127.0.0.1:0").await.unwrap();
    let addr = listener.local_addr().unwrap();
    let requests = std::sync::Arc::new(Mutex::new(Vec::<String>::new()));
    let requests_for_task = requests.clone();
    tokio::spawn(async move {
        for index in 0..2 {
            let Ok((mut stream, _)) = listener.accept().await else {
                return;
            };
            let mut buffer = vec![0; 8192];
            let mut request_bytes = Vec::new();
            loop {
                let bytes = stream.read(&mut buffer).await.unwrap_or(0);
                if bytes == 0 {
                    break;
                }
                request_bytes.extend_from_slice(&buffer[..bytes]);
                if request_bytes.windows(4).any(|window| window == b"\r\n\r\n") {
                    let request_text = String::from_utf8_lossy(&request_bytes);
                    let content_length = request_text
                        .lines()
                        .find_map(|line| {
                            line.strip_prefix("Content-Length:")
                                .or_else(|| line.strip_prefix("content-length:"))
                                .and_then(|value| value.trim().parse::<usize>().ok())
                        })
                        .unwrap_or(0);
                    let header_len = request_bytes
                        .windows(4)
                        .position(|window| window == b"\r\n\r\n")
                        .map(|position| position + 4)
                        .unwrap_or(request_bytes.len());
                    if request_bytes.len().saturating_sub(header_len) >= content_length {
                        break;
                    }
                }
            }
            requests_for_task
                .lock()
                .unwrap()
                .push(String::from_utf8_lossy(&request_bytes).to_string());
            let body = if index == 0 {
                json!({"access_token": "refreshed-google-chat-token", "expires_in": 3600})
                    .to_string()
            } else {
                json!({"name": "spaces/SA/messages/msg-2"}).to_string()
            };
            let response = format!(
                "HTTP/1.1 200 OK\r\nContent-Type: application/json\r\nContent-Length: {}\r\n\r\n{}",
                body.len(),
                body
            );
            let _ = stream.write_all(response.as_bytes()).await;
        }
    });

    let mut rng = rsa::rand_core::OsRng;
    let rsa = rsa::RsaPrivateKey::new(&mut rng, 2048).unwrap();
    let private_key = {
        use rsa::pkcs8::{EncodePrivateKey, LineEnding};
        rsa.to_pkcs8_pem(LineEnding::LF).unwrap().to_string()
    };
    let service_account = json!({
        "type": "service_account",
        "client_email": "bot@example.iam.gserviceaccount.com",
        "private_key": private_key
    });
    let dir = std::env::temp_dir().join(format!(
        "synthchat-google-chat-service-account-{}",
        new_id("test")
    ));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    let mut config = store.config().unwrap();
    config.google_chat = json!({
        "enabled": true,
        "apiBaseUrl": format!("http://{addr}"),
        "tokenUri": format!("http://{addr}/token"),
        "serviceAccountJson": service_account.to_string(),
        "timeoutSeconds": 5
    });
    store.set_config(config).unwrap();

    let wrapped = send_message_tool_async(
        &store,
        "conversation-1",
        &json!({
            "target": "google_chat:spaces/SA",
            "message": "service account send"
        }),
    )
    .await
    .unwrap();
    let wrapped: Value = serde_json::from_str(&wrapped).unwrap();
    assert_eq!(wrapped["success"], true);
    assert_eq!(wrapped["message_id"], "spaces/SA/messages/msg-2");

    let requests = requests.lock().unwrap().clone();
    assert_eq!(requests.len(), 2);
    assert!(requests[0].contains("POST /token "));
    assert!(
        requests[0].contains("grant_type=urn%3Aietf%3Aparams%3Aoauth%3Agrant-type%3Ajwt-bearer")
    );
    assert!(requests[0].contains("assertion="));
    assert!(requests[1].contains("POST /v1/spaces/SA/messages "));
    assert!(requests[1]
        .to_ascii_lowercase()
        .contains("authorization: bearer refreshed-google-chat-token"));

    let status = platform_adapter_status(&store, Some("google_chat")).unwrap();
    assert_eq!(status["credentialMode"], "service_account_jwt_refresh");
    assert_eq!(status["capabilityMatrix"]["serviceAccountRefresh"], true);
    assert_eq!(status["googleChatLiveE2e"]["serviceAccountReady"], true);
    assert_eq!(status["googleChatLiveE2e"]["credentialReady"], true);

    let _ = fs::remove_dir_all(dir);
}

