#[test]
fn disk_cleanup_tool_supports_hermes_ephemeral_file_rules() {
    let dir = std::env::temp_dir().join(format!("synthchat-disk-cleanup-{}", new_id("test")));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    let test_file = store.data_dir().join("test_ephemeral.test.py");
    fs::write(&test_file, "print('temporary')").unwrap();

    let guessed =
        disk_cleanup_tool(&store, &json!({"action": "guess", "path": test_file})).unwrap();
    let guessed: Value = serde_json::from_str(&guessed).unwrap();
    assert_eq!(guessed["safe"], true);
    assert_eq!(guessed["category"], "test");

    let tracked = disk_cleanup_tool(
        &store,
        &json!({"action": "track", "path": test_file, "category": "test"}),
    )
    .unwrap();
    let tracked: Value = serde_json::from_str(&tracked).unwrap();
    assert_eq!(tracked["tracked"], true);
    assert_eq!(tracked["category"], "test");
    assert_eq!(tracked["trackedCount"], 1);

    let preview = disk_cleanup_tool(&store, &json!({"action": "dry_run"})).unwrap();
    let preview: Value = serde_json::from_str(&preview).unwrap();
    assert_eq!(preview["autoDeleteCount"], 1);
    assert_eq!(preview["needsPromptCount"], 0);

    let cleaned = disk_cleanup_tool(&store, &json!({"action": "quick"})).unwrap();
    let cleaned: Value = serde_json::from_str(&cleaned).unwrap();
    assert_eq!(cleaned["deleted"], 1);
    assert_eq!(cleaned["trackedCount"], 0);
    assert!(!test_file.exists());

    let outside = std::env::temp_dir().join(format!("unsafe-disk-cleanup-{}.txt", new_id("test")));
    fs::write(&outside, "outside").unwrap();
    let rejected = disk_cleanup_tool(
        &store,
        &json!({"action": "track", "path": outside, "category": "test"}),
    )
    .unwrap();
    let rejected: Value = serde_json::from_str(&rejected).unwrap();
    assert_eq!(rejected["tracked"], false);
    assert_eq!(rejected["reason"], "outside_safe_roots");
    assert!(outside.exists());

    let _ = fs::remove_file(outside);
    let _ = fs::remove_dir_all(dir);
}

