#[tokio::test]
async fn langfuse_native_hooks_buffer_and_flush_observability_events() {
    let listener = tokio::net::TcpListener::bind("127.0.0.1:0").await.unwrap();
    let addr = listener.local_addr().unwrap();
    let requests = std::sync::Arc::new(Mutex::new(Vec::<String>::new()));
    let requests_for_task = requests.clone();
    tokio::spawn(async move {
        let Ok((mut stream, _)) = listener.accept().await else {
            return;
        };
        let mut buffer = vec![0; 16384];
        let mut request_bytes = Vec::new();
        loop {
            let bytes = stream.read(&mut buffer).await.unwrap_or(0);
            if bytes == 0 {
                break;
            }
            request_bytes.extend_from_slice(&buffer[..bytes]);
            if request_bytes.windows(4).any(|window| window == b"\r\n\r\n") {
                let request_text = String::from_utf8_lossy(&request_bytes);
                let content_length = request_text
                    .lines()
                    .find_map(|line| {
                        line.strip_prefix("Content-Length:")
                            .or_else(|| line.strip_prefix("content-length:"))
                            .and_then(|value| value.trim().parse::<usize>().ok())
                    })
                    .unwrap_or(0);
                let header_len = request_bytes
                    .windows(4)
                    .position(|window| window == b"\r\n\r\n")
                    .map(|index| index + 4)
                    .unwrap_or(request_bytes.len());
                if request_bytes.len().saturating_sub(header_len) >= content_length {
                    break;
                }
            }
        }
        requests_for_task
            .lock()
            .unwrap()
            .push(String::from_utf8_lossy(&request_bytes).to_string());
        let body = json!({"ok": true}).to_string();
        let response = format!(
            "HTTP/1.1 200 OK\r\nContent-Type: application/json\r\nContent-Length: {}\r\n\r\n{}",
            body.len(),
            body
        );
        let _ = stream.write_all(response.as_bytes()).await;
    });

    std::env::set_var("HERMES_LANGFUSE_PUBLIC_KEY", "pk-lf-test-public");
    std::env::set_var("HERMES_LANGFUSE_SECRET_KEY", "sk-lf-test-secret");
    std::env::set_var("HERMES_LANGFUSE_BASE_URL", format!("http://{addr}"));
    std::env::set_var("HERMES_LANGFUSE_SAMPLE_RATE", "1.0");

    let dir = std::env::temp_dir().join(format!("synthchat-langfuse-{}", new_id("test")));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    assert!(internal_tool_prompt_lines()
        .iter()
        .any(|(name, _)| *name == "trace_flush"));
    assert!(is_internal_tool("trace_flush"));

    let contexts =
        run_pre_llm_call_hooks(&store, "run-langfuse", "hello with secret sk-test").await;
    assert!(contexts.is_empty());
    run_pre_tool_call_hooks(
        &store,
        "run-langfuse",
        "read_file",
        &json!({"path": "README.md"}),
    )
    .await
    .unwrap();
    run_post_tool_call_hooks(
        &store,
        "run-langfuse",
        "read_file",
        &json!({"path": "README.md"}),
        &json!({"ok": true, "text": "done"}),
    )
    .await
    .unwrap();

    let dry = langfuse_tool(&store, &json!({"action": "flush", "dryRun": true}))
        .await
        .unwrap();
    let dry: Value = serde_json::from_str(&dry).unwrap();
    assert_eq!(dry["pendingEvents"], 3);
    assert_eq!(dry["batch"]["batch"][0]["type"], "event-create");
    assert_eq!(
        dry["batch"]["batch"][0]["body"]["metadata"]["schema"],
        "hermes_langfuse_desktop_v1"
    );

    let flushed = langfuse_tool(&store, &json!({"action": "flush"}))
        .await
        .unwrap();
    let flushed: Value = serde_json::from_str(&flushed).unwrap();
    assert_eq!(flushed["sent"], 3);
    assert_eq!(flushed["pendingEvents"], 0);

    let request = requests.lock().unwrap().join("\n");
    assert!(request.contains("POST /api/public/ingestion "));
    assert!(request.contains("Authorization: Basic "));
    assert!(request.contains("hermes_langfuse_desktop_v1"));
    assert!(request.contains("post_tool_call"));

    std::env::remove_var("HERMES_LANGFUSE_PUBLIC_KEY");
    std::env::remove_var("HERMES_LANGFUSE_SECRET_KEY");
    std::env::remove_var("HERMES_LANGFUSE_BASE_URL");
    std::env::remove_var("HERMES_LANGFUSE_SAMPLE_RATE");
    let _ = fs::remove_dir_all(dir);
}

