async fn whatsapp_send_message_forwards_media_to_bridge() {
    let listener = tokio::net::TcpListener::bind("127.0.0.1:0").await.unwrap();
    let addr = listener.local_addr().unwrap();
    let bridge_url = format!("http://{addr}");
    let requests = std::sync::Arc::new(Mutex::new(Vec::<String>::new()));
    let requests_for_task = requests.clone();
    tokio::spawn(async move {
        for _ in 0..2 {
            let Ok((mut stream, _)) = listener.accept().await else {
                return;
            };
            let mut buffer = vec![0; 8192];
            let mut request_bytes = Vec::new();
            loop {
                let bytes = stream.read(&mut buffer).await.unwrap_or(0);
                if bytes == 0 {
                    break;
                }
                request_bytes.extend_from_slice(&buffer[..bytes]);
                if request_bytes.windows(4).any(|window| window == b"\r\n\r\n") {
                    let request_text = String::from_utf8_lossy(&request_bytes);
                    let content_length = request_text
                        .lines()
                        .find_map(|line| {
                            line.strip_prefix("Content-Length:")
                                .or_else(|| line.strip_prefix("content-length:"))
                                .and_then(|value| value.trim().parse::<usize>().ok())
                        })
                        .unwrap_or(0);
                    let header_len = request_bytes
                        .windows(4)
                        .position(|window| window == b"\r\n\r\n")
                        .map(|index| index + 4)
                        .unwrap_or(request_bytes.len());
                    if request_bytes.len().saturating_sub(header_len) >= content_length {
                        break;
                    }
                }
            }
            let request = String::from_utf8_lossy(&request_bytes).to_string();
            requests_for_task.lock().unwrap().push(request.clone());
            let first_line = request.lines().next().unwrap_or_default();
            let body = if first_line.contains("/send-media") {
                json!({"messageId": "media-1"}).to_string()
            } else {
                json!({"messageId": "text-1"}).to_string()
            };
            let response = format!(
                "HTTP/1.1 200 OK\r\nContent-Type: application/json\r\nContent-Length: {}\r\n\r\n{}",
                body.len(),
                body
            );
            let _ = stream.write_all(response.as_bytes()).await;
        }
    });

    let dir = std::env::temp_dir().join(format!("synthchat-whatsapp-media-{}", new_id("test")));
    fs::create_dir_all(&dir).unwrap();
    let media_path = dir.join("photo.png");
    fs::write(&media_path, "image bytes").unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    let mut config = store.config().unwrap();
    config.whatsapp = json!({
        "enabled": true,
        "bridgeUrl": bridge_url
    });
    store.set_config(config).unwrap();

    let result = whatsapp_send_message_tool(
        &store,
        &json!({
            "chat_id": "15550001111@c.us",
            "message": "hello",
            "media_files": [media_path.to_string_lossy()]
        }),
    )
    .await
    .unwrap();
    let result: Value = serde_json::from_str(&result).unwrap();
    assert_eq!(result["success"], true);
    assert_eq!(result["platform"], "whatsapp");
    assert_eq!(result["message_id"], "media-1");
    assert_eq!(result["media_count"], 1);

    let requests = requests.lock().unwrap().join("\n---\n");
    assert!(requests.contains("POST /send "));
    assert!(requests.contains("hello"));
    assert!(requests.contains("POST /send-media "));
    assert!(requests.contains("photo.png"));
    assert!(requests.contains("\"mediaType\":\"image\""));
    assert!(requests.contains("15550001111@c.us"));

    let _ = fs::remove_dir_all(dir);
}

#[test]
fn qqbot_helpers_parse_settings_and_payload_targets() {
    let settings = qqbot_settings(&json!({
        "appId": "appid",
        "clientSecret": "secret",
        "apiBaseUrl": "https://api.sgroup.qq.com/",
        "tokenUrl": "https://bots.qq.com/app/getAppAccessToken",
        "timeoutSeconds": 45
    }))
    .unwrap();
    assert_eq!(settings.app_id, "appid");
    assert_eq!(settings.client_secret, "secret");
    assert_eq!(settings.api_base_url, "https://api.sgroup.qq.com");
    assert_eq!(
        settings.token_url,
        "https://bots.qq.com/app/getAppAccessToken"
    );
    assert_eq!(settings.timeout_seconds, 45);
    assert_eq!(
        qqbot_message_url(&settings, "channel", "123")
            .unwrap()
            .as_str(),
        "https://api.sgroup.qq.com/channels/123/messages"
    );
    assert_eq!(
        qqbot_message_url(&settings, "c2c", "user123")
            .unwrap()
            .as_str(),
        "https://api.sgroup.qq.com/v2/users/user123/messages"
    );
    assert_eq!(
        qqbot_message_url(&settings, "group", "group123")
            .unwrap()
            .as_str(),
        "https://api.sgroup.qq.com/v2/groups/group123/messages"
    );
    assert_eq!(
        qqbot_file_url(&settings, "c2c", "user123")
            .unwrap()
            .as_str(),
        "https://api.sgroup.qq.com/v2/users/user123/files"
    );
    assert_eq!(
        qqbot_file_url(&settings, "group", "group123")
            .unwrap()
            .as_str(),
        "https://api.sgroup.qq.com/v2/groups/group123/files"
    );
    assert_eq!(
        qqbot_upload_prepare_url(&settings, "c2c", "user123")
            .unwrap()
            .as_str(),
        "https://api.sgroup.qq.com/v2/users/user123/upload_prepare"
    );
    assert_eq!(
        qqbot_upload_part_finish_url(&settings, "group", "group123")
            .unwrap()
            .as_str(),
        "https://api.sgroup.qq.com/v2/groups/group123/upload_part_finish"
    );

    let dir = std::env::temp_dir().join(format!("synthchat-send-message-qqbot-{}", new_id("test")));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    let conversation = store
        .create_conversation(Some("qqbot".into()), None)
        .unwrap();
    let mut config = store.config().unwrap();
    config.qqbot = json!({
        "appId": "appid",
        "clientSecret": "secret",
        "homeTarget": "channel123"
    });
    store.set_config(config).unwrap();

    let listed = send_message_tool(&store, &conversation.id, &json!({"action": "list"})).unwrap();
    let listed: Value = serde_json::from_str(&listed).unwrap();
    let targets = listed["externalTargets"].as_array().unwrap();
    let qqbot = targets
        .iter()
        .find(|target| target["platform"].as_str() == Some("qqbot"))
        .expect("missing QQBot external target");
    assert_eq!(qqbot["target"], "qqbot:<id>");
    assert_eq!(qqbot["homeTarget"], "qqbot:channel123");

    let payloads = super::communication::qqbot_send_message_payloads(
        &store,
        &json!({"target": "qqbot:user123", "message": "hello"}),
    )
    .unwrap();
    assert_eq!(payloads[0]["chat_id"], "user123");

    let media_payloads = super::communication::qqbot_send_message_payloads(
        &store,
        &json!({"target": "qqbot:user123", "message": "hello MEDIA:C:\\tmp\\a.png"}),
    )
    .unwrap();
    assert_eq!(media_payloads[0]["message"], "hello");
    assert_eq!(
        media_payloads[0]["media_files"][0]["path"],
        "C:\\tmp\\a.png"
    );
    let approval_keyboard = qqbot_approval_keyboard("agent:main:qqbot:c2c:user123");
    assert_eq!(
        approval_keyboard["content"]["rows"][0]["buttons"][0]["action"]["data"],
        "approve:agent:main:qqbot:c2c:user123:allow-once"
    );
    assert_eq!(
        qqbot_parse_approval_button_data("approve:agent:main:qqbot:c2c:user123:allow-always"),
        Some(("agent:main:qqbot:c2c:user123".into(), "allow-always".into()))
    );
    assert_eq!(
        qqbot_parse_update_prompt_button_data("update_prompt:y"),
        Some("y".into())
    );
    assert!(qqbot_parse_approval_button_data("approve:bad").is_none());

    let _ = fs::remove_dir_all(dir);
}

