#[test]
fn qqbot_onboard_crypto_helpers_decrypt_aes_gcm_secret() {
    use aes_gcm::{
        aead::{Aead, KeyInit},
        Aes256Gcm, Nonce,
    };
    use base64::Engine as _;

    let bind_key = qqbot_generate_bind_key();
    let key = base64::engine::general_purpose::STANDARD
        .decode(&bind_key)
        .unwrap();
    assert_eq!(key.len(), 32);

    let iv = [7u8; 12];
    let cipher = Aes256Gcm::new_from_slice(&key).unwrap();
    let mut payload = iv.to_vec();
    payload.extend(
        cipher
            .encrypt(Nonce::from_slice(&iv), b"client-secret-for-test".as_slice())
            .unwrap(),
    );
    let encrypted = base64::engine::general_purpose::STANDARD.encode(payload);

    assert_eq!(
        qqbot_decrypt_secret(&encrypted, &bind_key).unwrap(),
        "client-secret-for-test"
    );
    assert_eq!(
        qqbot_build_connect_url("task id/1"),
        "https://q.qq.com/qqbot/openclaw/connect.html?task_id=task%20id%2F1&_wv=2&source=hermes"
    );
}

