#[test]
fn sethome_control_command_updates_gateway_home_targets() {
    let dir = std::env::temp_dir().join(format!("synthchat-sethome-control-{}", new_id("test")));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    let mut config = store.config().unwrap();
    config.telegram = json!({
        "botToken": "telegram-token",
        "apiBaseUrl": "https://api.telegram.org"
    });
    config.slack = json!({
        "botToken": "slack-token",
        "apiBaseUrl": "https://slack.com/api"
    });
    store.set_config(config).unwrap();

    let telegram = handle_sethome_control_command(&store, "telegram:-100123:42").unwrap();
    assert!(telegram.contains("telegram:-100123:42"));
    let config = store.config().unwrap();
    assert_eq!(config.telegram["homeChannel"], "-100123");
    assert_eq!(config.telegram["homeThreadId"], "42");

    let slack = handle_sethome_control_command(&store, "slack:C123:1712345678.000100").unwrap();
    assert!(slack.contains("slack:C123:1712345678.000100"));
    let config = store.config().unwrap();
    assert_eq!(config.slack["homeChannel"], "C123");
    assert_eq!(config.slack["homeThreadId"], "1712345678.000100");

    let status = handle_sethome_control_command(&store, "status").unwrap();
    assert!(status.contains("- telegram: telegram:-100123:42"));
    assert!(status.contains("- slack: slack:C123:1712345678.000100"));

    let error = handle_sethome_control_command(&store, "unknown:target").unwrap_err();
    assert!(error
        .to_string()
        .contains("unsupported home target platform"));

    let _ = fs::remove_dir_all(dir);
}

#[tokio::test]
async fn qqbot_send_message_uses_chunked_upload_for_large_media_file() {
    let listener = tokio::net::TcpListener::bind("127.0.0.1:0").await.unwrap();
    let addr = listener.local_addr().unwrap();
    let base_url = format!("http://{addr}");
    let cos_url = format!("{base_url}/cos/part1");
    let requests = std::sync::Arc::new(Mutex::new(Vec::<String>::new()));
    let requests_for_task = requests.clone();
    tokio::spawn(async move {
        for _ in 0..6 {
            let Ok((mut stream, _)) = listener.accept().await else {
                return;
            };
            let mut buffer = vec![0; 8192];
            let mut request_bytes = Vec::new();
            loop {
                let bytes = stream.read(&mut buffer).await.unwrap_or(0);
                if bytes == 0 {
                    break;
                }
                request_bytes.extend_from_slice(&buffer[..bytes]);
                if request_bytes.windows(4).any(|window| window == b"\r\n\r\n") {
                    let request_text = String::from_utf8_lossy(&request_bytes);
                    let content_length = request_text
                        .lines()
                        .find_map(|line| {
                            line.strip_prefix("Content-Length:")
                                .or_else(|| line.strip_prefix("content-length:"))
                                .and_then(|value| value.trim().parse::<usize>().ok())
                        })
                        .unwrap_or(0);
                    let header_len = request_bytes
                        .windows(4)
                        .position(|window| window == b"\r\n\r\n")
                        .map(|index| index + 4)
                        .unwrap_or(request_bytes.len());
                    if request_bytes.len().saturating_sub(header_len) >= content_length {
                        break;
                    }
                }
            }
            let request = String::from_utf8_lossy(&request_bytes).to_string();
            requests_for_task.lock().unwrap().push(request.clone());
            let first_line = request.lines().next().unwrap_or_default();
            let body = if first_line.contains("/token") {
                json!({"access_token": "qq-token"}).to_string()
            } else if first_line.contains("/upload_prepare") {
                json!({
                    "upload_id": "upload-1",
                    "block_size": 5,
                    "parts": [{
                        "part_index": 1,
                        "presigned_url": cos_url,
                        "block_size": 5
                    }]
                })
                .to_string()
            } else if first_line.starts_with("PUT /cos/part1 ") {
                "OK".to_string()
            } else if first_line.contains("/upload_part_finish") {
                json!({"ok": true}).to_string()
            } else if first_line.contains("/files") {
                json!({"file_info": "chunked-file-info"}).to_string()
            } else {
                json!({"id": "chunked-media-msg-1"}).to_string()
            };
            let content_type = if body == "OK" {
                "text/plain"
            } else {
                "application/json"
            };
            let response = format!(
                "HTTP/1.1 200 OK\r\nContent-Type: {content_type}\r\nContent-Length: {}\r\n\r\n{}",
                body.len(),
                body
            );
            let _ = stream.write_all(response.as_bytes()).await;
        }
    });

    let dir = std::env::temp_dir().join(format!("synthchat-qqbot-chunked-{}", new_id("test")));
    fs::create_dir_all(&dir).unwrap();
    let media_path = dir.join("large.txt");
    fs::write(&media_path, "hello").unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    let mut config = store.config().unwrap();
    config.qqbot = json!({
        "appId": "appid",
        "clientSecret": "secret",
        "apiBaseUrl": base_url,
        "tokenUrl": format!("{base_url}/token"),
        "timeoutSeconds": 5,
        "chunkedUploadThresholdBytes": 1
    });
    store.set_config(config).unwrap();

    let result = qqbot_send_message_tool(
        &store,
        &json!({
            "chat_id": "user123",
            "media_files": [media_path.to_string_lossy()]
        }),
    )
    .await
    .unwrap();
    let result: Value = serde_json::from_str(&result).unwrap();
    assert_eq!(result["success"], true);
    assert_eq!(result["message_id"], "chunked-media-msg-1");
    assert_eq!(result["media_count"], 1);

    let requests = requests.lock().unwrap().join("\n---\n");
    assert!(requests.contains("POST /v2/users/user123/upload_prepare "));
    assert!(requests.contains("\"file_size\":5"));
    assert!(requests.contains("\"md5\":\"5d41402abc4b2a76b9719d911017c592\""));
    assert!(requests.contains("\"sha1\":\"aaf4c61ddcc5e8a2dabede0f3b482cd9aea9434d\""));
    assert!(requests.contains("\"md5_10m\":\"5d41402abc4b2a76b9719d911017c592\""));
    assert!(requests.contains("PUT /cos/part1 "));
    assert!(requests.contains("hello"));
    assert!(requests.contains("POST /v2/users/user123/upload_part_finish "));
    assert!(requests.contains("\"upload_id\":\"upload-1\""));
    assert!(requests.contains("\"part_index\":1"));
    assert!(requests.contains("POST /v2/users/user123/files "));
    assert!(requests.contains("chunked-file-info"));
    assert!(requests.contains("\"msg_type\":7"));

    let _ = fs::remove_dir_all(dir);
}

#[test]
fn messaging_gateway_targets_and_payloads_preserve_hermes_targets() {
    let settings = messaging_gateway_settings(&json!({
        "enabled": true,
        "url": "127.0.0.1:8765",
        "token": "secret",
        "sendPath": "/api/tools/send_message",
        "platforms": ["wecom", "weixin", "yuanbao"],
        "timeoutSeconds": 42,
    }))
    .unwrap();
    assert_eq!(settings.url, "http://127.0.0.1:8765");
    assert_eq!(
        messaging_gateway_send_url(&settings).unwrap().as_str(),
        "http://127.0.0.1:8765/api/tools/send_message"
    );
    assert!(settings.platforms.contains("weixin"));

    let dir =
        std::env::temp_dir().join(format!("synthchat-send-message-gateway-{}", new_id("test")));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    let conversation = store
        .create_conversation(Some("gateway".into()), None)
        .unwrap();
    let mut config = store.config().unwrap();
    config.messaging_gateway = json!({
        "enabled": true,
        "url": "http://127.0.0.1:8765",
        "sendPath": "/send_message",
        "platforms": ["wecom", "weixin", "yuanbao"],
    });
    store.set_config(config).unwrap();

    let listed = send_message_tool(&store, &conversation.id, &json!({"action": "list"})).unwrap();
    let listed: Value = serde_json::from_str(&listed).unwrap();
    let targets = listed["externalTargets"].as_array().unwrap();
    assert!(targets
        .iter()
        .any(|target| target["platform"] == "wecom" && target["source"] == "messagingGateway"));
    assert!(targets
        .iter()
        .any(|target| target["platform"] == "weixin" && target["source"] == "messagingGateway"));
    assert!(targets.iter().any(|target| target["platform"] == "yuanbao"
        && target["target"] == "yuanbao:group:<group_code>"));

    assert!(
        super::communication::send_message_targets_messaging_gateway(
            &store,
            &json!({"target": "weixin:filehelper", "message": "hello"})
        )
        .unwrap()
    );
    assert!(
        super::communication::send_message_targets_messaging_gateway(
            &store,
            &json!({"target": "yuanbao:group:123", "message": "hello"})
        )
        .unwrap()
    );
    assert!(
        super::communication::send_message_targets_messaging_gateway(
            &store,
            &json!({"target": "group:123", "message": "hello"})
        )
        .unwrap()
    );
    assert!(
        !super::communication::send_message_targets_messaging_gateway(
            &store,
            &json!({"target": "yuanbao:direct:abc", "message": "hello"})
        )
        .unwrap()
    );

    let payloads = super::communication::messaging_gateway_send_message_payloads(&json!({
        "target": "wecom:user:alice",
        "message": "hello MEDIA:C:\\tmp\\report.pdf",
    }))
    .unwrap();
    assert_eq!(payloads[0]["platform"], "wecom");
    assert_eq!(payloads[0]["target"], "wecom:user:alice");
    assert_eq!(payloads[0]["chat_id"], "user:alice");
    assert_eq!(payloads[0]["media_files"][0]["path"], "C:\\tmp\\report.pdf");

    let group_payloads = super::communication::messaging_gateway_send_message_payloads(&json!({
        "target": "yuanbao:group:123",
        "message": "group hello",
    }))
    .unwrap();
    assert_eq!(group_payloads[0]["platform"], "yuanbao");
    assert_eq!(group_payloads[0]["chat_id"], "group:123");

    let shorthand_group_payloads =
        super::communication::messaging_gateway_send_message_payloads(&json!({
            "target": "group:123",
            "message": "group hello",
        }))
        .unwrap();
    assert_eq!(shorthand_group_payloads[0]["platform"], "yuanbao");
    assert_eq!(shorthand_group_payloads[0]["chat_id"], "group:123");

    let _ = fs::remove_dir_all(dir);
}

#[test]
fn delivery_mirror_writes_to_matching_gateway_origin_session() {
    let dir = std::env::temp_dir().join(format!("synthchat-delivery-mirror-{}", new_id("test")));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    let alice = store
        .create_conversation(Some("WeCom Alice".into()), None)
        .unwrap();
    store
        .set_conversation_metadata_value(&alice.id, "platform", json!("wecom"))
        .unwrap();
    store
        .set_conversation_metadata_value(
            &alice.id,
            "origin",
            json!({
                "platform": "wecom",
                "chatId": "room-1",
                "chat_id": "room-1",
                "userId": "alice",
                "user_id": "alice"
            }),
        )
        .unwrap();
    let bob = store
        .create_conversation(Some("WeCom Bob".into()), None)
        .unwrap();
    store
        .set_conversation_metadata_value(
            &bob.id,
            "origin",
            json!({
                "platform": "wecom",
                "chatId": "room-1",
                "chat_id": "room-1",
                "userId": "bob",
                "user_id": "bob"
            }),
        )
        .unwrap();

    assert!(!super::communication::delivery_mirror_to_session(
        &store,
        "wecom",
        &json!({"chat_id": "room-1", "message": "ambiguous delivery"}),
        "test"
    ));
    assert!(super::communication::delivery_mirror_to_session(
        &store,
        "wecom",
        &json!({"chat_id": "room-1", "user_id": "alice", "message": "sent to alice"}),
        "test"
    ));

    let alice_messages = store.messages(&alice.id, None).unwrap();
    assert_eq!(alice_messages.len(), 1);
    assert_eq!(alice_messages[0].role, "assistant");
    assert_eq!(alice_messages[0].source, "delivery-mirror");
    assert_eq!(alice_messages[0].content, "sent to alice");
    assert_eq!(
        alice_messages[0].provider_data.as_ref().unwrap()["mirrorSource"],
        "test"
    );
    assert!(store.messages(&bob.id, None).unwrap().is_empty());

    let _ = fs::remove_dir_all(dir);
}

#[test]
fn send_message_platform_results_include_hermes_post_delivery_metadata() {
    let single = super::communication::format_send_message_delivery_result(
        "telegram",
        &[json!({
            "chat_id": "-1001",
            "thread_id": "42",
            "message": "hello"
        })],
        vec![json!({
            "success": true,
            "messageId": "tg-1"
        })],
        "telegram",
        json!({}),
    )
    .unwrap();
    let single_json: Value = serde_json::from_str(&single).unwrap();
    assert_eq!(
        single_json["postDelivery"]["schema"],
        "hermes_post_delivery_callback_desktop_v1"
    );
    assert_eq!(single_json["postDelivery"]["delivered"], true);
    assert_eq!(single_json["postDelivery"]["platform"], "telegram");
    assert_eq!(single_json["postDelivery"]["transport"], "telegram");
    assert_eq!(single_json["postDelivery"]["target"], "-1001");
    assert_eq!(single_json["postDelivery"]["threadId"], "42");
    assert_eq!(single_json["postDelivery"]["messageId"], "tg-1");
    assert_eq!(single_json["postDelivery"]["messageSource"], "send_message");

    let multi = super::communication::format_send_message_delivery_result(
        "slack",
        &[json!({"channel_id": "C123", "thread_ts": "1718.1"})],
        vec![json!({"ok": true, "ts": "1718.2"}), json!({"id": "1718.3"})],
        "slack",
        json!({"custom": true}),
    )
    .unwrap();
    let multi_json: Value = serde_json::from_str(&multi).unwrap();
    assert_eq!(multi_json["success"], true);
    assert_eq!(multi_json["chunks"], 2);
    assert_eq!(multi_json["custom"], true);
    assert_eq!(multi_json["postDelivery"]["messageIds"][0], "1718.2");
    assert_eq!(multi_json["postDelivery"]["messageIds"][1], "1718.3");
    assert_eq!(multi_json["postDelivery"]["chunkCount"], 2);
}

#[tokio::test]
async fn send_message_filters_hermes_silence_narration_before_platform_delivery() {
    let dir =
        std::env::temp_dir().join(format!("synthchat-send-silence-filter-{}", new_id("test")));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    let conversation = store
        .create_conversation(Some("silence filter".into()), None)
        .unwrap();

    let filtered = send_message_tool_async(
        &store,
        &conversation.id,
        &json!({
            "target": "telegram:-100123",
            "message": "."
        }),
    )
    .await
    .unwrap();
    let filtered: Value = serde_json::from_str(&filtered).unwrap();
    assert_eq!(filtered["success"], true);
    assert_eq!(filtered["platform"], "telegram");
    assert_eq!(filtered["filtered"], "silence_narration");
    assert_eq!(
        filtered["filteredReason"],
        "hermes_delivery_silence_narration"
    );
    assert_eq!(filtered["delivered"], false);

    assert!(super::communication::send_message_silence_narration_skip(
        "telegram",
        Some(&json!({
            "message": "*(no reply)*"
        }))
    )
    .is_some());
    assert!(super::communication::send_message_silence_narration_skip(
        "telegram",
        Some(&json!({
            "message": ".",
            "media_files": [{"path": "D:\\tmp\\image.png"}]
        }))
    )
    .is_none());
    assert!(super::communication::send_message_silence_narration_skip(
        "telegram",
        Some(&json!({
            "message": "The service completed silently but produced a report."
        }))
    )
    .is_none());

    let _ = fs::remove_dir_all(dir);
}

#[test]
fn messaging_gateway_receive_runtime_parses_bridge_events() {
    let config = json!({
        "enabled": true,
        "webhookHost": "127.0.0.1",
        "webhookPort": 8767,
        "webhookPath": "/gateway/inbound",
        "platforms": ["wecom", "weixin", "yuanbao"],
        "allowedUsers": ["alice"],
        "allowedChats": ["room-1"],
        "mentionPatterns": ["@bot"],
        "requireMention": true,
    });
    let settings = messaging_gateway_receive_settings(&config).unwrap();
    assert_eq!(settings.path, "/gateway/inbound");
    assert!(settings.platforms.contains("wecom"));
    assert!(messaging_gateway_receive_configured(&config));
    assert!(messaging_gateway_runtime_configured(&config));

    let ignored = messaging_gateway_inbound_event_from_payload(
        &json!({
            "platform": "wecom",
            "chat_id": "room-1",
            "user_id": "alice",
            "chat_type": "group",
            "text": "hello"
        }),
        &config,
        &settings,
    );
    assert!(ignored.is_none());

    let inbound = messaging_gateway_inbound_event_from_payload(
        &json!({
            "platform": "wecom",
            "chat_id": "room-1",
            "user_id": "alice",
            "chat_type": "group",
            "text": "@bot hello",
            "attachments": [{
                "id": "file-1",
                "fileName": "report.pdf",
                "mimeType": "application/pdf",
                "size": 123
            }]
        }),
        &config,
        &settings,
    )
    .unwrap();
    assert_eq!(inbound["platform"], "wecom");
    assert_eq!(inbound["source"]["chat_id"], "room-1");
    assert_eq!(inbound["source"]["user_id"], "alice");
    assert_eq!(inbound["attachments"][0]["download_status"], "skipped");

    let state = messaging_gateway_adapter_state_for_platform(
        json!({"status": "running"}),
        true,
        true,
        "wecom",
    );
    assert_eq!(state["platform"], "wecom");
    assert_eq!(state["runtime"], true);
    assert!(state["capabilities"]
        .as_array()
        .unwrap()
        .iter()
        .any(|capability| capability == "receive"));
}

#[test]
fn platform_adapter_status_lists_send_only_hermes_platforms() {
    let dir = std::env::temp_dir().join(format!("synthchat-adapter-status-{}", new_id("test")));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    let status = platform_adapter_status(&store, None).unwrap();
    let supported = status["supportedAdapters"].as_array().unwrap();
    let hermes_platforms = status["hermesPlatforms"].as_array().unwrap();
    for platform in ["api_server", "feishu_comment", "msgraph_webhook", "wecom"] {
        assert!(hermes_platforms.iter().any(|value| value == platform));
    }
    assert!(supported.iter().any(|value| value == "feishu_comment"));
    let feishu_comment = status["adapters"]
        .as_array()
        .unwrap()
        .iter()
        .find(|adapter| adapter["platform"] == "feishu_comment")
        .unwrap();
    assert_eq!(
        feishu_comment["schema"],
        "hermes_feishu_comment_adapter_status_desktop_v1"
    );
    assert_eq!(feishu_comment["parentPlatform"], "feishu");
    assert_ne!(feishu_comment["status"], "unsupported");
    assert_eq!(feishu_comment["capabilityMatrix"]["commentTools"], true);

    let single = platform_adapter_status(&store, Some("feishu_comment")).unwrap();
    assert_eq!(
        single["schema"],
        "hermes_feishu_comment_adapter_status_desktop_v1"
    );
    assert_eq!(single["parent_platform"], "feishu");
    assert_ne!(single["status"], "unsupported");

    let webhook = platform_adapter_status(&store, Some("webhook")).unwrap();
    assert_eq!(
        webhook["schema"],
        "hermes_webhook_adapter_status_desktop_v1"
    );
    assert_eq!(webhook["capabilityMatrix"]["github_comment_delivery"], true);
    assert_eq!(
        webhook["githubCommentDelivery"]["hermesReference"],
        "gateway/platforms/webhook.py::_deliver_github_comment"
    );

    for platform in ["sms", "whatsapp", "qqbot", "homeassistant", "bluebubbles"] {
        assert!(supported.iter().any(|value| value == platform));
        let adapter = status["adapters"]
            .as_array()
            .unwrap()
            .iter()
            .find(|adapter| adapter["platform"] == platform)
            .unwrap();
        assert_eq!(adapter["mode"], "send_only");
        assert_eq!(adapter["runtimeAdapter"], false);
        assert_eq!(adapter["capabilityMatrix"]["send"], true);
        assert_eq!(adapter["capabilityMatrix"]["receive"], false);
    }

    let _ = fs::remove_dir_all(dir);
}

#[tokio::test]
async fn webhook_github_comment_delivery_returns_hermes_gh_plan() {
    let payload = json!({
        "delivery": {
            "deliver": "github_comment",
            "deliver_extra": {
                "repo": "nousresearch/hermes-agent",
                "pr_number": 42
            }
        },
        "content": "agent response"
    });
    let result = webhook_deliver_github_comment(&payload).await.unwrap();
    assert_eq!(
        result["schema"],
        "hermes_webhook_github_comment_delivery_desktop_v1"
    );
    assert_eq!(result["delivery"], "github_comment");
    assert_eq!(result["planned"], true);
    assert_eq!(result["executed"], false);
    assert_eq!(result["repo"], "nousresearch/hermes-agent");
    assert_eq!(result["pr_number"], "42");
    assert_eq!(
        result["args"],
        json!([
            "pr",
            "comment",
            "42",
            "--repo",
            "nousresearch/hermes-agent",
            "--body",
            "agent response"
        ])
    );
    assert_eq!(
        result["managed_process_start_payload"]["command"],
        "gh pr comment 42 --repo nousresearch/hermes-agent --body agent response"
    );

    let missing = webhook_deliver_github_comment(&json!({
        "delivery": {"deliver": "github_comment"},
        "content": "agent response"
    }))
    .await
    .unwrap_err();
    assert!(missing.to_string().contains("requires deliver_extra.repo"));
}

#[test]
fn platform_adapter_status_exposes_hermes_display_config_defaults() {
    let dir = std::env::temp_dir().join(format!(
        "synthchat-display-config-status-{}",
        new_id("test")
    ));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();

    let status = platform_adapter_status(&store, None).unwrap();
    assert_eq!(
        status["hermesDisplayConfig"]["schema"],
        "hermes_gateway_display_config_desktop_v1"
    );
    assert!(status["hermesDisplayConfig"]["overrideableKeys"]
        .as_array()
        .unwrap()
        .iter()
        .any(|key| key == "long_running_notifications"));

    let adapter = |platform: &str| {
        status["adapters"]
            .as_array()
            .unwrap()
            .iter()
            .find(|adapter| adapter["platform"] == platform)
            .unwrap()
            .clone()
    };
    let telegram = adapter("telegram");
    assert_eq!(
        telegram["displayConfig"]["schema"],
        "hermes_gateway_display_config_desktop_v1"
    );
    assert_eq!(telegram["displayConfig"]["tier"], "high");
    assert_eq!(
        telegram["displayConfig"]["effective"]["toolProgress"],
        "off"
    );
    assert_eq!(
        telegram["displayConfig"]["effective"]["busyAckDetail"],
        false
    );

    let slack = adapter("slack");
    assert_eq!(slack["displayConfig"]["tier"], "medium");
    assert_eq!(slack["displayConfig"]["effective"]["toolProgress"], "off");

    let email = adapter("email");
    assert_eq!(email["displayConfig"]["tier"], "minimal");
    assert_eq!(email["displayConfig"]["effective"]["streaming"], false);
    assert_eq!(
        email["displayConfig"]["effective"]["longRunningNotifications"],
        false
    );

    let api_server = platform_adapter_status(&store, Some("api_server")).unwrap();
    assert_eq!(api_server["displayConfig"]["tier"], "high");
    assert_eq!(
        api_server["displayConfig"]["effective"]["toolPreviewLength"],
        0
    );

    let _ = fs::remove_dir_all(dir);
}

