    assert_eq!(telegram["typingLifecycle"]["pauseDuringApproval"], true);
    assert_eq!(telegram["typingLifecycle"]["resumeAfterApproval"], true);
    assert_eq!(telegram["typingLifecycle"]["stopOnCompletion"], true);
    assert_eq!(telegram["typingLifecycle"]["interruptStopsTyping"], true);
