#[test]
fn matrix_encrypted_attachment_decrypts_with_hash_validation() {
    use aes::Aes256;
    use base64::{engine::general_purpose::URL_SAFE_NO_PAD, Engine as _};
    use ctr::cipher::{KeyIvInit, StreamCipher};
    use sha2::{Digest, Sha256};

    let key = [7u8; 32];
    let iv = [3u8; 16];
    let plaintext = b"matrix encrypted media payload";
    let mut ciphertext = plaintext.to_vec();
    type Aes256Ctr = ctr::Ctr128BE<Aes256>;
    let mut cipher = Aes256Ctr::new_from_slices(&key, &iv).unwrap();
    cipher.apply_keystream(&mut ciphertext);
    let file = json!({
        "key": {"k": URL_SAFE_NO_PAD.encode(key)},
        "iv": URL_SAFE_NO_PAD.encode(iv),
        "hashes": {"sha256": URL_SAFE_NO_PAD.encode(Sha256::digest(&ciphertext))},
    });

    let decrypted = matrix_decrypt_encrypted_attachment(&file, &ciphertext).unwrap();
    assert_eq!(decrypted, plaintext);

    let mut bad_file = file.clone();
    bad_file["hashes"]["sha256"] = json!(URL_SAFE_NO_PAD.encode([0u8; 32]));
    assert!(matrix_decrypt_encrypted_attachment(&bad_file, &ciphertext)
        .unwrap_err()
        .to_string()
        .contains("hash mismatch"));
}

