#[test]
fn api_server_reload_env_reads_hermes_env_into_process() {
    let _guard = CHANNEL_DIRECTORY_ENV_LOCK.lock().unwrap();
    let old_home = env::var_os("HERMES_HOME");
    let old_reload_key = env::var_os("SYNTHCHAT_RELOAD_ENV_TEST_KEY");
    let old_quoted_key = env::var_os("SYNTHCHAT_RELOAD_ENV_QUOTED");
    let dir = std::env::temp_dir().join(format!("synthchat-reload-env-{}", new_id("test")));
    fs::create_dir_all(&dir).unwrap();
    env::set_var("HERMES_HOME", &dir);
    fs::write(
        dir.join(".env"),
        "export SYNTHCHAT_RELOAD_ENV_TEST_KEY=one # comment\nSYNTHCHAT_RELOAD_ENV_QUOTED=\"two\\nlines\"\nINVALID-KEY=skip\n",
    )
    .unwrap();
    env::remove_var("SYNTHCHAT_RELOAD_ENV_TEST_KEY");
    env::remove_var("SYNTHCHAT_RELOAD_ENV_QUOTED");
    let parsed = api_server_parse_env_file(&dir.join(".env")).unwrap();
    assert_eq!(parsed["SYNTHCHAT_RELOAD_ENV_TEST_KEY"], "one");
    assert_eq!(parsed["SYNTHCHAT_RELOAD_ENV_QUOTED"], "two\nlines");
    assert!(!parsed.contains_key("INVALID-KEY"));

    let store = AppStore::new(dir.join("state.json")).unwrap();
    let settings = api_server_settings(&store.config().unwrap()).unwrap();
    let response = api_server_chat_tab_gateway_dispatch(
        &store,
        &settings,
        &json!({"jsonrpc": "2.0", "id": 743, "method": "reload.env", "params": {}}),
    );
    assert_eq!(response["result"]["status"], "reloaded");
    assert_eq!(response["result"]["loaded"], 2);
    assert_eq!(env::var("SYNTHCHAT_RELOAD_ENV_TEST_KEY").unwrap(), "one");
    assert_eq!(
        env::var("SYNTHCHAT_RELOAD_ENV_QUOTED").unwrap(),
        "two\nlines"
    );
    assert!(response["result"]["updatedKeys"]
        .as_array()
        .unwrap()
        .iter()
        .any(|key| key == "SYNTHCHAT_RELOAD_ENV_TEST_KEY"));

    restore_test_env("HERMES_HOME", old_home);
    restore_test_env("SYNTHCHAT_RELOAD_ENV_TEST_KEY", old_reload_key);
    restore_test_env("SYNTHCHAT_RELOAD_ENV_QUOTED", old_quoted_key);
    let _ = fs::remove_dir_all(dir);
}

