    assert_eq!(voice_tts_response["result"]["providerId"], "chat-tab-tts");
    assert_eq!(voice_tts_response["result"]["format"], "wav");
    assert_eq!(voice_tts_response["result"]["artifact"]["sizeBytes"], 4);
