#[tokio::test]
async fn api_server_exposes_kanban_recovery_routes() {
    let dir = std::env::temp_dir().join(format!(
        "synthchat-api-server-kanban-recovery-{}",
        new_id("test")
    ));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    let mut config = store.config().unwrap();
    config.messaging_gateway = json!({
        "apiServer": {
            "enabled": true,
            "key": "test-key",
            "modelName": "synthchat-test"
        }
    });
    store.set_config(config.clone()).unwrap();
    let settings = api_server_settings(&config).unwrap();
    let mut headers = HashMap::new();
    headers.insert("authorization".into(), "Bearer test-key".into());

    let capabilities = api_server_process_request(
        &store,
        &settings,
        ParsedWebhookRequest {
            method: "GET".into(),
            path: "/v1/capabilities".into(),
            headers: headers.clone(),
            body: String::new(),
        },
    )
    .await
    .unwrap();
    assert_eq!(
        capabilities["capabilityMatrix"]["kanbanRecoveryActions"],
        true
    );
    assert_eq!(
        capabilities["endpoints"]["kanban_task_reclaim"]["path"],
        "/api/plugins/kanban/tasks/{task_id}/reclaim"
    );
    assert_eq!(
        capabilities["endpoints"]["kanban_task_reassign"]["path"],
        "/api/plugins/kanban/tasks/{task_id}/reassign"
    );

    kanban_create_tool(
        &store,
        &json!({
            "taskId": "kb-api-reclaim",
            "title": "API reclaim stuck worker",
            "status": "ready",
            "assignee": "operator",
            "metadata": {"board": "alpha"}
        }),
    )
    .unwrap();
    let dispatch: Value = serde_json::from_str(
        &dashboard_plugins_tool(
            &store,
            &json!({"action": "kanban-dispatch", "dryRun": false, "maxSpawn": 1, "board": "alpha"}),
        )
        .unwrap(),
    )
    .unwrap();
    let reclaim_run_id = dispatch["spawnedTasks"][0]["run_id"].as_str().unwrap();

    let reclaimed = api_server_process_request(
        &store,
        &settings,
        ParsedWebhookRequest {
            method: "POST".into(),
            path: "/api/plugins/kanban/tasks/kb-api-reclaim/reclaim".into(),
            headers: headers.clone(),
            body: json!({"reason": "api recovery"}).to_string(),
        },
    )
    .await
    .unwrap();
    assert_eq!(reclaimed["object"], "kanban.recovery");
    assert_eq!(
        reclaimed["nativeApiServerRoute"],
        "/api/plugins/kanban/tasks/{task_id}/reclaim"
    );
    assert_eq!(reclaimed["action"], "kanban-reclaim");
    assert_eq!(reclaimed["ok"], true);
    assert_eq!(reclaimed["task_id"], "kb-api-reclaim");
    assert_eq!(reclaimed["task"]["status"], "ready");
    assert_eq!(store.agent_run(reclaim_run_id).unwrap().state, "aborted");

    kanban_create_tool(
        &store,
        &json!({
            "taskId": "kb-api-reassign",
            "title": "API reassign stuck worker",
            "status": "ready",
            "assignee": "operator",
            "metadata": {"board": "beta"}
        }),
    )
    .unwrap();
    let dispatch_reassign: Value = serde_json::from_str(
        &dashboard_plugins_tool(
            &store,
            &json!({"action": "kanban-dispatch", "dryRun": false, "maxSpawn": 1, "board": "beta"}),
        )
        .unwrap(),
    )
    .unwrap();
    assert_eq!(
        dispatch_reassign["spawnedTasks"][0]["task_id"],
        "kb-api-reassign"
    );

    let blocked = api_server_process_request(
        &store,
        &settings,
        ParsedWebhookRequest {
            method: "POST".into(),
            path: "/api/plugins/kanban/tasks/kb-api-reassign/reassign".into(),
            headers: headers.clone(),
            body: json!({"profile": "reviewer"}).to_string(),
        },
    )
    .await
    .unwrap();
    assert_eq!(blocked["object"], "kanban.recovery");
    assert_eq!(blocked["action"], "kanban-reassign");
    assert_eq!(blocked["status"], "conflict");
    assert_eq!(blocked["ok"], false);

    let reassigned = api_server_process_request(
        &store,
        &settings,
        ParsedWebhookRequest {
            method: "POST".into(),
            path: "/api/plugins/kanban/tasks/kb-api-reassign/reassign?reclaimFirst=true".into(),
            headers,
            body: json!({"profile": "reviewer", "reason": "api retry"}).to_string(),
        },
    )
    .await
    .unwrap();
    assert_eq!(reassigned["object"], "kanban.recovery");
    assert_eq!(
        reassigned["nativeApiServerRoute"],
        "/api/plugins/kanban/tasks/{task_id}/reassign"
    );
    assert_eq!(reassigned["action"], "kanban-reassign");
    assert_eq!(reassigned["ok"], true);
    assert_eq!(reassigned["assignee"], "reviewer");
    assert_eq!(reassigned["task"]["status"], "ready");

    let _ = fs::remove_dir_all(dir);
}

#[test]
fn api_server_chat_tab_clipboard_windows_scripts_match_hermes_backends() {
    let scripts = api_server_chat_tab_gateway_clipboard_powershell_extract_scripts();
    assert_eq!(scripts.len(), 3);
    assert!(scripts
        .iter()
        .any(|script| script.contains("System.Windows.Forms.Clipboard")
            && script.contains("ImageFormat]::Png")));
    assert!(scripts
        .iter()
        .any(|script| script.contains("Get-Clipboard") && script.contains("PngBitmapEncoder")));
    assert!(scripts.iter().any(|script| script.contains("FileDropList")
        && script.contains("FILE:")
        && script.contains(".webp")));

    let linux_backends = api_server_chat_tab_gateway_clipboard_linux_backends();
    assert_eq!(linux_backends.len(), 6);
    assert!(linux_backends
        .iter()
        .any(|(program, args, mime)| *program == "wl-paste"
            && args == &["--type", "image/png"]
            && *mime == "image/png"));
    assert!(linux_backends
        .iter()
        .any(|(program, args, mime)| *program == "wl-paste"
            && args == &["--type", "image/jpeg"]
            && *mime == "image/jpeg"));
    assert!(linux_backends
        .iter()
        .any(|(program, args, mime)| *program == "wl-paste"
            && args == &["--type", "image/bmp"]
            && *mime == "image/bmp"));
    assert!(linux_backends
        .iter()
        .any(|(program, args, mime)| *program == "wl-paste"
            && args == &["--type", "image/gif"]
            && *mime == "image/gif"));
    assert!(linux_backends
        .iter()
        .any(|(program, args, mime)| *program == "wl-paste"
            && args == &["--type", "image/webp"]
            && *mime == "image/webp"));
    assert!(linux_backends
        .iter()
        .any(|(program, args, mime)| *program == "xclip"
            && args == &["-selection", "clipboard", "-t", "image/png", "-o"]
            && *mime == "image/png"));
    let dir = std::env::temp_dir().join(format!("synthchat-clipboard-png-{}", new_id("test")));
    fs::create_dir_all(&dir).unwrap();
    let png = dir.join("clipboard.png");
    let jpeg = dir.join("clipboard.jpg");
    fs::write(&png, b"\x89PNG\r\n\x1a\nrest").unwrap();
    fs::write(&jpeg, b"\xff\xd8\xff\xe0not-png").unwrap();
    assert!(api_server_chat_tab_gateway_clipboard_is_png(&png));
    assert!(!api_server_chat_tab_gateway_clipboard_is_png(&jpeg));
    let renamed = dir.join("converted.jpg");
    fs::write(&renamed, b"\x89PNG\r\n\x1a\nconverted").unwrap();
    let renamed_png = api_server_chat_tab_gateway_clipboard_rename_png(&renamed)
        .unwrap()
        .unwrap();
    assert_eq!(
        renamed_png.extension().and_then(|value| value.to_str()),
        Some("png")
    );
    assert!(api_server_chat_tab_gateway_clipboard_is_png(&renamed_png));
    assert!(!renamed.exists());
    let _ = fs::remove_dir_all(&dir);

    let macos_backends = api_server_chat_tab_gateway_clipboard_macos_backends();
    assert_eq!(macos_backends, vec!["pngpaste", "osascript"]);
    let osascript =
        api_server_chat_tab_gateway_clipboard_macos_osascript(Path::new(r#"/tmp/clip"board.png"#));
    assert!(osascript.contains("«class PNGf»"));
    assert!(osascript.contains(r#"POSIX file "/tmp/clip\"board.png""#));
}

#[test]
fn api_server_chat_tab_gateway_event_aliases_match_hermes_message_events() {
    let start_aliases = api_server_chat_tab_gateway_event_aliases(
        "message.started",
        &json!({
            "session_id": "session-1",
            "run_id": "run-1",
            "message": {"id": "msg-1", "role": "assistant"},
            "seq": 1
        }),
    );
    assert_eq!(start_aliases[0].0, "message.start");
    assert_eq!(start_aliases[0].1["aliasOf"], "message.started");

    let delta_aliases = api_server_chat_tab_gateway_event_aliases(
        "assistant.delta",
        &json!({
            "session_id": "session-1",
            "run_id": "run-1",
            "message_id": "msg-1",
            "delta": "hello",
            "seq": 2
        }),
    );
    assert_eq!(delta_aliases[0].0, "message.delta");
    assert_eq!(delta_aliases[0].1["text"], "hello");

    let complete_aliases = api_server_chat_tab_gateway_event_aliases(
        "assistant.completed",
        &json!({
            "session_id": "session-1",
            "run_id": "run-1",
            "message_id": "msg-1",
            "content": "done",
            "completed": true,
            "partial": false,
            "interrupted": false,
            "seq": 3
        }),
    );
    assert_eq!(complete_aliases[0].0, "message.complete");
    assert_eq!(complete_aliases[0].1["text"], "done");
    assert_eq!(complete_aliases[0].1["status"], "complete");

    let tool_started_aliases = api_server_chat_tab_gateway_event_aliases(
        "tool.started",
        &json!({
            "run_id": "run-1",
            "data": {
                "progress": {
                    "tool": "terminal",
                    "status": "running",
                    "toolCallId": "tc-1",
                    "label": "pwd"
                }
            }
        }),
    );
    assert_eq!(tool_started_aliases[0].0, "tool.start");
    assert_eq!(tool_started_aliases[0].1["tool_id"], "tc-1");
    assert_eq!(tool_started_aliases[0].1["name"], "terminal");
    assert_eq!(tool_started_aliases[0].1["status"], "running");
    assert_eq!(tool_started_aliases[0].1["context"], "pwd");

    let tool_completed_aliases = api_server_chat_tab_gateway_event_aliases(
        "tool.completed",
        &json!({
            "run_id": "run-1",
            "data": {
                "progress": {
                    "tool": "terminal",
                    "status": "completed",
                    "toolCallId": "tc-1",
                    "label": "exitCode: 0"
                },
                "toolEvent": {
                    "result": {"stdout": "ok"}
                }
            }
        }),
    );
    assert_eq!(tool_completed_aliases[0].0, "tool.complete");
    assert_eq!(tool_completed_aliases[0].1["tool_id"], "tc-1");
    assert_eq!(tool_completed_aliases[0].1["result"]["stdout"], "ok");

    let tool_failed_aliases = api_server_chat_tab_gateway_event_aliases(
        "tool.failed",
        &json!({
            "run_id": "run-1",
            "data": {
                "toolEvent": {
                    "toolName": "terminal",
                    "status": "failed",
                    "callId": "tc-2",
                    "summary": "command failed",
                    "error": "exitCode: 1"
                }
            }
        }),
    );
    assert_eq!(tool_failed_aliases[0].0, "tool.complete");
    assert_eq!(tool_failed_aliases[0].1["tool_id"], "tc-2");
    assert_eq!(tool_failed_aliases[0].1["name"], "terminal");
    assert_eq!(tool_failed_aliases[0].1["status"], "failed");
    assert_eq!(tool_failed_aliases[0].1["error"], "exitCode: 1");

    let status_aliases = api_server_chat_tab_gateway_event_aliases(
        "run.started",
        &json!({
            "session_id": "session-1",
            "run_id": "run-1"
        }),
    );
    assert_eq!(status_aliases[0].0, "status.update");
    assert_eq!(status_aliases[0].1["kind"], "run");
    assert_eq!(status_aliases[0].1["status"], "started");
    assert_eq!(status_aliases[0].1["run_id"], "run-1");

    let reasoning_aliases = api_server_chat_tab_gateway_event_aliases(
        "reasoning.delta",
        &json!({
            "delta": "thinking through the task"
        }),
    );
    assert_eq!(reasoning_aliases[0].0, "reasoning.delta");
    assert_eq!(reasoning_aliases[0].1["text"], "thinking through the task");
    let thinking_aliases = api_server_chat_tab_gateway_event_aliases(
        "thinking.delta",
        &json!({
            "preview": "planning"
        }),
    );
    assert_eq!(thinking_aliases[0].0, "thinking.delta");
    assert_eq!(thinking_aliases[0].1["text"], "planning");

    let subagent_aliases = api_server_chat_tab_gateway_event_aliases(
        "subagent.complete",
        &json!({
            "data": {
                "subagentId": "sub-1",
                "parentId": "run-1",
                "task": "inspect files",
                "taskCount": 3,
                "taskIndex": 2,
                "depth": 1,
                "model": "worker-model",
                "summary": "finished"
            }
        }),
    );
    assert_eq!(subagent_aliases[0].0, "subagent.complete");
    assert_eq!(subagent_aliases[0].1["subagent_id"], "sub-1");
    assert_eq!(subagent_aliases[0].1["parent_id"], "run-1");
    assert_eq!(subagent_aliases[0].1["goal"], "inspect files");
    assert_eq!(subagent_aliases[0].1["task_count"], 3);
    assert_eq!(subagent_aliases[0].1["task_index"], 2);
    assert_eq!(subagent_aliases[0].1["summary"], "finished");
}

#[tokio::test]
async fn api_server_exposes_kanban_run_terminate_route() {
    let dir = std::env::temp_dir().join(format!(
        "synthchat-api-server-kanban-terminate-{}",
        new_id("test")
    ));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    let mut config = store.config().unwrap();
    config.messaging_gateway = json!({
        "apiServer": {
            "enabled": true,
            "key": "test-key",
            "modelName": "synthchat-test"
        }
    });
    store.set_config(config.clone()).unwrap();
    let settings = api_server_settings(&config).unwrap();
    let mut headers = HashMap::new();
    headers.insert("authorization".into(), "Bearer test-key".into());

    let capabilities = api_server_process_request(
        &store,
        &settings,
        ParsedWebhookRequest {
            method: "GET".into(),
            path: "/v1/capabilities".into(),
            headers: headers.clone(),
            body: String::new(),
        },
    )
    .await
    .unwrap();
    assert_eq!(capabilities["capabilityMatrix"]["kanbanRunTerminate"], true);
    assert_eq!(
        capabilities["endpoints"]["kanban_run_terminate"]["path"],
        "/api/plugins/kanban/runs/{run_id}/terminate"
    );

    kanban_create_tool(
        &store,
        &json!({
            "taskId": "kb-api-terminate",
            "title": "API terminate running worker",
            "status": "ready",
            "assignee": "operator",
            "metadata": {"board": "terminate"}
        }),
    )
    .unwrap();
    let dispatch: Value = serde_json::from_str(
        &dashboard_plugins_tool(
            &store,
            &json!({
                "action": "kanban-dispatch",
                "dryRun": false,
                "maxSpawn": 1,
                "board": "terminate"
            }),
        )
        .unwrap(),
    )
    .unwrap();
    assert_eq!(dispatch["spawned"], 1);
    let run_id = dispatch["spawnedTasks"][0]["run_id"].as_str().unwrap();

    let terminated = api_server_process_request(
        &store,
        &settings,
        ParsedWebhookRequest {
            method: "POST".into(),
            path: format!("/api/plugins/kanban/runs/{run_id}/terminate"),
            headers,
            body: json!({"reason": "api operator stop"}).to_string(),
        },
    )
    .await
    .unwrap();
    assert_eq!(terminated["object"], "kanban.run_termination");
    assert_eq!(
        terminated["nativeApiServerRoute"],
        "/api/plugins/kanban/runs/{run_id}/terminate"
    );
    assert_eq!(terminated["action"], "kanban-run-terminate");
    assert_eq!(terminated["ok"], true);
    assert_eq!(terminated["run_id"], run_id);
    assert_eq!(terminated["stopped"]["count"], 1);

    let workers: Value = serde_json::from_str(
        &dashboard_plugins_tool(&store, &json!({"action": "kanban-workers-active"})).unwrap(),
    )
    .unwrap();
    assert_eq!(workers["count"], 0);

    let _ = fs::remove_dir_all(dir);
}

