#[tokio::test]
async fn api_server_exposes_kanban_events_and_task_log_routes() {
    let dir = std::env::temp_dir().join(format!(
        "synthchat-api-server-kanban-events-{}",
        new_id("test")
    ));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    let mut config = store.config().unwrap();
    config.messaging_gateway = json!({
        "apiServer": {
            "enabled": true,
            "key": "test-key",
            "modelName": "synthchat-test"
        }
    });
    store.set_config(config.clone()).unwrap();
    let settings = api_server_settings(&config).unwrap();
    let mut headers = HashMap::new();
    headers.insert("authorization".into(), "Bearer test-key".into());

    kanban_create_tool(
        &store,
        &json!({
            "taskId": "kb-api-events",
            "title": "API event stream",
            "assignee": "operator",
            "metadata": {"board": "alpha"}
        }),
    )
    .unwrap();
    kanban_comment_tool(
        &store,
        &json!({"taskId": "kb-api-events", "body": "first update", "author": "tester"}),
    )
    .unwrap();
    kanban_update_tool(
        &store,
        &json!({"taskId": "kb-api-events", "status": "review", "metadata": {"board": "alpha"}}),
    )
    .unwrap();

    let capabilities = api_server_process_request(
        &store,
        &settings,
        ParsedWebhookRequest {
            method: "GET".into(),
            path: "/v1/capabilities".into(),
            headers: headers.clone(),
            body: String::new(),
        },
    )
    .await
    .unwrap();
    assert_eq!(
        capabilities["capabilityMatrix"]["kanbanEventHttpRoutes"],
        true
    );
    assert_eq!(
        capabilities["endpoints"]["kanban_events"]["path"],
        "/api/plugins/kanban/events"
    );
    assert_eq!(
        capabilities["endpoints"]["kanban_task_log"]["path"],
        "/api/plugins/kanban/tasks/{task_id}/log"
    );

    let events = api_server_process_request(
        &store,
        &settings,
        ParsedWebhookRequest {
            method: "GET".into(),
            path: "/api/plugins/kanban/events?since=0&board=alpha".into(),
            headers: headers.clone(),
            body: String::new(),
        },
    )
    .await
    .unwrap();
    assert_eq!(events["nativeApiServerRoute"], "/api/plugins/kanban/events");
    assert_eq!(events["action"], "kanban-events");
    assert_eq!(events["websocketEmbedded"], false);
    assert!(events["events"]
        .as_array()
        .unwrap()
        .iter()
        .any(|event| event["task_id"] == "kb-api-events" && event["kind"] == "commented"));
    let cursor = events["cursor"].as_u64().unwrap();

    let checkpoint = api_server_process_request(
        &store,
        &settings,
        ParsedWebhookRequest {
            method: "GET".into(),
            path: format!("/api/plugins/kanban/events/checkpoint?since={cursor}&board=alpha"),
            headers: headers.clone(),
            body: String::new(),
        },
    )
    .await
    .unwrap();
    assert_eq!(
        checkpoint["nativeApiServerRoute"],
        "/api/plugins/kanban/events/checkpoint"
    );
    assert_eq!(checkpoint["action"], "kanban-events-checkpoint");
    assert_eq!(checkpoint["count"], 0);

    store
        .register_managed_process(ManagedProcess {
            id: "proc-api-events".into(),
            label: "operator".into(),
            command: "hermes kanban worker kb-api-events".into(),
            cwd: Some(dir.to_string_lossy().to_string()),
            pid: Some(4343),
            backend: "kanban".into(),
            env_type: "desktop".into(),
            status_command: None,
            kill_command: None,
            stdout_command: None,
            stderr_command: None,
            exit_command: None,
            cleanup_command: None,
            exit_code: None,
            task_id: Some("kb-api-events".into()),
            conversation_id: "conv-api-events".into(),
            run_id: "run-api-events".into(),
            detached: true,
            pid_scope: "sandbox".into(),
            started_at: now_iso(),
            finished_at: None,
            finished_at_instant: None,
            notify_on_complete: false,
            watch_patterns: Vec::new(),
            tail_retention_lines: 200,
            notifications: std::sync::Arc::new(Mutex::new(
                ManagedProcessNotificationState::default(),
            )),
            stdout: std::sync::Arc::new(Mutex::new(vec![
                "worker claimed kb-api-events".into(),
                "worker wrote progress".into(),
            ])),
            stderr: std::sync::Arc::new(Mutex::new(Vec::new())),
            stdin: std::sync::Arc::new(tokio::sync::Mutex::new(None)),
            child: None,
        })
        .unwrap();

    let log = api_server_process_request(
        &store,
        &settings,
        ParsedWebhookRequest {
            method: "GET".into(),
            path: "/api/plugins/kanban/tasks/kb-api-events/log?limit=10".into(),
            headers,
            body: String::new(),
        },
    )
    .await
    .unwrap();
    assert_eq!(
        log["nativeApiServerRoute"],
        "/api/plugins/kanban/tasks/{task_id}/log"
    );
    assert_eq!(log["action"], "kanban-task-log");
    assert_eq!(log["status"], "ok");
    assert!(log["content"]
        .as_str()
        .unwrap()
        .contains("worker wrote progress"));

    let _ = fs::remove_dir_all(dir);
}

