#[tokio::test]
async fn platform_control_status_persists_hermes_pid_and_runtime_lock() {
    let dir = std::env::temp_dir().join(format!("synthchat-platform-pid-{}", new_id("test")));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();

    let response = handle_platforms_control_command(&store, "status", None)
        .await
        .unwrap();
    assert!(response.contains("Gateway runtime"));
    assert!(response.contains("lockActive=true"));

    let pid_path = dir.join("platforms").join("gateway.pid");
    let lock_path = dir.join("platforms").join("gateway.lock");
    let status_path = dir.join("platforms").join("gateway_state.json");
    let pid_record: Value = serde_json::from_str(&fs::read_to_string(pid_path).unwrap()).unwrap();
    let lock_record: Value = serde_json::from_str(&fs::read_to_string(lock_path).unwrap()).unwrap();
    let status: Value = serde_json::from_str(&fs::read_to_string(status_path).unwrap()).unwrap();
    let hermes_pid_path = PathBuf::from(status["hermesPidFile"].as_str().unwrap());
    let hermes_lock_path = PathBuf::from(status["hermesRuntimeLockFile"].as_str().unwrap());
    let hermes_status_path = PathBuf::from(status["hermesRuntimeStatusFile"].as_str().unwrap());
    let hermes_pid_record: Value =
        serde_json::from_str(&fs::read_to_string(hermes_pid_path).unwrap()).unwrap();
    let hermes_lock_record: Value =
        serde_json::from_str(&fs::read_to_string(hermes_lock_path).unwrap()).unwrap();
    let hermes_status: Value =
        serde_json::from_str(&fs::read_to_string(hermes_status_path).unwrap()).unwrap();
    assert_eq!(pid_record["kind"], "hermes-gateway");
    assert_eq!(pid_record["pid"], std::process::id());
    assert_eq!(lock_record["kind"], "hermes-gateway-runtime-lock");
    assert_eq!(lock_record["active"], true);
    assert_eq!(status["runtimeLockActive"], true);
    assert_eq!(
        status["daemonLifecycle"]["schema"],
        "hermes_gateway_daemon_lifecycle_desktop_v1"
    );
    assert_eq!(status["daemonLifecycle"]["pidFileMirroring"], true);
    assert_eq!(status["daemonLifecycle"]["runtimeLockMirroring"], true);
    assert_eq!(status["daemonLifecycle"]["restartIntentRecords"], true);
    assert_eq!(status["daemonLifecycle"]["plannedStopMarkers"], true);
    assert_eq!(status["daemonLifecycle"]["takeoverMarkers"], true);
    assert_eq!(
        status["daemonLifecycle"]["pythonGatewayDaemonEmbedded"],
        false
    );
    assert_eq!(status["daemonLifecycle"]["managedProcessPlanReady"], true);
    assert_eq!(
        status["daemonLifecycle"]["managedProcessPlan"]["schema"],
        "hermes_gateway_daemon_managed_process_plan_desktop_v1"
    );
    assert_eq!(
        status["daemonLifecycle"]["managedProcessPlan"]["managedProcessStartPayload"]["taskId"],
        "hermes-gateway-daemon"
    );
    assert_eq!(
        status["daemonLifecycle"]["managedProcessPlan"]["managedProcessReplacePayload"]["command"],
        "hermes gateway run --replace"
    );
    assert_eq!(status["daemonLifecycle"]["osServiceManagerApplied"], false);
    assert_eq!(
        status["daemon_lifecycle"]["external_supervisor_required_for_python_daemon"],
        true
    );
    assert_eq!(
        status["daemon_lifecycle"]["managed_process_plan"]["managed_process_stop_payload"]
            ["task_id"],
        "hermes-gateway-daemon"
    );
    assert_eq!(status["pidRecord"]["pid"], std::process::id());
    assert_eq!(status["mirroredToHermesHome"], true);
    assert_eq!(hermes_pid_record["pid"], std::process::id());
    assert_eq!(hermes_lock_record["kind"], "hermes-gateway-runtime-lock");
    assert_eq!(
        hermes_status["schema"],
        "hermes_gateway_runtime_status_desktop_v1"
    );

    let _ = fs::remove_dir_all(dir);
}

