#[test]
fn messaging_gateway_slash_access_blocks_unlisted_registered_commands() {
    let dir =
        std::env::temp_dir().join(format!("synthchat-gateway-slash-access-{}", new_id("test")));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    let config = json!({
        "enabled": true,
        "platforms": ["wecom"],
        "allowedUsers": ["alice", "owner"],
        "allowedChats": ["room-1"],
        "platformConfigs": {
            "wecom": {
                "allow_admin_from": ["owner"],
                "user_allowed_commands": ["status"]
            }
        }
    });
    let settings = messaging_gateway_receive_settings(&config).unwrap();
    let inbound = messaging_gateway_inbound_event_from_payload(
        &json!({
            "platform": "wecom",
            "message": {
                "chatId": "room-1",
                "userId": "alice",
                "chatType": "dm",
                "text": "/queue"
            }
        }),
        &config,
        &settings,
    )
    .unwrap();

    let denied = messaging_gateway_slash_access_denial(&store, &config, &inbound)
        .unwrap()
        .unwrap();
    assert_eq!(denied["type"], "slash_access_denied");
    assert_eq!(denied["command"], "queue");
    assert_eq!(denied["policy"]["enabled"], true);

    let allowed_inbound = messaging_gateway_inbound_event_from_payload(
        &json!({
            "platform": "wecom",
            "message": {
                "chatId": "room-1",
                "userId": "alice",
                "chatType": "dm",
                "text": "/status"
            }
        }),
        &config,
        &settings,
    )
    .unwrap();
    assert!(
        messaging_gateway_slash_access_denial(&store, &config, &allowed_inbound)
            .unwrap()
            .is_none()
    );

    let admin_inbound = messaging_gateway_inbound_event_from_payload(
        &json!({
            "platform": "wecom",
            "message": {
                "chatId": "room-1",
                "userId": "owner",
                "chatType": "dm",
                "text": "/queue"
            }
        }),
        &config,
        &settings,
    )
    .unwrap();
    assert!(
        messaging_gateway_slash_access_denial(&store, &config, &admin_inbound)
            .unwrap()
            .is_none()
    );

    let _ = fs::remove_dir_all(dir);
}

