    assert_eq!(status["configured"], true);
    assert_eq!(status["capabilityMatrix"]["receive"], true);
    assert_eq!(status["capabilityMatrix"]["gatewayJsonReceive"], true);
    assert_eq!(status["capabilityMatrix"]["nativeSocketReceive"], true);
    assert_eq!(status["nativeSocketReceive"], true);

