#[test]
fn feishu_webhook_signature_matches_hermes_sha256_rule() {
    let body = r#"{"schema":"2.0","header":{"event_type":"im.message.receive_v1"}}"#;
    let signature = feishu_webhook_signature("1710000000", "nonce-1", "encrypt-key-for-test", body);
    assert_eq!(
        signature,
        "322ad0b7443693aaa3b1d03e109f6f41e3616a084ea7f519d9442340b3c3a02e"
    );
    assert_ne!(
        signature,
        feishu_webhook_signature("1710000000", "nonce-2", "encrypt-key-for-test", body)
    );
}

#[test]
fn feishu_webhook_signature_validation_uses_raw_request_body() {
    let body = r#"{"schema":"2.0","header":{"event_type":"im.message.receive_v1"}}"#;
    let settings = FeishuWebhookSettings {
        host: "127.0.0.1".into(),
        port: 9001,
        path: "/feishu/webhook".into(),
        verification_token: None,
        encrypt_key: Some("encrypt-key-for-test".into()),
        require_mention: true,
        bot_open_id: None,
        bot_user_id: None,
        bot_name: None,
    };
    let signature = feishu_webhook_signature("1710000000", "nonce-1", "encrypt-key-for-test", body);
    let mut headers = HashMap::new();
    headers.insert("x-lark-request-timestamp".into(), "1710000000".into());
    headers.insert("x-lark-request-nonce".into(), "nonce-1".into());
    headers.insert("x-lark-signature".into(), signature);
    let request = ParsedWebhookRequest {
        method: "POST".into(),
        path: "/feishu/webhook".into(),
        headers: headers.clone(),
        body: body.into(),
    };
    feishu_verify_webhook_signature(&settings, &request).unwrap();

    let mut bad_request = request.clone();
    bad_request
        .headers
        .insert("x-lark-signature".into(), "bad".into());
    assert!(feishu_verify_webhook_signature(&settings, &bad_request).is_err());

    let missing_request = ParsedWebhookRequest {
        method: "POST".into(),
        path: "/feishu/webhook".into(),
        headers: HashMap::new(),
        body: body.into(),
    };
    assert!(feishu_verify_webhook_signature(&settings, &missing_request).is_err());
}

