#[test]
fn feishu_comment_rules_allowlist_and_pairing_gate_comment_events() {
    let dir = std::env::temp_dir().join(format!("synthchat-feishu-rules-{}", new_id("test")));
    fs::create_dir_all(dir.join(".hermes")).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    let settings = FeishuWebhookSettings {
        host: "127.0.0.1".into(),
        port: 9001,
        path: "/feishu/webhook".into(),
        verification_token: None,
        encrypt_key: None,
        bot_open_id: Some("ou_bot".into()),
        bot_user_id: None,
        bot_name: Some("Synth".into()),
        require_mention: true,
    };
    let payload = json!({
        "schema": "2.0",
        "header": {
            "event_id": "evt-comment-rules",
            "event_type": "drive.notice.comment_add_v1"
        },
        "event": {
            "event_id": "evt-comment-rules",
            "comment_id": "comment-1",
            "reply_id": "reply-1",
            "is_mentioned": true,
            "notice_meta": {
                "file_token": "doccn123",
                "file_type": "docx",
                "notice_type": "add_reply",
                "from_user_id": {"open_id": "ou_alice"},
                "to_user_id": {"open_id": "ou_bot"}
            }
        }
    });
    let base_config = json!({
        "allowedUsers": ["ou_alice"],
        "allowedChats": ["comment-doc:docx:doccn123"],
    });
    let inbound = feishu_inbound_event_from_payload(&payload, &base_config, &settings).unwrap();

    let inline_allow = json!({
        "allowedUsers": ["ou_alice"],
        "allowedChats": ["comment-doc:docx:doccn123"],
        "commentRules": {
            "enabled": true,
            "policy": "allowlist",
            "allow_from": ["ou_alice"]
        }
    });
    assert!(
        feishu_comment_access_denial(&store, &inline_allow, &inbound)
            .unwrap()
            .is_none()
    );

    fs::write(
        feishu_comment_rules_path(&store),
        serde_json::to_vec_pretty(&json!({
            "enabled": true,
            "policy": "allowlist",
            "allow_from": [],
            "documents": {
                "docx:doccn123": {"enabled": true, "policy": "pairing"},
                "*": {"enabled": false}
            }
        }))
        .unwrap(),
    )
    .unwrap();
    let denial = feishu_comment_access_denial(&store, &base_config, &inbound)
        .unwrap()
        .unwrap();
    assert_eq!(denial["allowed"], false);
    assert_eq!(denial["policy"], "pairing");
    assert_eq!(denial["match_source"], "exact:docx:doccn123");

    fs::write(
        feishu_comment_pairing_path(&store),
        serde_json::to_vec_pretty(&json!({
            "approved": {
                "ou_alice": {"approved_at": 1234}
            }
        }))
        .unwrap(),
    )
    .unwrap();
    assert!(feishu_comment_access_denial(&store, &base_config, &inbound)
        .unwrap()
        .is_none());

    let _ = fs::remove_dir_all(dir);
}

