#[tokio::test]
async fn security_guidance_native_transform_warns_on_dangerous_writes() {
    std::env::remove_var("SECURITY_GUIDANCE_DISABLE");
    std::env::remove_var("SECURITY_GUIDANCE_BLOCK");
    let dir = std::env::temp_dir().join(format!("synthchat-security-guidance-{}", new_id("test")));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();

    let warned = run_transform_tool_result_hooks(
        &store,
        "run-security-guidance-test",
        "write_file",
        &json!({
            "path": "src/app.py",
            "content": "import yaml\nvalue = yaml.load(user_input)\n"
        }),
        r#"{"ok":true,"path":"src/app.py"}"#,
        true,
        None,
    )
    .await;
    assert!(warned.contains("Security guidance"));
    assert!(warned.contains("python_yaml_load"));
    assert!(warned.contains("yaml.safe_load"));

    let simple_error = run_transform_tool_result_hooks(
        &store,
        "run-security-guidance-test",
        "write_file",
        &json!({"path": "src/app.py", "content": "eval(user_input)"}),
        r#"{"error":"write failed"}"#,
        true,
        None,
    )
    .await;
    assert!(!simple_error.contains("Security guidance"));

    std::env::set_var("SECURITY_GUIDANCE_DISABLE", "1");
    let disabled = run_transform_tool_result_hooks(
        &store,
        "run-security-guidance-test",
        "write_file",
        &json!({"path": "src/app.py", "content": "eval(user_input)"}),
        r#"{"ok":true}"#,
        true,
        None,
    )
    .await;
    assert!(!disabled.contains("Security guidance"));
    std::env::remove_var("SECURITY_GUIDANCE_DISABLE");

    let _ = fs::remove_dir_all(dir);
}

