#[test]
fn clarify_tool_result_pauses_agent_run_for_user_response() {
    let dir = std::env::temp_dir().join(format!("synthchat-clarify-pause-{}", new_id("test")));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    let persona = store.persona(None).unwrap();
    let conversation = store
        .create_conversation(Some("Clarify Test".into()), Some(persona.id.clone()))
        .unwrap();
    let mut run = AgentRunRecord::new(conversation.id.clone(), persona.id, conversation.agent_id);
    run.state = "running".into();
    run = store.save_agent_run(run).unwrap();
    let mut event = tool_started_event(
        &run.run_id,
        "__internal",
        "clarify",
        &json!({"question": "Which branch?", "__agentProviderToolCall": {"id": "call-clarify-1"}}),
    );
    event.call_id = Some("call-clarify-1".into());
    let tool_text = clarify_tool(&json!({
        "question": "Which branch?",
        "choices": ["main", "dev"]
    }))
    .unwrap();

    let assistant = pause_run_for_clarify_tool(
        &store,
        None,
        &mut run,
        &conversation.id,
        WorkflowMode::ChatTurn,
        &tool_text,
        &event,
    )
    .unwrap()
    .unwrap();

    assert!(assistant
        .content
        .contains("Clarification required: Which branch?"));
    let saved = store.agent_run(&run.run_id).unwrap();
    assert_eq!(saved.state, "needsClarification");
    assert_eq!(saved.checkpoints[0].state, "needs_clarification");
    assert_eq!(
        saved.checkpoints[0].completed_call_ids,
        vec!["call-clarify-1"]
    );
    let graph = saved.workflow_graph.as_ref().unwrap();
    assert_eq!(graph["currentNode"], "checkpoint");
    let checkpoint = graph["nodes"]
        .as_array()
        .unwrap()
        .iter()
        .find(|node| node["node"] == "checkpoint")
        .unwrap();
    assert_eq!(checkpoint["status"], "waiting");
    assert_eq!(checkpoint["detail"]["mode"], "chat_turn");
    assert_eq!(checkpoint["detail"]["kind"], "clarify_pause");
    assert_eq!(checkpoint["detail"]["checkpointScope"], "user_input");
    assert_eq!(checkpoint["detail"]["humanGate"]["kind"], "clarification");
    assert_eq!(checkpoint["detail"]["humanGate"]["status"], "waiting");
    assert_eq!(
        checkpoint["detail"]["humanGate"]["runId"].as_str(),
        Some(saved.run_id.as_str())
    );
    assert_eq!(
        checkpoint["detail"]["humanGate"]["checkpointId"].as_str(),
        Some(saved.checkpoints[0].checkpoint_id.as_str())
    );
    let transition = graph["transitions"]
        .as_array()
        .unwrap()
        .iter()
        .find(|transition| transition["reason"] == WORKFLOW_REASON_CLARIFY_REQUIRES_USER_INPUT)
        .unwrap();
    assert_eq!(transition["from"], "executor");
    assert_eq!(transition["to"], "checkpoint");
    assert_eq!(
        transition["detail"]["checkpointId"].as_str(),
        Some(saved.checkpoints[0].checkpoint_id.as_str())
    );
    assert_eq!(transition["detail"]["humanGate"]["kind"], "clarification");
    let _ = fs::remove_dir_all(dir);
}

