#[test]
fn cronjob_schedule_parser_supports_once_cron_and_rejects_bad_duration() {
    let mut job = ScheduledAgentJob::default();
    apply_cron_schedule_input(&mut job, "30m").unwrap();
    assert_eq!(job.schedule_kind, "once");
    assert!(job.run_at.is_some());

    apply_cron_schedule_input(&mut job, "0 9 * * 1-5").unwrap();
    assert_eq!(job.schedule_kind, "cron");
    assert_eq!(job.cron_expr.as_deref(), Some("0 9 * * 1-5"));

    let timestamp = (Utc::now() + ChronoDuration::minutes(15)).to_rfc3339();
    apply_cron_schedule_input(&mut job, &timestamp).unwrap();
    assert_eq!(job.schedule_kind, "once");
    assert!(job.run_at.as_deref().unwrap().contains('T'));

    let error = parse_duration_minutes("soon").unwrap_err();
    assert!(format!("{error}").contains("invalid schedule duration"));
}

#[test]
fn cronjob_tool_exposes_hermes_style_alias_fields_and_status() {
    let dir = std::env::temp_dir().join(format!("synthchat-cronjob-alias-{}", new_id("test")));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    let persona = store.persona(None).unwrap();
    let conversation = store
        .create_conversation(Some("Cron Alias Test".into()), Some(persona.id))
        .unwrap();

    let created = cronjob_tool(
        &store,
        &conversation.id,
        &json!({
            "action": "create",
            "name": "daily-report",
            "prompt": "Summarize project status.",
            "schedule": "every 2h",
            "skills": ["status/reporter"]
        }),
    )
    .unwrap();
    let created: Value = serde_json::from_str(&created).unwrap();
    assert_eq!(created["success"], true);
    assert_eq!(created["job_id"], created["jobId"]);
    assert_eq!(created["schedule"], "every 2h");
    assert_eq!(created["skills"][0], "status/reporter");
    assert!(created["next_run_at"].as_str().unwrap().contains('T'));

    let status = cronjob_tool(&store, &conversation.id, &json!({"action": "status"})).unwrap();
    let status: Value = serde_json::from_str(&status).unwrap();
    assert_eq!(status["success"], true);
    assert_eq!(status["action"], "status");
    assert_eq!(status["active_count"], 1);
    assert_eq!(status["next_run_at"], created["next_run_at"]);

    let paused = cronjob_tool(
        &store,
        &conversation.id,
        &json!({"action": "pause", "jobId": created["job_id"]}),
    )
    .unwrap();
    let paused: Value = serde_json::from_str(&paused).unwrap();
    assert_eq!(paused["success"], true);
    assert_eq!(paused["job_id"], created["job_id"]);

    let resumed = cronjob_tool(
        &store,
        &conversation.id,
        &json!({"action": "resume", "job_id": created["job_id"]}),
    )
    .unwrap();
    let resumed: Value = serde_json::from_str(&resumed).unwrap();
    assert_eq!(resumed["success"], true);
    assert_eq!(resumed["jobId"], created["job_id"]);

    let _ = fs::remove_dir_all(dir);
}

