#[tokio::test]
async fn api_server_exposes_dashboard_plugin_management_routes() {
    let dir = std::env::temp_dir().join(format!(
        "synthchat-dashboard-plugin-management-{}",
        new_id("test")
    ));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    let settings = api_server_settings(&store.config().unwrap()).unwrap();

    let hub = api_server_process_request(
        &store,
        &settings,
        ParsedWebhookRequest {
            method: "GET".into(),
            path: "/api/dashboard/plugins/hub".into(),
            headers: HashMap::new(),
            body: String::new(),
        },
    )
    .await
    .unwrap();
    assert_eq!(hub["schema"], "hermes_dashboard_plugins_hub_desktop_v1");
    assert_eq!(hub["management"]["visibility"], true);
    assert_eq!(hub["management"]["providerSelection"], true);
    assert!(hub["agentPlugins"]
        .as_array()
        .unwrap()
        .iter()
        .any(|plugin| plugin["name"] == "kanban"));

    let providers = api_server_process_request(
        &store,
        &settings,
        ParsedWebhookRequest {
            method: "PUT".into(),
            path: "/api/dashboard/plugin-providers".into(),
            headers: HashMap::new(),
            body: json!({
                "memory_provider": "holographic",
                "context_engine": "compressor"
            })
            .to_string(),
        },
    )
    .await
    .unwrap();
    assert_eq!(
        providers["schema"],
        "hermes_dashboard_plugin_providers_desktop_v1"
    );
    assert_eq!(providers["providers"]["memory_provider"], "holographic");
    assert_eq!(providers["providers"]["context_engine"], "compressor");

    let hidden = api_server_process_request(
        &store,
        &settings,
        ParsedWebhookRequest {
            method: "POST".into(),
            path: "/api/dashboard/plugins/kanban/visibility".into(),
            headers: HashMap::new(),
            body: json!({"hidden": true}).to_string(),
        },
    )
    .await
    .unwrap();
    assert_eq!(
        hidden["schema"],
        "hermes_dashboard_plugin_visibility_desktop_v1"
    );
    assert_eq!(hidden["name"], "kanban");
    assert_eq!(hidden["hidden"], true);

    let manifest = api_server_process_request(
        &store,
        &settings,
        ParsedWebhookRequest {
            method: "GET".into(),
            path: "/api/dashboard/plugins".into(),
            headers: HashMap::new(),
            body: String::new(),
        },
    )
    .await
    .unwrap();
    assert!(manifest["hiddenPlugins"]
        .as_array()
        .unwrap()
        .iter()
        .any(|value| value == "kanban"));
    assert!(!manifest["plugins"]
        .as_array()
        .unwrap()
        .iter()
        .any(|plugin| plugin["name"] == "kanban"));

    let disabled = api_server_process_request(
        &store,
        &settings,
        ParsedWebhookRequest {
            method: "POST".into(),
            path: "/api/dashboard/agent-plugins/kanban/disable".into(),
            headers: HashMap::new(),
            body: String::new(),
        },
    )
    .await
    .unwrap();
    assert_eq!(
        disabled["schema"],
        "hermes_dashboard_agent_plugin_state_desktop_v1"
    );
    assert_eq!(disabled["enabled"], false);
    assert_eq!(
        store.config().unwrap().messaging_gateway["dashboardPlugins"]["agentPlugins"]["kanban"]
            ["enabled"],
        false
    );

    let install = api_server_process_request(
        &store,
        &settings,
        ParsedWebhookRequest {
            method: "POST".into(),
            path: "/api/dashboard/agent-plugins/install".into(),
            headers: HashMap::new(),
            body: json!({"identifier": "github:user/plugin", "force": true}).to_string(),
        },
    )
    .await
    .unwrap();
    assert_eq!(
        install["schema"],
        "hermes_dashboard_agent_plugin_install_desktop_v1"
    );
    assert_eq!(install["ok"], true);
    assert_eq!(install["status"], "external_cli_plan");
    assert_eq!(
        install["installCommand"],
        "hermes plugins install github:user/plugin --force --enable"
    );
    assert_eq!(install["requiresExternalHermesCli"], true);
    assert_eq!(install["confirmationRequired"], true);
    assert_eq!(
        install["managedProcessStartPayload"]["metadata"]["hermesCommand"],
        "hermes plugins install"
    );
    assert!(install["boundary"]
        .as_str()
        .unwrap()
        .contains("dashboard_install_plugin"));

    let update = api_server_process_request(
        &store,
        &settings,
        ParsedWebhookRequest {
            method: "POST".into(),
            path: "/api/dashboard/agent-plugins/kanban/update".into(),
            headers: HashMap::new(),
            body: json!({"execute": true}).to_string(),
        },
    )
    .await
    .unwrap();
    assert_eq!(
        update["schema"],
        "hermes_dashboard_agent_plugin_external_action_desktop_v1"
    );
    assert_eq!(update["ok"], true);
    assert_eq!(update["status"], "external_cli_execution_requested");
    assert_eq!(update["command"], "hermes plugins update kanban");
    assert_eq!(
        update["managedProcessStartPayload"]["metadata"]["hermesCommand"],
        "hermes plugins update"
    );

    let remove = api_server_process_request(
        &store,
        &settings,
        ParsedWebhookRequest {
            method: "DELETE".into(),
            path: "/api/dashboard/agent-plugins/kanban".into(),
            headers: HashMap::new(),
            body: String::new(),
        },
    )
    .await
    .unwrap();
    assert_eq!(
        remove["schema"],
        "hermes_dashboard_agent_plugin_external_action_desktop_v1"
    );
    assert_eq!(remove["ok"], true);
    assert_eq!(remove["status"], "external_cli_plan");
    assert_eq!(remove["command"], "hermes plugins remove kanban");
    assert_eq!(remove["confirmationRequired"], true);

    let capabilities = api_server_capabilities_value(&settings);
    assert_eq!(
        capabilities["capabilityMatrix"]["dashboardPluginManagementRoutes"],
        true
    );
    assert_eq!(
        capabilities["endpoints"]["dashboard_plugins_hub"]["path"],
        "/api/dashboard/plugins/hub"
    );

    let _ = fs::remove_dir_all(dir);
}

#[tokio::test]
async fn api_server_exposes_dashboard_config_routes() {
    let dir = std::env::temp_dir().join(format!(
        "synthchat-dashboard-config-routes-{}",
        new_id("test")
    ));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    let settings = api_server_settings(&store.config().unwrap()).unwrap();

    let mut direct_config = store.config().unwrap();
    direct_config.slack["botToken"] = json!("xoxb-secret");
    store.set_config(direct_config).unwrap();

    let config = api_server_process_request(
        &store,
        &settings,
        ParsedWebhookRequest {
            method: "GET".into(),
            path: "/api/config".into(),
            headers: HashMap::new(),
            body: String::new(),
        },
    )
    .await
    .unwrap();
    assert_eq!(config["schema"], "hermes_dashboard_config_desktop_v1");
    assert_eq!(config["slack"]["botToken"], "***redacted***");

    let defaults = api_server_process_request(
        &store,
        &settings,
        ParsedWebhookRequest {
            method: "GET".into(),
            path: "/api/config/defaults".into(),
            headers: HashMap::new(),
            body: String::new(),
        },
    )
    .await
    .unwrap();
    assert_eq!(
        defaults["schema"],
        "hermes_dashboard_config_defaults_desktop_v1"
    );
    assert_eq!(defaults["config"]["logLevel"], "info");

    let schema = api_server_process_request(
        &store,
        &settings,
        ParsedWebhookRequest {
            method: "GET".into(),
            path: "/api/config/schema".into(),
            headers: HashMap::new(),
            body: String::new(),
        },
    )
    .await
    .unwrap();
    assert_eq!(
        schema["schema"],
        "hermes_dashboard_config_schema_desktop_v1"
    );
    assert_eq!(
        schema["fields"]["dashboardPlugins"]["category"],
        "dashboard"
    );

    let mut updated_config = store.config().unwrap();
    updated_config.log_level = "debug".into();
    let update = api_server_process_request(
        &store,
        &settings,
        ParsedWebhookRequest {
            method: "PUT".into(),
            path: "/api/config".into(),
            headers: HashMap::new(),
            body: json!({"config": updated_config}).to_string(),
        },
    )
    .await
    .unwrap();
    assert_eq!(
        update["schema"],
        "hermes_dashboard_config_update_desktop_v1"
    );
    assert_eq!(store.config().unwrap().log_level, "debug");

    let raw = api_server_process_request(
        &store,
        &settings,
        ParsedWebhookRequest {
            method: "GET".into(),
            path: "/api/config/raw".into(),
            headers: HashMap::new(),
            body: String::new(),
        },
    )
    .await
    .unwrap();
    assert_eq!(raw["schema"], "hermes_dashboard_config_raw_desktop_v1");
    assert_eq!(raw["rawFormat"], "json");

    let mut raw_config = store.config().unwrap();
    raw_config.log_level = "warn".into();
    let raw_update = api_server_process_request(
        &store,
        &settings,
        ParsedWebhookRequest {
            method: "PUT".into(),
            path: "/api/config/raw".into(),
            headers: HashMap::new(),
            body: json!({"yaml_text": serde_json::to_string_pretty(&raw_config).unwrap()})
                .to_string(),
        },
    )
    .await
    .unwrap();
    assert_eq!(
        raw_update["schema"],
        "hermes_dashboard_config_raw_update_desktop_v1"
    );
    assert_eq!(store.config().unwrap().log_level, "warn");

    let capabilities = api_server_capabilities_value(&settings);
    assert_eq!(capabilities["capabilityMatrix"]["configRoutes"], true);
    assert_eq!(capabilities["endpoints"]["config"]["path"], "/api/config");
    assert_eq!(
        capabilities["endpoints"]["config_raw"]["path"],
        "/api/config/raw"
    );

    let _ = fs::remove_dir_all(dir);
}

#[tokio::test]
async fn api_server_exposes_dashboard_env_routes() {
    let dir =
        std::env::temp_dir().join(format!("synthchat-dashboard-env-routes-{}", new_id("test")));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    let mut provider = LlmProvider::default();
    provider.id = "openai-main".into();
    provider.name = "OpenAI".into();
    provider.provider_type = "openai".into();
    provider.api_key_env = "OPENAI_API_KEY".into();
    provider.api_key = None;
    provider.model = "gpt-4o".into();
    provider.enabled = true;
    store.set_providers(vec![provider]).unwrap();
    let settings = api_server_settings(&store.config().unwrap()).unwrap();

    let initial = api_server_process_request(
        &store,
        &settings,
        ParsedWebhookRequest {
            method: "GET".into(),
            path: "/api/env".into(),
            headers: HashMap::new(),
            body: String::new(),
        },
    )
    .await
    .unwrap();
    assert_eq!(initial["OPENAI_API_KEY"]["is_set"], false);
    assert_eq!(initial["OPENAI_API_KEY"]["category"], "models");

    let update = api_server_process_request(
        &store,
        &settings,
        ParsedWebhookRequest {
            method: "PUT".into(),
            path: "/api/env".into(),
            headers: HashMap::new(),
            body: json!({"key": "OPENAI_API_KEY", "value": "sk-test-secret"}).to_string(),
        },
    )
    .await
    .unwrap();
    assert_eq!(update["schema"], "hermes_dashboard_env_update_desktop_v1");
    assert_eq!(
        store.config().unwrap().messaging_gateway["dashboardEnv"]["OPENAI_API_KEY"],
        "sk-test-secret"
    );
    assert_eq!(
        store.providers().unwrap()[0].api_key.as_deref(),
        Some("sk-test-secret")
    );

    let env_after = api_server_process_request(
        &store,
        &settings,
        ParsedWebhookRequest {
            method: "GET".into(),
            path: "/api/env".into(),
            headers: HashMap::new(),
            body: String::new(),
        },
    )
    .await
    .unwrap();
    assert_eq!(env_after["OPENAI_API_KEY"]["is_set"], true);
    assert_eq!(env_after["OPENAI_API_KEY"]["redacted_value"], "sk-t...cret");

    let revealed = api_server_process_request(
        &store,
        &settings,
        ParsedWebhookRequest {
            method: "POST".into(),
            path: "/api/env/reveal".into(),
            headers: HashMap::new(),
            body: json!({"key": "OPENAI_API_KEY"}).to_string(),
        },
    )
    .await
    .unwrap();
    assert_eq!(revealed["schema"], "hermes_dashboard_env_reveal_desktop_v1");
    assert_eq!(revealed["value"], "sk-test-secret");

    let valid = api_server_process_request(
        &store,
        &settings,
        ParsedWebhookRequest {
            method: "POST".into(),
            path: "/api/providers/validate".into(),
            headers: HashMap::new(),
            body: json!({"key": "OPENAI_API_KEY", "value": "sk-valid-shape"}).to_string(),
        },
    )
    .await
    .unwrap();
    assert_eq!(
        valid["schema"],
        "hermes_dashboard_provider_validate_desktop_v1"
    );
    assert_eq!(valid["ok"], true);
    assert_eq!(valid["reachable"], false);

    let invalid = api_server_process_request(
        &store,
        &settings,
        ParsedWebhookRequest {
            method: "POST".into(),
            path: "/api/providers/validate".into(),
            headers: HashMap::new(),
            body: json!({"key": "OPENAI_API_KEY", "value": "bad"}).to_string(),
        },
    )
    .await
    .unwrap();
    assert_eq!(invalid["ok"], false);

    let deleted = api_server_process_request(
        &store,
        &settings,
        ParsedWebhookRequest {
            method: "DELETE".into(),
            path: "/api/env".into(),
            headers: HashMap::new(),
            body: json!({"key": "OPENAI_API_KEY"}).to_string(),
        },
    )
    .await
    .unwrap();
    assert_eq!(deleted["schema"], "hermes_dashboard_env_delete_desktop_v1");
    assert!(store.config().unwrap().messaging_gateway["dashboardEnv"]["OPENAI_API_KEY"].is_null());
    assert_eq!(store.providers().unwrap()[0].api_key, None);

    let capabilities = api_server_capabilities_value(&settings);
    assert_eq!(capabilities["capabilityMatrix"]["envRoutes"], true);
    assert_eq!(
        capabilities["endpoints"]["provider_validate"]["path"],
        "/api/providers/validate"
    );

    let _ = fs::remove_dir_all(dir);
}

