#[test]
fn memory_tool_respects_hermes_user_and_memory_targets() {
    let dir = std::env::temp_dir().join(format!("synthchat-memory-targets-{}", new_id("test")));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    let persona = store.persona(None).unwrap();
    let conversation = store
        .create_conversation(Some("Memory Target Test".into()), Some(persona.id.clone()))
        .unwrap();

    let user_added = memory_tool(
        &store,
        &conversation.id,
        &json!({
            "action": "add",
            "target": "user",
            "content": "User prefers terse status updates.",
            "importance": 5
        }),
    )
    .unwrap();
    let user_json: Value = serde_json::from_str(&user_added).unwrap();
    assert_eq!(user_json["result"]["target"], "user");
    assert_eq!(user_json["result"]["memory"]["target"], "user");

    memory_tool(
        &store,
        &conversation.id,
        &json!({
            "action": "add",
            "target": "memory",
            "content": "Project uses Hermes-style memory targets.",
            "importance": 4
        }),
    )
    .unwrap();

    let user_read = memory_tool(
        &store,
        &conversation.id,
        &json!({"action": "read", "target": "user"}),
    )
    .unwrap();
    assert!(user_read.contains("terse status updates"));
    assert!(!user_read.contains("Hermes-style memory targets"));

    let memory_read = memory_tool(
        &store,
        &conversation.id,
        &json!({"action": "read", "target": "memory"}),
    )
    .unwrap();
    assert!(memory_read.contains("Hermes-style memory targets"));
    assert!(!memory_read.contains("terse status updates"));

    let invalid = memory_tool(
        &store,
        &conversation.id,
        &json!({"action": "read", "target": "team"}),
    )
    .unwrap_err()
    .to_string();
    assert!(invalid.contains("invalid memory target"));

    let _ = fs::remove_dir_all(dir);
}

#[test]
fn memory_tool_replace_and_remove_accept_unique_substring_selectors() {
    let dir = std::env::temp_dir().join(format!("synthchat-memory-substring-{}", new_id("test")));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    let persona = store.persona(None).unwrap();
    let conversation = store
        .create_conversation(
            Some("Memory Substring Test".into()),
            Some(persona.id.clone()),
        )
        .unwrap();

    memory_tool(
        &store,
        &conversation.id,
        &json!({"action": "add", "content": "Remember the Hermes memory substring selector."}),
    )
    .unwrap();
    memory_tool(
        &store,
        &conversation.id,
        &json!({"action": "add", "content": "Remember the Hermes memory target split."}),
    )
    .unwrap();

    let replaced = memory_tool(
        &store,
        &conversation.id,
        &json!({
            "action": "replace",
            "oldText": "substring selector",
            "content": "Hermes memory substring selector accepts short unique matches."
        }),
    )
    .unwrap();
    assert!(replaced.contains("short unique matches"));

    let ambiguous = memory_tool(
        &store,
        &conversation.id,
        &json!({"action": "remove", "match": "Hermes memory"}),
    )
    .unwrap_err()
    .to_string();
    assert!(ambiguous.contains("ambiguous"));

    let removed = memory_tool(
        &store,
        &conversation.id,
        &json!({"action": "remove", "match": "target split"}),
    )
    .unwrap();
    assert!(removed.contains("Removed long-term memory"));

    let remaining = memory_tool(
        &store,
        &conversation.id,
        &json!({"action": "read", "query": "Hermes memory"}),
    )
    .unwrap();
    assert!(remaining.contains("short unique matches"));
    assert!(!remaining.contains("target split"));

    let _ = fs::remove_dir_all(dir);
}

#[test]
fn memory_write_hook_records_run_phase() {
    let dir = std::env::temp_dir().join(format!("synthchat-memory-write-hook-{}", new_id("test")));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    let persona = store.persona(None).unwrap();
    let conversation = store
        .create_conversation(Some("Memory Write Hook".into()), Some(persona.id.clone()))
        .unwrap();
    let run = store
        .save_agent_run(AgentRunRecord::new(
            conversation.id.clone(),
            persona.id.clone(),
            "default".into(),
        ))
        .unwrap();

    let remembered = remember_fact_tool_for_run(
        &store,
        &conversation.id,
        &run.run_id,
        &json!({"summary": "User prefers memory write hooks.", "importance": 4}),
    )
    .unwrap();
    let memory_id = serde_json::from_str::<Value>(&remembered).unwrap()["memory"]["id"]
        .as_str()
        .unwrap()
        .to_string();
    manage_memory_tool_for_run(
        &store,
        &conversation.id,
        &run.run_id,
        &json!({"action": "remove", "id": memory_id}),
    )
    .unwrap();

    let saved = store.agent_run(&run.run_id).unwrap();
    assert!(saved.phase_events.iter().any(|phase| {
        phase.phase == "memory_write_observed"
            && phase.detail["action"] == "add"
            && phase.detail["target"] == memory_id
    }));
    assert!(saved.phase_events.iter().any(|phase| {
        phase.phase == "memory_write_observed"
            && phase.detail["action"] == "remove"
            && phase.detail["target"] == memory_id
    }));

    let _ = fs::remove_dir_all(dir);
}

