#[test]
fn acp_available_commands_update_matches_hermes_advertised_commands() {
    let update = acp_available_commands_update();
    let commands = update["availableCommands"].as_array().unwrap();
    let names = commands
        .iter()
        .filter_map(|command| command["name"].as_str())
        .collect::<Vec<_>>();
    let model = commands
        .iter()
        .find(|command| command["name"] == "model")
        .unwrap();
    let queue = commands
        .iter()
        .find(|command| command["name"] == "queue")
        .unwrap();

    assert_eq!(update["sessionUpdate"], "available_commands_update");
    assert_eq!(
        names,
        vec!["help", "model", "tools", "context", "reset", "compact", "steer", "queue", "version"]
    );
    assert!(!names.contains(&"approvals"));
    assert!(!names.contains(&"profile"));
    assert_eq!(model["input"]["root"]["hint"], "model name to switch to");
    assert_eq!(queue["input"]["root"]["hint"], "prompt to run next");
}

#[tokio::test]
async fn acp_available_commands_update_for_store_includes_dynamic_plugin_skill_and_bundle_commands()
{
    let dir =
        std::env::temp_dir().join(format!("synthchat-acp-dynamic-commands-{}", new_id("test")));
    let plugin_dir = dir.join("plugins").join("research-plugin");
    let skills_dir = dir.join("skills");
    fs::create_dir_all(&plugin_dir).unwrap();
    fs::create_dir_all(skills_dir.join("research")).unwrap();
    fs::create_dir_all(skills_dir.join("browser").join("control")).unwrap();
    fs::create_dir_all(skills_dir.join("browser").join("automation")).unwrap();
    fs::write(
        plugin_dir.join("__init__.py"),
        r#"
def register(ctx):
    def _handle(raw_args):
        return "plugin research command: " + raw_args
    ctx.register_command("research", handler=_handle, description="Plugin research command", args_hint="query")
"#,
    )
    .unwrap();
    fs::write(skills_dir.join("research").join("SKILL.md"), "# Research\n").unwrap();
    fs::write(
        skills_dir.join("browser").join("control").join("SKILL.md"),
        "# Browser Control\n",
    )
    .unwrap();
    fs::write(
        skills_dir
            .join("browser")
            .join("automation")
            .join("SKILL.md"),
        "# Browser Automation\n",
    )
    .unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    store
        .set_plugins(vec![crate::models::PluginSummary {
            id: "research-plugin".into(),
            name: "research-plugin".into(),
            description: "test plugin command".into(),
            enabled: true,
            provided_tools: vec![],
            provided_capabilities: vec![],
            missing_env: vec![],
            env_configured: true,
            provided_hooks: vec![],
            requires_env: vec![],
            version: "0.1.0".into(),
            author: "test".into(),
            source: "test".into(),
            homepage_url: String::new(),
            kind: "standalone".into(),
            path: plugin_dir.display().to_string(),
            manifest_path: plugin_dir.join("plugin.yaml").display().to_string(),
            entry_point: String::new(),
        }])
        .unwrap();
    store
        .set_skills(vec![
            test_skill_summary(
                "research",
                "Research",
                "Skill research command should not override plugin.",
                false,
                skills_dir
                    .join("research")
                    .join("SKILL.md")
                    .to_string_lossy()
                    .to_string(),
            ),
            test_skill_summary(
                "browser/control",
                "Browser Control",
                "Control browser sessions.",
                false,
                skills_dir
                    .join("browser")
                    .join("control")
                    .join("SKILL.md")
                    .to_string_lossy()
                    .to_string(),
            ),
            test_skill_summary(
                "browser/automation",
                "Browser Automation",
                "Automate browser sessions.",
                false,
                skills_dir
                    .join("browser")
                    .join("automation")
                    .join("SKILL.md")
                    .to_string_lossy()
                    .to_string(),
            ),
        ])
        .unwrap();

    let update = acp_available_commands_update_for_store(&store);
    let commands = update["availableCommands"].as_array().unwrap();
    let by_name = |name: &str| {
        commands
            .iter()
            .filter(|command| command["name"] == name)
            .collect::<Vec<_>>()
    };

    assert_eq!(update["sessionUpdate"], "available_commands_update");
    assert_eq!(by_name("model").len(), 1);
    let research = by_name("research");
    assert_eq!(research.len(), 1);
    assert_eq!(research[0]["description"], "Plugin research command");
    assert_eq!(research[0]["input"]["root"]["hint"], "query");
    assert_eq!(by_name("browser-control").len(), 1);
    assert_eq!(by_name("browser-automation").len(), 1);
    assert_eq!(by_name("browser").len(), 1);
    assert_eq!(
        by_name("browser")[0]["input"]["root"]["hint"],
        "instruction for the skill bundle"
    );
    let help = delegation::acp_local_command_reply_for_prompt(&store, "", "/help")
        .await
        .unwrap()
        .unwrap()
        .text;
    assert!(help.contains("/research"));
    assert!(help.contains("Plugin research command"));
    assert!(help.contains("/browser-control"));
    assert!(help.contains("/browser-automation"));
    assert!(help.contains("/browser"));

    let _ = fs::remove_dir_all(dir);
}

