#[test]
fn skill_manage_create_write_patch_remove_and_delete_skill() {
    let dir = std::env::temp_dir().join(format!("synthchat-skill-manage-{}", new_id("test")));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    let content = r#"---
name: managed-skill
description: Captures a reusable managed workflow.
version: 1.0.0
---

Use snapshots before browser actions.
"#;

    let created = skill_manage_tool(
        &store,
        &json!({
            "action": "create",
            "name": "managed-skill",
            "content": content
        }),
    )
    .unwrap();
    let created_json: Value = serde_json::from_str(&created).unwrap();
    assert_eq!(created_json["ok"], true);
    assert_eq!(created_json["success"], true);
    assert_eq!(store.skills().unwrap().len(), 1);

    let written = skill_manage_tool(
        &store,
        &json!({
            "action": "write_file",
            "name": "managed-skill",
            "filePath": "references/forms.md",
            "fileContent": "Extract forms first."
        }),
    )
    .unwrap();
    let written_json: Value = serde_json::from_str(&written).unwrap();
    assert_eq!(written_json["action"], "write_file");
    assert!(PathBuf::from(written_json["path"].as_str().unwrap()).exists());

    skill_manage_tool(
        &store,
        &json!({
            "action": "patch",
            "name": "managed-skill",
            "oldString": "Use snapshots before browser actions.",
            "newString": "Use browser_cdp snapshots before browser actions."
        }),
    )
    .unwrap();
    let agent = store.agent(None).unwrap();
    let viewed = skill_view_tool(&store, &agent, &json!({"name": "managed-skill"})).unwrap();
    assert!(viewed.contains("browser_cdp snapshots"));

    skill_manage_tool(
        &store,
        &json!({
            "action": "remove_file",
            "name": "managed-skill",
            "filePath": "references/forms.md"
        }),
    )
    .unwrap();
    let skill_dir = dir
        .join("skills")
        .join("agent-managed")
        .join("managed-skill");
    assert!(!skill_dir.join("references").join("forms.md").exists());

    let pinned =
        skill_manage_tool(&store, &json!({"action": "pin", "name": "managed-skill"})).unwrap();
    let pinned_json: Value = serde_json::from_str(&pinned).unwrap();
    assert!(pinned_json["pinnedSkillIds"]
        .as_array()
        .unwrap()
        .iter()
        .any(|id| id.as_str() == Some("agent-managed/managed-skill")));
    let delete_pinned = skill_manage_tool(
        &store,
        &json!({"action": "delete", "name": "managed-skill"}),
    )
    .unwrap_err();
    assert!(format!("{delete_pinned}").contains("is pinned"));

    let unpinned =
        skill_manage_tool(&store, &json!({"action": "unpin", "name": "managed-skill"})).unwrap();
    let unpinned_json: Value = serde_json::from_str(&unpinned).unwrap();
    assert!(unpinned_json["pinnedSkillIds"]
        .as_array()
        .unwrap()
        .is_empty());

    let archived = skill_manage_tool(
        &store,
        &json!({
            "action": "archive",
            "name": "managed-skill",
            "reason": "covered by a broader workflow"
        }),
    )
    .unwrap();
    let archived_json: Value = serde_json::from_str(&archived).unwrap();
    assert_eq!(
        archived_json["archive"]["skillId"],
        "agent-managed/managed-skill"
    );
    assert!(store.skills().unwrap().is_empty());
    assert!(!skill_dir.exists());

    let restored = skill_manage_tool(
        &store,
        &json!({"action": "restore", "name": "agent-managed/managed-skill"}),
    )
    .unwrap();
    let restored_json: Value = serde_json::from_str(&restored).unwrap();
    assert_eq!(restored_json["archive"]["restoredAt"].is_string(), true);
    assert_eq!(store.skills().unwrap().len(), 1);
    assert!(skill_dir.exists());

    skill_manage_tool(
        &store,
        &json!({"action": "delete", "name": "managed-skill"}),
    )
    .unwrap();
    assert!(store.skills().unwrap().is_empty());
    assert!(!skill_dir.exists());
    let _ = fs::remove_dir_all(dir);
}

#[test]
fn skill_manage_rejects_invalid_skill_inputs() {
    let dir =
        std::env::temp_dir().join(format!("synthchat-skill-manage-invalid-{}", new_id("test")));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();

    let bad_name = skill_manage_tool(
        &store,
        &json!({
            "action": "create",
            "name": "Bad Name",
            "content": "---\nname: bad\ndescription: bad\n---\n\nBody"
        }),
    )
    .unwrap_err();
    assert!(format!("{bad_name}").contains("skill name"));

    let bad_frontmatter = skill_manage_tool(
        &store,
        &json!({
            "action": "create",
            "name": "bad-skill",
            "content": "No frontmatter"
        }),
    )
    .unwrap_err();
    assert!(format!("{bad_frontmatter}").contains("frontmatter"));

    let content = "---\nname: safe\ndescription: safe skill\n---\n\nBody";
    skill_manage_tool(
        &store,
        &json!({"action": "create", "name": "safe", "content": content}),
    )
    .unwrap();
    let escape = skill_manage_tool(
        &store,
        &json!({
            "action": "write_file",
            "name": "safe",
            "filePath": "../secret.md",
            "fileContent": "secret"
        }),
    )
    .unwrap_err();
    assert!(format!("{escape}").contains("normal relative"));
    let _ = fs::remove_dir_all(dir);
}

#[test]
fn skill_manage_exposes_hub_status_provenance_and_taps() {
    let dir = std::env::temp_dir().join(format!("synthchat-skill-hub-{}", new_id("test")));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();

    let content = r#"---
name: external-demo
description: External demo skill.
---

Use this skill for external workflow tests.
"#;
    let installed = skill_manage_tool(
        &store,
        &json!({
            "action": "install_content",
            "content": content,
            "name": "external-demo",
            "identifier": "inline:external-demo",
            "force": true
        }),
    )
    .unwrap();
    let installed_json: Value = serde_json::from_str(&installed).unwrap();
    assert_eq!(installed_json["success"], true);
    assert_eq!(installed_json["skill"]["name"], "external-demo");

    let status = skill_manage_tool(&store, &json!({"action": "status"})).unwrap();
    let status_json: Value = serde_json::from_str(&status).unwrap();
    assert_eq!(status_json["success"], true);
    assert_eq!(status_json["installRecords"], 1);
    assert_eq!(status_json["externalSkills"], 1);

    let installs = skill_manage_tool(&store, &json!({"action": "list_installs"})).unwrap();
    let installs_json: Value = serde_json::from_str(&installs).unwrap();
    assert_eq!(installs_json["count"], 1);
    assert_eq!(
        installs_json["records"][0]["identifier"],
        "inline:external-demo"
    );

    let updates = skill_manage_tool(&store, &json!({"action": "check_updates"})).unwrap();
    let updates_json: Value = serde_json::from_str(&updates).unwrap();
    assert_eq!(updates_json["success"], true);
    assert_eq!(updates_json["count"], 1);
    assert_eq!(updates_json["updates"][0]["status"], "source_missing");

    let audit = skill_manage_tool(&store, &json!({"action": "audit", "name": "external"})).unwrap();
    let audit_json: Value = serde_json::from_str(&audit).unwrap();
    assert_eq!(audit_json["success"], true);
    assert_eq!(audit_json["count"], 1);

    let added_tap = skill_manage_tool(
        &store,
        &json!({"action": "add_tap", "repo": "Example/Skills", "path": "skills/"}),
    )
    .unwrap();
    let added_tap_json: Value = serde_json::from_str(&added_tap).unwrap();
    assert_eq!(added_tap_json["success"], true);
    assert_eq!(added_tap_json["tap"]["repo"], "example/skills");

    let taps = skill_manage_tool(&store, &json!({"action": "list_taps"})).unwrap();
    let taps_json: Value = serde_json::from_str(&taps).unwrap();
    assert_eq!(taps_json["count"], 1);

    let removed_tap = skill_manage_tool(
        &store,
        &json!({"action": "remove_tap", "repo": "example/skills"}),
    )
    .unwrap();
    let removed_tap_json: Value = serde_json::from_str(&removed_tap).unwrap();
    assert_eq!(removed_tap_json["removed"], true);

    let curator_status = skill_manage_tool(&store, &json!({"action": "curator_status"})).unwrap();
    let curator_status_json: Value = serde_json::from_str(&curator_status).unwrap();
    assert_eq!(curator_status_json["success"], true);
    assert_eq!(curator_status_json["state"]["paused"], false);

    let paused = skill_manage_tool(&store, &json!({"action": "curator_pause"})).unwrap();
    let paused_json: Value = serde_json::from_str(&paused).unwrap();
    assert_eq!(paused_json["state"]["paused"], true);

    let resumed = skill_manage_tool(&store, &json!({"action": "curator_resume"})).unwrap();
    let resumed_json: Value = serde_json::from_str(&resumed).unwrap();
    assert_eq!(resumed_json["state"]["paused"], false);

    let audit_log = skill_manage_tool(&store, &json!({"action": "audit_log", "limit": 5})).unwrap();
    let audit_log_json: Value = serde_json::from_str(&audit_log).unwrap();
    assert_eq!(audit_log_json["success"], true);
    assert_eq!(audit_log_json["count"], 1);

    let snapshot_path = dir.join("snapshot.json");
    let exported = skill_manage_tool(
        &store,
        &json!({"action": "export_snapshot", "path": snapshot_path.display().to_string()}),
    )
    .unwrap();
    let exported_json: Value = serde_json::from_str(&exported).unwrap();
    assert!(PathBuf::from(exported_json["path"].as_str().unwrap()).exists());

    let imported = skill_manage_tool(
        &store,
        &json!({"action": "import_snapshot", "path": snapshot_path.display().to_string()}),
    )
    .unwrap();
    let imported_json: Value = serde_json::from_str(&imported).unwrap();
    assert_eq!(imported_json["success"], true);
    assert!(imported_json["count"].as_u64().unwrap() >= 1);

    let _ = fs::remove_dir_all(dir);
}

#[test]
fn session_search_helpers_score_and_sort_candidates() {
    let exact =
        session_search_relevance_score("backend logs show blank page root cause", "blank page");
    let terms = session_search_relevance_score("blank screen after page load", "blank page");
    let none = session_search_relevance_score("unrelated message", "blank page");
    assert!(exact > terms);
    assert!(terms > none);
    assert_eq!(session_search_relevance_score("anything", ""), 1);

    let mut candidates = vec![
        SessionSearchCandidate {
            kind: "message".into(),
            conversation_id: "old".into(),
            message_id: None,
            source: "old".into(),
            content: "old".into(),
            metadata: None,
            score: 10,
            recency: 10,
        },
        SessionSearchCandidate {
            kind: "message".into(),
            conversation_id: "new".into(),
            message_id: None,
            source: "new".into(),
            content: "new".into(),
            metadata: None,
            score: 1,
            recency: 1,
        },
    ];
    sort_session_search_candidates(&mut candidates, "newest");
    assert_eq!(candidates[0].conversation_id, "new");
    sort_session_search_candidates(&mut candidates, "oldest");
    assert_eq!(candidates[0].conversation_id, "old");
}

#[test]
fn session_search_browse_discover_and_scroll_store_history() {
    let dir = std::env::temp_dir().join(format!("synthchat-session-search-{}", new_id("test")));
    fs::create_dir_all(&dir).unwrap();
    let path = dir.join("state.json");
    let store = AppStore::new(path).unwrap();
    let persona = store.persona(None).unwrap();
    let conversation = store
        .create_conversation(Some("Session Search Test".into()), Some(persona.id))
        .unwrap();
    let first = store
        .append_message(ChatMessage::new(
            conversation.id.clone(),
            "user",
            "The blank page was caused by missing backend startup.".into(),
            "test",
        ))
        .unwrap();
    store
        .append_message(ChatMessage::new(
            conversation.id.clone(),
            "assistant",
            "We fixed it by starting the backend service.".into(),
            "test",
        ))
        .unwrap();

    let (browse_text, browse_raw) =
        execute_session_search(&store, &conversation, &json!({})).unwrap();
    assert!(browse_text.contains("Session Search Test"));
    assert_eq!(browse_raw["mode"], "browse");
    assert_eq!(browse_raw["success"], true);
    assert_eq!(browse_raw["count"].as_u64().unwrap(), 1);
    assert_eq!(browse_raw["results"][0]["session_id"], conversation.id);
    assert!(browse_raw["results"][0]["preview"]
        .as_str()
        .unwrap()
        .contains("backend"));

    let (discover_text, discover_raw) = execute_session_search(
        &store,
        &conversation,
        &json!({"query": "blank backend", "kind": "message", "limit": 2}),
    )
    .unwrap();
    assert!(discover_text.contains("blank page"));
    assert_eq!(discover_raw["mode"], "discover");
    assert_eq!(discover_raw["success"], true);
    assert_eq!(discover_raw["count"].as_u64().unwrap(), 2);
    assert_eq!(discover_raw["total"].as_u64().unwrap(), 2);
    assert_eq!(discover_raw["results"][0]["session_id"], conversation.id);
    assert!(discover_raw["results"][0]["match_message_id"].is_string());
    assert!(discover_raw["results"][0]["snippet"]
        .as_str()
        .unwrap()
        .contains("blank"));

    let (scroll_text, scroll_raw) = execute_session_search(
        &store,
        &conversation,
        &json!({"session_id": conversation.id, "around_message_id": first.id, "window": 1}),
    )
    .unwrap();
    assert!(scroll_text.contains("messageId="));
    assert_eq!(scroll_raw["mode"], "scroll");
    assert_eq!(scroll_raw["success"], true);
    assert_eq!(scroll_raw["found"], true);
    assert_eq!(scroll_raw["session_id"], conversation.id);
    assert_eq!(scroll_raw["around_message_id"], first.id);
    assert_eq!(scroll_raw["messages_before"], 0);
    let _ = fs::remove_dir_all(dir);
}

#[test]
fn session_search_hides_subagent_runs_by_default() {
    let dir = std::env::temp_dir().join(format!(
        "synthchat-session-search-subagents-{}",
        new_id("test")
    ));
    fs::create_dir_all(&dir).unwrap();
    let path = dir.join("state.json");
    let store = AppStore::new(path).unwrap();
    let persona = store.persona(None).unwrap();
    let agent = store.agents().unwrap().remove(0);
    let conversation = store
        .create_conversation(
            Some("Subagent Search Test".into()),
            Some(persona.id.clone()),
        )
        .unwrap();

    let mut parent = AgentRunRecord::new(
        conversation.id.clone(),
        persona.id.clone(),
        agent.id.clone(),
    );
    parent.user_request = "parent request".into();
    store.save_agent_run(parent.clone()).unwrap();

    let mut child = AgentRunRecord::new(
        conversation.id.clone(),
        persona.id.clone(),
        agent.id.clone(),
    );
    child.parent_run_id = Some(parent.run_id.clone());
    child.subagent_index = Some(1);
    child.user_request = "needle child delegated run".into();
    store.save_agent_run(child).unwrap();

    let (_, default_raw) = execute_session_search(
        &store,
        &conversation,
        &json!({"query": "needle delegated", "kind": "run"}),
    )
    .unwrap();
    assert_eq!(default_raw["includeSubagents"], false);
    assert_eq!(default_raw["total"].as_u64().unwrap(), 0);

    let (_, included_raw) = execute_session_search(
        &store,
        &conversation,
        &json!({"query": "needle delegated", "kind": "run", "includeSubagents": true}),
    )
    .unwrap();
    assert_eq!(included_raw["includeSubagents"], true);
    assert_eq!(included_raw["total"].as_u64().unwrap(), 1);

    let _ = fs::remove_dir_all(dir);
}

