#[test]
fn dashboard_auth_tool_exposes_hermes_nous_contract_snapshot() {
    let _guard = CHANNEL_DIRECTORY_ENV_LOCK.lock().unwrap();
    let old_home = env::var_os("HERMES_HOME");
    let old_client_id = env::var_os("HERMES_DASHBOARD_OAUTH_CLIENT_ID");
    let old_portal_url = env::var_os("HERMES_DASHBOARD_PORTAL_URL");
    env::remove_var("HERMES_DASHBOARD_OAUTH_CLIENT_ID");
    env::remove_var("HERMES_DASHBOARD_PORTAL_URL");
    env::remove_var("HERMES_DASHBOARD_JWKS_JSON");
    env::remove_var("HERMES_DASHBOARD_JWKS_PATH");
    let dir = std::env::temp_dir().join(format!("synthchat-dashboard-auth-{}", new_id("test")));
    let hermes_home = dir.join(".hermes");
    fs::create_dir_all(&hermes_home).unwrap();
    fs::write(
        hermes_home.join("config.yaml"),
        "dashboard:\n  oauth:\n    client_id: agent:instance-123456\n    portal_url: https://portal.rewbs.uk\n",
    )
    .unwrap();
    env::set_var("HERMES_HOME", &hermes_home);
    let store = AppStore::new(dir.join("state.json")).unwrap();

    let snapshot = dashboard_auth::nous_dashboard_auth_snapshot(&store);
    assert_eq!(snapshot["schema"], "hermes_dashboard_auth_desktop_v1");
    assert_eq!(snapshot["provider"]["registered"], true);
    assert_eq!(
        snapshot["configuration"]["clientIdSource"],
        "config.yaml:dashboard.oauth.client_id"
    );
    assert_eq!(
        snapshot["configuration"]["portalUrl"],
        "https://portal.rewbs.uk"
    );
    assert_eq!(snapshot["contract"]["scope"], "agent_dashboard:access");
    assert_eq!(
        snapshot["contract"]["tokenEndpoint"],
        "https://portal.rewbs.uk/api/oauth/token"
    );
    assert_eq!(
        snapshot["contract"]["jwksEndpoint"],
        "https://portal.rewbs.uk/.well-known/jwks.json"
    );
    assert_eq!(snapshot["contract"]["refreshTokens"]["issuedInV1"], false);
    assert_eq!(
        snapshot["contract"]["redirectUriRules"]["pathSuffix"],
        "/auth/callback"
    );
    assert_eq!(
        snapshot["desktopAdaptation"]["relatedAuthSurface"],
        "Nous LLM/device-code OAuth remains handled by /auth login nous and the credential pool; this dashboard auth contract is separate from LLM provider auth."
    );

    let prompt = agent_planner_prompt(&[], &[], &[], &empty_short_context(), &[]);
    assert!(prompt.contains("dashboard_auth"));
    assert!(prompt.contains("dashboard_auth/nous"));
    assert!(is_internal_tool("dashboard_auth"));
    assert!(!is_risky_tool_call(
        "dashboard_auth",
        &json!({"provider": "nous"})
    ));
    assert_eq!(
        tool_event_kind("__internal", "dashboard_auth", None),
        "read"
    );
    let toolsets = tool_toolsets(&test_internal_tool("dashboard_auth"));
    assert!(toolsets.contains("config"));

    restore_test_env("HERMES_HOME", old_home);
    restore_test_env("HERMES_DASHBOARD_OAUTH_CLIENT_ID", old_client_id);
    restore_test_env("HERMES_DASHBOARD_PORTAL_URL", old_portal_url);
    let _ = fs::remove_dir_all(dir);
}

#[test]
fn dashboard_auth_gate_contract_matches_hermes_cookie_and_unauth_rules() {
    assert_eq!(
        dashboard_auth::dashboard_auth_normalise_prefix(Some("hermes/")),
        "/hermes"
    );
    assert_eq!(
        dashboard_auth::dashboard_auth_normalise_prefix(Some("/bad/../prefix")),
        ""
    );
    assert_eq!(
        dashboard_auth::dashboard_auth_cookie_name("hermes_session_at", false, ""),
        "hermes_session_at"
    );
    assert_eq!(
        dashboard_auth::dashboard_auth_cookie_name("hermes_session_at", true, ""),
        "__Host-hermes_session_at"
    );
    assert_eq!(
        dashboard_auth::dashboard_auth_cookie_name("hermes_session_at", true, "/hermes"),
        "__Secure-hermes_session_at"
    );
    assert_eq!(dashboard_auth::dashboard_auth_cookie_path(""), "/");
    assert_eq!(
        dashboard_auth::dashboard_auth_cookie_path("/hermes"),
        "/hermes"
    );
    assert!(dashboard_auth::dashboard_auth_path_is_public("/api/status"));
    assert!(dashboard_auth::dashboard_auth_path_is_public(
        "/assets/app.js"
    ));
    assert!(!dashboard_auth::dashboard_auth_path_is_public(
        "/api/status/secret-extension"
    ));

    let api = dashboard_auth::dashboard_auth_unauth_response_contract(
        "/api/plugins/kanban/board",
        "",
        Some("/hermes"),
        "invalid_or_expired_session",
    );
    assert_eq!(api["status"], 401);
    assert_eq!(api["body"]["error"], "session_expired");
    assert_eq!(api["body"]["login_url"], "/hermes/login");

    let html = dashboard_auth::dashboard_auth_unauth_response_contract(
        "/sessions",
        "page=2",
        Some("hermes"),
        "no_cookie",
    );
    assert_eq!(html["status"], 302);
    assert_eq!(
        html["location"],
        "/hermes/login?next=%2Fsessions%3Fpage%3D2"
    );

    let contract = dashboard_auth::dashboard_auth_gate_contract_summary();
    assert_eq!(contract["schema"], "hermes_dashboard_auth_gate_desktop_v1");
    assert!(contract["publicApiPaths"]
        .as_array()
        .unwrap()
        .iter()
        .any(|path| path == "/api/dashboard/plugins"));

    let mut config = crate::models::AppConfig::default();
    config.messaging_gateway = json!({
        "apiServer": {
            "key": "test-key"
        }
    });
    let settings = api_server_settings(&config).unwrap();
    let capabilities = api_server_capabilities_value(&settings);
    assert_eq!(
        capabilities["capabilityMatrix"]["dashboardAuthGateContract"],
        true
    );
    assert_eq!(
        capabilities["endpoints"]["dashboard_auth_gate"]["native"],
        true
    );
    assert_eq!(
        capabilities["dashboardAuthGate"]["cookiePrefixRules"]["httpsWithForwardedPrefix"],
        "__Secure-"
    );
}

