#[tokio::test]
async fn dashboard_auth_me_verifies_rs256_jwks_when_configured() {
    let _guard = CHANNEL_DIRECTORY_ENV_LOCK.lock().unwrap();
    let old_home = env::var_os("HERMES_HOME");
    let old_client_id = env::var_os("HERMES_DASHBOARD_OAUTH_CLIENT_ID");
    let old_portal_url = env::var_os("HERMES_DASHBOARD_PORTAL_URL");
    let old_jwks_json = env::var_os("HERMES_DASHBOARD_JWKS_JSON");
    let old_jwks_path = env::var_os("HERMES_DASHBOARD_JWKS_PATH");
    let old_jwks_fetch = env::var_os("HERMES_DASHBOARD_JWKS_FETCH");
    env::remove_var("HERMES_DASHBOARD_OAUTH_CLIENT_ID");
    env::remove_var("HERMES_DASHBOARD_PORTAL_URL");
    env::remove_var("HERMES_DASHBOARD_JWKS_PATH");
    env::remove_var("HERMES_DASHBOARD_JWKS_FETCH");
    let dir =
        std::env::temp_dir().join(format!("synthchat-dashboard-auth-jwks-{}", new_id("test")));
    let hermes_home = dir.join(".hermes");
    fs::create_dir_all(&hermes_home).unwrap();
    fs::write(
        hermes_home.join("config.yaml"),
        "dashboard:\n  oauth:\n    client_id: agent:instance-jwks\n    portal_url: https://portal.rewbs.uk\n",
    )
    .unwrap();
    env::set_var("HERMES_HOME", &hermes_home);
    let store = AppStore::new(dir.join("state.json")).unwrap();
    let mut config = store.config().unwrap();
    config.messaging_gateway = json!({
        "apiServer": {
            "key": "api-key"
        }
    });
    let settings = api_server_settings(&config).unwrap();

    let mut rng = rsa::rand_core::OsRng;
    let private_key = rsa::RsaPrivateKey::new(&mut rng, 2048).unwrap();
    let jwks = dashboard_auth_test_jwks(&private_key, "test-key");
    env::set_var("HERMES_DASHBOARD_JWKS_JSON", jwks.to_string());
    let now = chrono::Utc::now().timestamp();
    let token = dashboard_auth_signed_test_jwt(
        &private_key,
        "test-key",
        json!({
            "exp": now + 3600,
            "iat": now - 10,
            "aud": "agent:instance-jwks",
            "iss": "https://portal.rewbs.uk",
            "sub": "user-jwks",
            "agent_instance_id": "instance-jwks",
            "oauth_contract_version": 1,
        }),
    );
    let mut headers = HashMap::new();
    headers.insert("cookie".into(), format!("hermes_session_at={token}"));
    let me = api_server_process_request(
        &store,
        &settings,
        ParsedWebhookRequest {
            method: "GET".into(),
            path: "/api/auth/me".into(),
            headers,
            body: String::new(),
        },
    )
    .await
    .unwrap();
    assert_eq!(me["provider"], "nous");
    assert_eq!(me["user_id"], "user-jwks");
    assert_eq!(me["claimsValidated"], true);
    assert_eq!(me["signatureVerified"], true);
    assert_eq!(me["externalJwksBoundary"], false);
    assert_eq!(me["verification"]["signature"], "rs256_jwks_verified");
    assert_eq!(
        me["verification"]["jwksSource"],
        "env:HERMES_DASHBOARD_JWKS_JSON"
    );

    let mut tampered = token.clone();
    tampered.pop();
    tampered.push(if token.ends_with('A') { 'B' } else { 'A' });
    let rejected = dashboard_auth::dashboard_auth_session_from_access_token(&store, &tampered)
        .unwrap_err()
        .to_string();
    assert!(rejected.contains("signature verification failed") || rejected.contains("JWT"));

    restore_test_env("HERMES_HOME", old_home);
    restore_test_env("HERMES_DASHBOARD_OAUTH_CLIENT_ID", old_client_id);
    restore_test_env("HERMES_DASHBOARD_PORTAL_URL", old_portal_url);
    restore_test_env("HERMES_DASHBOARD_JWKS_JSON", old_jwks_json);
    restore_test_env("HERMES_DASHBOARD_JWKS_PATH", old_jwks_path);
    restore_test_env("HERMES_DASHBOARD_JWKS_FETCH", old_jwks_fetch);
    let _ = fs::remove_dir_all(dir);
}

