#[tokio::test]
async fn dashboard_auth_callback_exchanges_code_and_sets_session_cookie() {
    let _guard = CHANNEL_DIRECTORY_ENV_LOCK.lock().unwrap();
    dashboard_auth::dashboard_auth_reset_jwks_cache_for_tests();
    let old_home = env::var_os("HERMES_HOME");
    let old_client_id = env::var_os("HERMES_DASHBOARD_OAUTH_CLIENT_ID");
    let old_portal_url = env::var_os("HERMES_DASHBOARD_PORTAL_URL");
    let old_jwks_json = env::var_os("HERMES_DASHBOARD_JWKS_JSON");
    let old_jwks_path = env::var_os("HERMES_DASHBOARD_JWKS_PATH");
    let old_jwks_fetch = env::var_os("HERMES_DASHBOARD_JWKS_FETCH");
    env::remove_var("HERMES_DASHBOARD_OAUTH_CLIENT_ID");
    env::remove_var("HERMES_DASHBOARD_PORTAL_URL");
    env::remove_var("HERMES_DASHBOARD_JWKS_JSON");
    env::remove_var("HERMES_DASHBOARD_JWKS_PATH");
    env::remove_var("HERMES_DASHBOARD_JWKS_FETCH");

    let private_key = rsa::RsaPrivateKey::new(&mut rsa::rand_core::OsRng, 2048).unwrap();
    let jwks = dashboard_auth_test_jwks(&private_key, "callback-key-1");
    let listener = std::net::TcpListener::bind("127.0.0.1:0").unwrap();
    let portal_url = format!("http://{}", listener.local_addr().unwrap());
    let now = chrono::Utc::now().timestamp();
    let token = dashboard_auth_signed_test_jwt(
        &private_key,
        "callback-key-1",
        json!({
            "exp": now + 3600,
            "iat": now - 10,
            "aud": "agent:instance-callback",
            "iss": portal_url,
            "sub": "user-callback",
            "org_id": "org-callback",
            "agent_instance_id": "instance-callback",
            "oauth_contract_version": 1,
        }),
    );
    let jwks_body = jwks.to_string();
    let server = std::thread::spawn(move || {
        for _ in 0..2 {
            let (mut stream, _) = listener.accept().unwrap();
            let mut request = [0_u8; 8192];
            let bytes = std::io::Read::read(&mut stream, &mut request).unwrap_or(0);
            let request = String::from_utf8_lossy(&request[..bytes]).to_string();
            let body = if request.starts_with("POST /api/oauth/token ") {
                json!({
                    "access_token": token,
                    "token_type": "bearer"
                })
                .to_string()
            } else if request.starts_with("GET /.well-known/jwks.json ") {
                jwks_body.clone()
            } else {
                json!({"error": "unexpected_request", "request": request}).to_string()
            };
            let status = if body.contains("unexpected_request") {
                "404 Not Found"
            } else {
                "200 OK"
            };
            let response = format!(
                "HTTP/1.1 {status}\r\nContent-Type: application/json\r\nContent-Length: {}\r\nConnection: close\r\n\r\n{}",
                body.len(),
                body
            );
            std::io::Write::write_all(&mut stream, response.as_bytes()).unwrap();
        }
    });

    let dir = std::env::temp_dir().join(format!(
        "synthchat-dashboard-auth-callback-{}",
        new_id("test")
    ));
    let hermes_home = dir.join(".hermes");
    fs::create_dir_all(&hermes_home).unwrap();
    fs::write(
        hermes_home.join("config.yaml"),
        format!(
            "dashboard:\n  oauth:\n    client_id: agent:instance-callback\n    portal_url: {portal_url}\n"
        ),
    )
    .unwrap();
    env::set_var("HERMES_HOME", &hermes_home);
    let store = AppStore::new(dir.join("state.json")).unwrap();
    let mut config = store.config().unwrap();
    config.messaging_gateway = json!({
        "apiServer": {
            "key": "api-key"
        }
    });
    let settings = api_server_settings(&config).unwrap();
    let mut login_headers = HashMap::new();
    login_headers.insert("host".into(), "127.0.0.1:8642".into());
    let login = api_server_process_http_request(
        &store,
        &settings,
        ParsedWebhookRequest {
            method: "GET".into(),
            path: "/auth/login?provider=nous&next=%2Fsessions".into(),
            headers: login_headers,
            body: String::new(),
        },
    )
    .await
    .unwrap();
    let (state, cookie_header) = match login {
        ApiServerHttpResponse::Redirect {
            status,
            location,
            headers,
        } => {
            assert_eq!(status, 302);
            let state = dashboard_auth_test_query_value(&location, "state").unwrap();
            let cookie = headers
                .iter()
                .find(|(key, _)| key == "Set-Cookie")
                .map(|(_, value)| value.split(';').next().unwrap().to_string())
                .unwrap();
            assert!(cookie.starts_with("hermes_session_pkce="));
            (state, cookie)
        }
        _ => panic!("expected auth login redirect"),
    };

    let mut callback_headers = HashMap::new();
    callback_headers.insert("host".into(), "127.0.0.1:8642".into());
    callback_headers.insert("cookie".into(), cookie_header);
    let callback = api_server_process_http_request(
        &store,
        &settings,
        ParsedWebhookRequest {
            method: "GET".into(),
            path: format!("/auth/callback?code=valid-code&state={state}"),
            headers: callback_headers,
            body: String::new(),
        },
    )
    .await
    .unwrap();
    match callback {
        ApiServerHttpResponse::Redirect {
            status,
            location,
            headers,
        } => {
            assert_eq!(status, 302);
            assert_eq!(location, "/sessions");
            assert!(headers.iter().any(|(_, value)| {
                value.starts_with("hermes_session_at=")
                    && value.contains("Max-Age=")
                    && value.contains("Path=/")
            }));
            assert!(headers.iter().any(|(_, value)| {
                value.starts_with("__Host-hermes_session_pkce=; Max-Age=0; Path=/")
            }));
        }
        _ => panic!("expected callback redirect"),
    }

    server.join().unwrap();
    dashboard_auth::dashboard_auth_reset_jwks_cache_for_tests();
    restore_test_env("HERMES_HOME", old_home);
    restore_test_env("HERMES_DASHBOARD_OAUTH_CLIENT_ID", old_client_id);
    restore_test_env("HERMES_DASHBOARD_PORTAL_URL", old_portal_url);
    restore_test_env("HERMES_DASHBOARD_JWKS_JSON", old_jwks_json);
    restore_test_env("HERMES_DASHBOARD_JWKS_PATH", old_jwks_path);
    restore_test_env("HERMES_DASHBOARD_JWKS_FETCH", old_jwks_fetch);
    let _ = fs::remove_dir_all(dir);
}

fn dashboard_auth_test_jwt(claims: Value) -> String {
    use base64::{engine::general_purpose::URL_SAFE_NO_PAD, Engine as _};
    let header = URL_SAFE_NO_PAD.encode(br#"{"alg":"RS256","typ":"JWT"}"#);
    let payload = URL_SAFE_NO_PAD.encode(serde_json::to_string(&claims).unwrap());
    let signature = URL_SAFE_NO_PAD.encode(b"signature");
    format!("{header}.{payload}.{signature}")
}

fn dashboard_auth_test_query_value(url: &str, key: &str) -> Option<String> {
    let query = url.split_once('?')?.1;
    for pair in query.split('&') {
        let (raw_key, raw_value) = pair.split_once('=').unwrap_or((pair, ""));
        if raw_key == key {
            return Some(raw_value.to_string());
        }
    }
    None
}

fn dashboard_auth_test_percent_decode(value: &str) -> String {
    let mut output = Vec::new();
    let bytes = value.as_bytes();
    let mut index = 0;
    while index < bytes.len() {
        if bytes[index] == b'%' && index + 2 < bytes.len() {
            if let Ok(hex) = std::str::from_utf8(&bytes[index + 1..index + 3]) {
                if let Ok(byte) = u8::from_str_radix(hex, 16) {
                    output.push(byte);
                    index += 3;
                    continue;
                }
            }
        }
        output.push(bytes[index]);
        index += 1;
    }
    String::from_utf8_lossy(&output).to_string()
}

fn dashboard_auth_signed_test_jwt(
    private_key: &rsa::RsaPrivateKey,
    kid: &str,
    claims: Value,
) -> String {
    use base64::{engine::general_purpose::URL_SAFE_NO_PAD, Engine as _};
    use rsa::{
        pkcs1v15::SigningKey,
        signature::{SignatureEncoding, Signer},
    };
    use sha2::Sha256;
    let header = json!({"alg": "RS256", "typ": "JWT", "kid": kid});
    let signing_input = format!(
        "{}.{}",
        URL_SAFE_NO_PAD.encode(serde_json::to_vec(&header).unwrap()),
        URL_SAFE_NO_PAD.encode(serde_json::to_vec(&claims).unwrap())
    );
    let signer = SigningKey::<Sha256>::new(private_key.clone());
    let signature = signer.sign(signing_input.as_bytes()).to_vec();
    format!("{signing_input}.{}", URL_SAFE_NO_PAD.encode(signature))
}

fn dashboard_auth_test_jwks(private_key: &rsa::RsaPrivateKey, kid: &str) -> Value {
    use base64::{engine::general_purpose::URL_SAFE_NO_PAD, Engine as _};
    use rsa::traits::PublicKeyParts;
    let public_key = private_key.to_public_key();
    json!({
        "keys": [{
            "kty": "RSA",
            "kid": kid,
            "alg": "RS256",
            "use": "sig",
            "n": URL_SAFE_NO_PAD.encode(public_key.n().to_bytes_be()),
            "e": URL_SAFE_NO_PAD.encode(public_key.e().to_bytes_be()),
        }]
    })
}

#[tokio::test]
async fn dashboard_auth_ws_ticket_route_mints_single_use_websocket_tickets() {
    dashboard_auth::dashboard_auth_reset_ws_tickets_for_tests();
    let dir = std::env::temp_dir().join(format!(
        "synthchat-dashboard-auth-ticket-{}",
        new_id("test")
    ));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    let mut config = store.config().unwrap();
    config.messaging_gateway = json!({
        "apiServer": {
            "enabled": true,
            "key": "test key/+",
            "modelName": "synthchat-test"
        }
    });
    store.set_config(config.clone()).unwrap();
    let settings = api_server_settings(&config).unwrap();
    let headers = HashMap::from([("authorization".into(), "Bearer test key/+".into())]);

    let ticket_response = api_server_process_request(
        &store,
        &settings,
        ParsedWebhookRequest {
            method: "POST".into(),
            path: "/api/auth/ws-ticket".into(),
            headers: headers.clone(),
            body: json!({"user_id": "user-123", "provider": "nous"}).to_string(),
        },
    )
    .await
    .unwrap();
    assert_eq!(
        ticket_response["schema"],
        "hermes_dashboard_ws_ticket_desktop_v1"
    );
    assert_eq!(ticket_response["ttl_seconds"], 30);
    assert_eq!(ticket_response["singleUse"], true);
    assert_eq!(ticket_response["info"]["user_id"], "user-123");
    assert_eq!(ticket_response["info"]["provider"], "nous");
    let ticket = ticket_response["ticket"].as_str().unwrap();
    assert!(ticket.starts_with("dashws-"));

    let token_ws_request = ParsedWebhookRequest {
        method: "GET".into(),
        path: "/api/plugins/kanban/events?token=test+key%2F%2B&board=alpha%20board".into(),
        headers: HashMap::from([("upgrade".into(), "websocket".into())]),
        body: String::new(),
    };
    assert!(api_server_verify_websocket_auth(&settings, &token_ws_request).is_ok());
    let token_query = api_server_query_params(&token_ws_request.path);
    assert_eq!(
        token_query.get("token").map(String::as_str),
        Some("test key/+")
    );
    assert_eq!(
        token_query.get("board").map(String::as_str),
        Some("alpha board")
    );

    let ws_request = ParsedWebhookRequest {
        method: "GET".into(),
        path: format!("/api/plugins/kanban/events?ticket={ticket}"),
        headers: HashMap::from([("upgrade".into(), "websocket".into())]),
        body: String::new(),
    };
    assert!(api_server_verify_websocket_auth(&settings, &ws_request).is_ok());
    assert!(api_server_verify_websocket_auth(&settings, &ws_request).is_err());

    let capabilities = api_server_capabilities_value(&settings);
    assert_eq!(
        capabilities["capabilityMatrix"]["dashboardAuthWsTickets"],
        true
    );
    assert_eq!(
        capabilities["endpoints"]["dashboard_auth_ws_ticket"]["path"],
        "/api/auth/ws-ticket"
    );
    assert_eq!(
        capabilities["endpoints"]["kanban_events_websocket"]["queryTicketAuth"],
        true
    );

    dashboard_auth::dashboard_auth_reset_ws_tickets_for_tests();
    let _ = fs::remove_dir_all(dir);
}

