#[tokio::test(flavor = "current_thread")]
async fn dashboard_plugins_fastapi_host_execute_starts_managed_process() {
    let dir = std::env::temp_dir().join(format!(
        "synthchat-dashboard-fastapi-host-{}",
        new_id("test")
    ));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    let agent = store.agent(None).unwrap();
    let command = if cfg!(windows) {
        "powershell -NoProfile -Command Start-Sleep -Seconds 30"
    } else {
        "sh -c 'sleep 30'"
    };

    let plan: Value = serde_json::from_str(
        &dashboard_plugins_tool(
            &store,
            &json!({"action": "fastapi-host", "dashboardCommand": command}),
        )
        .unwrap(),
    )
    .unwrap();
    assert_eq!(plan["status"], "fastapi_host_process_plan");
    assert_eq!(
        plan["managedProcessPlan"]["managedProcessStartPayload"]["command"],
        command
    );
    assert_eq!(
        plan["managedProcessPlan"]["managedProcessTaskStopPayload"]["taskId"],
        "hermes-dashboard-fastapi-host"
    );
    let execution_request_plan: Value = serde_json::from_str(
        &dashboard_plugins_tool(
            &store,
            &json!({"action": "dashboard-host", "execute": true, "dashboardCommand": command}),
        )
        .unwrap(),
    )
    .unwrap();
    assert_eq!(
        execution_request_plan["status"],
        "managed_process_execution_requested"
    );
    assert_eq!(execution_request_plan["executeRequested"], true);

    let result = dashboard_plugins_tool_async(
        &store,
        &agent,
        "conv-dashboard-host",
        "run-dashboard-host",
        &json!({
            "action": "dashboard-host",
            "execute": true,
            "dashboardCommand": command
        }),
        None,
    )
    .await
    .unwrap();
    let result: Value = serde_json::from_str(&result).unwrap();
    assert_eq!(result["status"], "managed_process_started");
    assert_eq!(result["runtime"], "managed_process");
    assert_eq!(result["managedProcessStarted"], true);
    assert_eq!(
        result["managedProcess"]["taskId"],
        "hermes-dashboard-fastapi-host"
    );
    assert_eq!(
        result["managedProcessPlan"]["managedProcessStartPayload"]["command"],
        command
    );

    let processes = store.managed_processes().unwrap();
    assert!(processes.iter().any(|process| {
        process.get("taskId").and_then(Value::as_str) == Some("hermes-dashboard-fastapi-host")
            && process.get("command").and_then(Value::as_str) == Some(command)
    }));

    let stop_result = dashboard_plugins_tool_async(
        &store,
        &agent,
        "conv-dashboard-host",
        "run-dashboard-host-stop",
        &json!({
            "action": "host-stop",
            "execute": true
        }),
        None,
    )
    .await
    .unwrap();
    let stop_result: Value = serde_json::from_str(&stop_result).unwrap();
    assert_eq!(stop_result["status"], "managed_process_stopped");
    assert_eq!(stop_result["managedProcessStopped"], true);
    assert_eq!(
        stop_result["managedProcessStop"]["taskId"],
        "hermes-dashboard-fastapi-host"
    );
    assert_eq!(stop_result["managedProcessStop"]["killed"], 1);

    let _ = fs::remove_dir_all(dir);
}

#[test]
fn dashboard_plugins_kanban_read_actions_adapt_hermes_dashboard_payloads() {
    let dir = std::env::temp_dir().join(format!("synthchat-dashboard-kanban-{}", new_id("test")));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();

    kanban_create_tool(
        &store,
        &json!({
            "taskId": "kb-parent",
            "title": "Port Hermes kanban dashboard",
            "body": "Expose board, stats, assignees, and task detail payloads.",
            "assignee": "planner",
            "tenant": "desktop",
            "priority": 4
        }),
    )
    .unwrap();
    kanban_create_tool(
        &store,
        &json!({
            "taskId": "kb-child",
            "title": "Verify dashboard read payloads",
            "body": "Check cards, comments, and dependency links.",
            "assignee": "worker",
            "tenant": "desktop",
            "parents": ["kb-parent"]
        }),
    )
    .unwrap();
    kanban_link_tool(
        &store,
        &json!({"parentId": "kb-parent", "childId": "kb-child"}),
    )
    .unwrap();
    kanban_comment_tool(
        &store,
        &json!({"taskId": "kb-child", "body": "dashboard handoff", "author": "tester"}),
    )
    .unwrap();
    kanban_complete_tool(
        &store,
        &json!({"taskId": "kb-child", "summary": "read payloads verified"}),
    )
    .unwrap();

    let board: Value = serde_json::from_str(
        &dashboard_plugins_tool(&store, &json!({"action": "kanban-board"})).unwrap(),
    )
    .unwrap();
    assert_eq!(board["schema"], "hermes_kanban_dashboard_desktop_v1");
    assert_eq!(board["status"], "ok");
    assert_eq!(board["action"], "kanban-board");
    assert_eq!(board["nativeDashboardRead"], true);
    assert!(board["tenants"]
        .as_array()
        .unwrap()
        .iter()
        .any(|tenant| tenant == "desktop"));
    assert!(board["assignees"]
        .as_array()
        .unwrap()
        .iter()
        .any(|assignee| assignee == "planner"));
    let columns = board["columns"].as_array().unwrap();
    let ready = columns
        .iter()
        .find(|column| column["name"] == "ready")
        .unwrap();
    let done = columns
        .iter()
        .find(|column| column["name"] == "done")
        .unwrap();
    assert_eq!(ready["tasks"][0]["id"], "kb-parent");
    assert_eq!(ready["tasks"][0]["link_counts"]["children"], 1);
    assert_eq!(done["tasks"][0]["id"], "kb-child");
    assert_eq!(done["tasks"][0]["synthChatStatus"], "completed");
    assert_eq!(done["tasks"][0]["link_counts"]["parents"], 1);
    assert_eq!(done["tasks"][0]["comment_count"], 1);

    let stats: Value = serde_json::from_str(
        &dashboard_plugins_tool(&store, &json!({"action": "kanban-stats"})).unwrap(),
    )
    .unwrap();
    assert_eq!(stats["schema"], "hermes_kanban_dashboard_desktop_v1");
    assert_eq!(stats["total"], 2);
    assert_eq!(stats["per_status"]["ready"], 1);
    assert_eq!(stats["per_status"]["done"], 1);
    assert_eq!(stats["per_assignee"]["planner"], 1);
    assert_eq!(stats["per_assignee"]["worker"], 1);

    let assignees: Value = serde_json::from_str(
        &dashboard_plugins_tool(&store, &json!({"action": "kanban-assignees"})).unwrap(),
    )
    .unwrap();
    assert_eq!(assignees["action"], "kanban-assignees");
    assert_eq!(assignees["count"], 2);
    assert!(assignees["assignees"]
        .as_array()
        .unwrap()
        .iter()
        .any(|item| item["name"] == "worker" && item["task_count"] == 1));

    let task: Value = serde_json::from_str(
        &dashboard_plugins_tool(
            &store,
            &json!({"action": "kanban-task", "taskId": "kb-child"}),
        )
        .unwrap(),
    )
    .unwrap();
    assert_eq!(task["status"], "ok");
    assert_eq!(task["task"]["id"], "kb-child");
    assert_eq!(task["task"]["status"], "done");
    assert_eq!(task["comments"][0]["body"], "dashboard handoff");
    assert_eq!(task["links"]["parents"][0], "kb-parent");
    assert!(task["events"].as_array().unwrap().len() >= 3);

    let missing: Value = serde_json::from_str(
        &dashboard_plugins_tool(
            &store,
            &json!({"action": "kanban-task", "taskId": "missing"}),
        )
        .unwrap(),
    )
    .unwrap();
    assert_eq!(missing["status"], "not_found");
    assert_eq!(missing["task"], Value::Null);

    let _ = fs::remove_dir_all(dir);
}

#[test]
fn dashboard_plugins_kanban_events_adapt_hermes_event_stream_cursor() {
    let dir = std::env::temp_dir().join(format!(
        "synthchat-dashboard-kanban-events-{}",
        new_id("test")
    ));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();

    kanban_create_tool(
        &store,
        &json!({
            "taskId": "kb-events",
            "title": "Stream Hermes kanban events",
            "assignee": "operator",
            "metadata": {"board": "alpha"}
        }),
    )
    .unwrap();
    kanban_comment_tool(
        &store,
        &json!({"taskId": "kb-events", "body": "first dashboard update", "author": "tester"}),
    )
    .unwrap();
    kanban_update_tool(
        &store,
        &json!({"taskId": "kb-events", "status": "review", "metadata": {"board": "alpha"}}),
    )
    .unwrap();
    kanban_create_tool(
        &store,
        &json!({
            "taskId": "kb-events-other",
            "title": "Other board event",
            "metadata": {"board": "beta"}
        }),
    )
    .unwrap();

    let stream: Value = serde_json::from_str(
        &dashboard_plugins_tool(&store, &json!({"action": "kanban-events", "since": 0})).unwrap(),
    )
    .unwrap();
    assert_eq!(stream["schema"], "hermes_kanban_dashboard_desktop_v1");
    assert_eq!(stream["status"], "ok");
    assert_eq!(stream["action"], "kanban-events");
    assert_eq!(stream["nativeEventStream"], true);
    assert_eq!(stream["websocketEmbedded"], false);
    assert_eq!(stream["count"], 4);
    assert_eq!(stream["cursor"], 4);
    let events = stream["events"].as_array().unwrap();
    assert_eq!(events[0]["id"], 1);
    assert_eq!(events[0]["task_id"], "kb-events");
    assert_eq!(events[0]["run_id"], Value::Null);
    assert_eq!(events[0]["kind"], "created");
    assert_eq!(events[0]["payload"], json!({}));
    assert!(events
        .iter()
        .any(|event| event["task_id"] == "kb-events" && event["kind"] == "commented"));
    assert!(events
        .iter()
        .any(|event| event["task_id"] == "kb-events" && event["kind"] == "updated"));

    let alpha: Value = serde_json::from_str(
        &dashboard_plugins_tool(
            &store,
            &json!({"action": "kanban-events-checkpoint", "since": "0", "board": "alpha"}),
        )
        .unwrap(),
    )
    .unwrap();
    assert_eq!(alpha["action"], "kanban-events-checkpoint");
    assert_eq!(alpha["count"], 3);
    assert!(alpha["events"]
        .as_array()
        .unwrap()
        .iter()
        .all(|event| event["task_id"] == "kb-events"));

    std::thread::sleep(std::time::Duration::from_millis(2));
    let cursor = stream["cursor"].as_u64().unwrap();
    kanban_complete_tool(
        &store,
        &json!({"taskId": "kb-events", "summary": "events cursor verified"}),
    )
    .unwrap();
    let next: Value = serde_json::from_str(
        &dashboard_plugins_tool(&store, &json!({"action": "kanban-events", "since": cursor}))
            .unwrap(),
    )
    .unwrap();
    assert_eq!(next["count"], 1);
    assert_eq!(next["cursor"], cursor + 1);
    assert_eq!(next["events"][0]["task_id"], "kb-events");
    assert_eq!(next["events"][0]["kind"], "completed");
    assert_eq!(
        next["events"][0]["payload"]["summary"],
        "events cursor verified"
    );

    let empty: Value = serde_json::from_str(
        &dashboard_plugins_tool(
            &store,
            &json!({"action": "kanban-events", "since": next["cursor"].as_u64().unwrap()}),
        )
        .unwrap(),
    )
    .unwrap();
    assert_eq!(empty["count"], 0);
    assert_eq!(empty["cursor"], cursor + 1);

    let _ = fs::remove_dir_all(dir);
}

#[test]
fn dashboard_plugins_kanban_runtime_events_merge_queue_run_tool_and_task_transitions() {
    let dir = std::env::temp_dir().join(format!(
        "synthchat-dashboard-kanban-runtime-events-{}",
        new_id("test")
    ));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    let conversation = store
        .create_conversation(
            Some("Runtime events".into()),
            Some("persona-runtime".into()),
        )
        .unwrap();
    let conversation_id = conversation.id.clone();
    let message = store
        .append_message(ChatMessage::new(
            conversation_id.clone(),
            "user",
            "Run the bridged worker".into(),
            "desktop",
        ))
        .unwrap();
    let queued = store
        .enqueue_agent_request(conversation_id.clone(), "persona-runtime".into(), &message)
        .unwrap();
    let mut run = AgentRunRecord::new(
        conversation_id.clone(),
        "persona-runtime".into(),
        "agent-runtime".into(),
    );
    run.queue_item_id = Some(queued.id.clone());
    run.user_request = queued.content.clone();
    run.state = "running".into();
    let workflow_updated_at = now_iso();
    run.workflow_graph = Some(json!({
        "schema": SYNTHGRAPH_WORKFLOW_SCHEMA,
        "mode": "chat_turn",
        "currentNode": "executor",
        "currentStatus": "running",
        "lastEventSequence": 2,
        "updatedAt": workflow_updated_at.clone(),
        "nodes": [
            {
                "node": "planner",
                "status": "completed",
                "detail": {"iteration": 1},
                "eventSequence": 1,
                "updatedAt": workflow_updated_at.clone()
            },
            {
                "node": "executor",
                "status": "running",
                "detail": {"toolCount": 1},
                "eventSequence": 2,
                "updatedAt": workflow_updated_at.clone()
            }
        ],
        "transitions": [
            {
                "from": "planner",
                "to": "executor",
                "reason": "tool_request",
                "detail": {"toolCount": 1},
                "eventSequence": 2,
                "updatedAt": workflow_updated_at.clone()
            }
        ]
    }));
    run.phase_events.push(AgentRunPhaseRecord {
        phase: "tool_started".into(),
        detail: json!({"serverId": "__internal", "toolName": "kanban-show"}),
        updated_at: now_iso(),
    });
    let tool_event = tool_started_event(
        &run.run_id,
        "__internal",
        "kanban-show",
        &json!({"taskId": "kb-runtime"}),
    );
    push_tool_event_record(&mut run, &tool_event);
    store.save_agent_run(run.clone()).unwrap();
    kanban_create_tool(
        &store,
        &json!({
            "taskId": "kb-runtime",
            "title": "Runtime bridge task",
            "assignee": "operator",
            "metadata": {"board": "alpha"}
        }),
    )
    .unwrap();

    let stream: Value = serde_json::from_str(
        &dashboard_plugins_tool(
            &store,
            &json!({
                "action": "kanban-runtime-events",
                "conversationId": conversation_id.clone(),
                "board": "alpha"
            }),
        )
        .unwrap(),
    )
    .unwrap();
    assert_eq!(stream["schema"], "hermes_kanban_runtime_events_desktop_v1");
    assert_eq!(stream["nativeRuntimeEventBridge"], true);
    assert_eq!(stream["websocketEmbedded"], false);
    assert!(stream["sources"]
        .as_array()
        .unwrap()
        .contains(&json!(WORKFLOW_RUNTIME_SOURCE)));
    assert_eq!(
        stream["workflowGraphRuntimeContract"]["schema"],
        WORKFLOW_RUNTIME_EVENTS_SCHEMA
    );
    assert_eq!(
        stream["workflow_graph_runtime_contract"]["schema"],
        WORKFLOW_RUNTIME_EVENTS_SCHEMA
    );
    assert_eq!(
        stream["toolCallProtocolContract"]["schema"],
        TOOL_CALL_PROTOCOL_SCHEMA
    );
    assert_eq!(
        stream["tool_call_protocol_contract"]["schema"],
        TOOL_CALL_PROTOCOL_SCHEMA
    );
    assert_eq!(
        stream["runtimeContracts"]["workflowGraph"]["schema"],
        WORKFLOW_RUNTIME_EVENTS_SCHEMA
    );
    assert_eq!(
        stream["runtimeContracts"]["toolCallProtocol"]["schema"],
        TOOL_CALL_PROTOCOL_SCHEMA
    );
    assert_eq!(
        stream["agentRuntimeContracts"]["workflowGraph"]["schema"],
        WORKFLOW_RUNTIME_EVENTS_SCHEMA
    );
    assert_eq!(
        stream["agent_runtime_contracts"]["tool_call_protocol"]["schema"],
        TOOL_CALL_PROTOCOL_SCHEMA
    );
    assert_eq!(
        stream["runtime_contracts"]["workflow_graph"]["schema"],
        WORKFLOW_RUNTIME_EVENTS_SCHEMA
    );
    assert_eq!(
        stream["runtime_contracts"]["tool_call_protocol"]["schema"],
        TOOL_CALL_PROTOCOL_SCHEMA
    );
    assert_eq!(
        stream["toolCallProtocolContract"]["acceptedInputShapes"]["providerNative"]["sourceKeys"],
        json!(provider_tool_call_metadata_source_keys())
    );
    assert_eq!(
        stream["toolCallProtocolContract"]["acceptedInputShapes"]["providerNative"]
            ["callIdLookupKeys"],
        json!(PROVIDER_TOOL_CALL_ID_KEYS)
    );
    let events = stream["events"].as_array().unwrap();
    assert!(events
        .iter()
        .any(|event| event["kind"] == "queue_pending" && event["queue_item_id"] == queued.id));
    assert!(events.iter().any(|event| {
        event["kind"] == "run_running"
            && event["run_id"] == run.run_id
            && event["payload"]["workflowGraph"]["currentNode"] == "executor"
            && event["payload"]["workflowGraph"]["nodes"].is_array()
            && event["payload"]["workflowSummary"]["currentNode"] == "executor"
            && event["payload"]["workflowSummary"]["nodes"].is_null()
    }));
    assert!(events.iter().any(|event| {
        event["kind"] == WORKFLOW_RUNTIME_KIND_SNAPSHOT
            && event["run_id"] == run.run_id
            && event["payload"]["summary"]["currentNode"] == "executor"
            && event["payload"]["workflowSummary"]["currentNode"] == "executor"
            && event["payload"]["workflow_summary"]["currentNode"] == "executor"
            && event["payload"]["workflowGraph"]["currentNode"] == "executor"
            && event["payload"]["workflowGraph"]["current_node"] == "executor"
            && event["payload"]["workflowGraph"]["current_status"] == "running"
            && event["payload"]["workflow_graph"]["currentNode"] == "executor"
            && event["payload"]["workflow_graph"]["current_node"] == "executor"
            && event["payload"]["graph"]["currentNode"] == "executor"
            && event["payload"]["graph"]["current_node"] == "executor"
            && event["payload"]["graph"]["nodes"][0]["event_sequence"] == json!(2)
            && event["payload"]["workflowGraph"]["nodes"].is_array()
            && event["payload"]["summary"]["currentStatus"] == "running"
    }));
    assert!(events.iter().any(|event| {
        event["kind"] == "workflow_node_running"
            && event["run_id"] == run.run_id
            && event["payload"]["role"] == "tool execution"
            && event["payload"]["node"] == "executor"
            && event["payload"]["event_sequence"] == 2
            && event["payload"]["graphSummary"]["currentNode"] == "executor"
            && event["payload"]["graph_summary"]["currentNode"] == "executor"
    }));
    assert!(events.iter().any(|event| {
        event["kind"] == WORKFLOW_RUNTIME_KIND_TRANSITION
            && event["run_id"] == run.run_id
            && event["payload"]["from"] == "planner"
            && event["payload"]["to"] == "executor"
            && event["payload"]["event_sequence"] == 2
            && event["payload"]["graphSummary"]["currentStatus"] == "running"
            && event["payload"]["graph_summary"]["currentStatus"] == "running"
    }));
    assert!(events.iter().any(|event| {
        event["kind"] == "run_phase_tool_started" && event["run_id"] == run.run_id
    }));
    assert!(events
        .iter()
        .any(|event| event["kind"] == "tool_running" && event["run_id"] == run.run_id));
    assert!(events.iter().any(|event| {
        event["kind"] == "created"
            && event["task_id"] == "kb-runtime"
            && event["source"] == "task.events"
    }));

    let cursor = stream["cursor"].as_u64().unwrap();
    let empty: Value = serde_json::from_str(
        &dashboard_plugins_tool(
            &store,
            &json!({
                "action": "kanban-runtime-checkpoint",
                "since": cursor,
                "conversationId": conversation_id.clone(),
                "board": "alpha"
            }),
        )
        .unwrap(),
    )
    .unwrap();
    assert_eq!(empty["action"], "kanban-runtime-checkpoint");
    assert_eq!(empty["count"], 0);
    assert_eq!(empty["cursor"], cursor);

    let _ = fs::remove_dir_all(dir);
}

#[test]
fn dashboard_plugins_kanban_write_actions_adapt_hermes_dashboard_mutations() {
    let dir = std::env::temp_dir().join(format!(
        "synthchat-dashboard-kanban-write-{}",
        new_id("test")
    ));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();

    let created: Value = serde_json::from_str(
        &dashboard_plugins_tool(
            &store,
            &json!({
                "action": "kanban-create",
                "taskId": "kb-parent",
                "title": "Implement Hermes write route parity",
                "body": "Adapt dashboard task mutation routes.",
                "assignee": "planner",
                "tenant": "desktop"
            }),
        )
        .unwrap(),
    )
    .unwrap();
    assert_eq!(created["schema"], "hermes_kanban_dashboard_desktop_v1");
    assert_eq!(created["nativeDashboardWrite"], true);
    assert_eq!(created["taskCard"]["id"], "kb-parent");
    assert_eq!(created["taskCard"]["status"], "ready");

    dashboard_plugins_tool(
        &store,
        &json!({
            "action": "kanban-create",
            "taskId": "kb-child",
            "title": "Exercise dependency writes",
            "assignee": "worker",
            "tenant": "desktop"
        }),
    )
    .unwrap();
    let linked: Value = serde_json::from_str(
        &dashboard_plugins_tool(
            &store,
            &json!({"action": "kanban-link", "parentId": "kb-parent", "childId": "kb-child"}),
        )
        .unwrap(),
    )
    .unwrap();
    assert_eq!(linked["action"], "kanban-link");
    assert_eq!(linked["nativeDashboardWrite"], true);

    let commented: Value = serde_json::from_str(
        &dashboard_plugins_tool(
            &store,
            &json!({
                "action": "kanban-comment",
                "taskId": "kb-child",
                "body": "dashboard mutation note",
                "author": "tester"
            }),
        )
        .unwrap(),
    )
    .unwrap();
    assert_eq!(commented["action"], "kanban-comment");

    let updated: Value = serde_json::from_str(
        &dashboard_plugins_tool(
            &store,
            &json!({
                "action": "kanban-update",
                "taskId": "kb-child",
                "title": "Exercise dependency writes after patch",
                "status": "done",
                "metadata": {"route": "PATCH /tasks/{task_id}"}
            }),
        )
        .unwrap(),
    )
    .unwrap();
    assert_eq!(updated["task"]["status"], "completed");
    assert_eq!(updated["taskCard"]["status"], "done");
    assert_eq!(
        updated["task"]["metadata"]["route"],
        "PATCH /tasks/{task_id}"
    );

    let detail: Value = serde_json::from_str(
        &dashboard_plugins_tool(
            &store,
            &json!({"action": "kanban-task", "taskId": "kb-child"}),
        )
        .unwrap(),
    )
    .unwrap();
    assert_eq!(detail["comments"][0]["body"], "dashboard mutation note");
    assert_eq!(detail["links"]["parents"][0], "kb-parent");

    let unlinked: Value = serde_json::from_str(
        &dashboard_plugins_tool(
            &store,
            &json!({"action": "kanban-unlink", "parentId": "kb-parent", "childId": "kb-child"}),
        )
        .unwrap(),
    )
    .unwrap();
    assert_eq!(unlinked["action"], "kanban-unlink");
    let unlinked_detail: Value = serde_json::from_str(
        &dashboard_plugins_tool(
            &store,
            &json!({"action": "kanban-task", "taskId": "kb-child"}),
        )
        .unwrap(),
    )
    .unwrap();
    assert!(unlinked_detail["links"]["parents"]
        .as_array()
        .unwrap()
        .is_empty());

    let bulk: Value = serde_json::from_str(
        &dashboard_plugins_tool(
            &store,
            &json!({
                "action": "kanban-bulk",
                "taskIds": ["kb-parent", "kb-child"],
                "status": "review",
                "assignee": "reviewer"
            }),
        )
        .unwrap(),
    )
    .unwrap();
    assert_eq!(bulk["count"], 2);
    assert_eq!(bulk["taskCards"][0]["status"], "review");
    assert_eq!(bulk["taskCards"][0]["assignee"], "reviewer");

    let archived: Value = serde_json::from_str(
        &dashboard_plugins_tool(
            &store,
            &json!({"action": "kanban-delete", "taskId": "kb-child"}),
        )
        .unwrap(),
    )
    .unwrap();
    assert_eq!(archived["task"]["status"], "archived");
    assert_eq!(archived["taskCard"]["status"], "archived");

    let board: Value = serde_json::from_str(
        &dashboard_plugins_tool(
            &store,
            &json!({"action": "kanban-board", "includeArchived": true}),
        )
        .unwrap(),
    )
    .unwrap();
    let archived_column = board["columns"]
        .as_array()
        .unwrap()
        .iter()
        .find(|column| column["name"] == "archived")
        .unwrap();
    assert_eq!(archived_column["tasks"][0]["id"], "kb-child");

    let status: Value = serde_json::from_str(
        &dashboard_plugins_tool(&store, &json!({"action": "status"})).unwrap(),
    )
    .unwrap();
    assert!(status["kanbanDashboard"]["nativeDashboardWriteActions"]
        .as_array()
        .unwrap()
        .iter()
        .any(|action| action == "kanban-bulk"));
    assert!(status["kanbanDashboard"]["synthChatNativeTools"]
        .as_array()
        .unwrap()
        .iter()
        .any(|tool| tool == "kanban_update"));

    let _ = fs::remove_dir_all(dir);
}

#[test]
fn dashboard_plugins_kanban_worker_visibility_adapts_hermes_runtime_routes() {
    let dir = std::env::temp_dir().join(format!(
        "synthchat-dashboard-kanban-workers-{}",
        new_id("test")
    ));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    kanban_create_tool(
        &store,
        &json!({
            "taskId": "kb-worker",
            "title": "Expose worker visibility",
            "status": "running",
            "assignee": "operator",
            "metadata": {"artifacts": ["target/report.txt"]}
        }),
    )
    .unwrap();
    kanban_create_tool(
        &store,
        &json!({
            "taskId": "kb-ready",
            "title": "Ready dispatch candidate",
            "status": "ready",
            "assignee": "operator"
        }),
    )
    .unwrap();
    kanban_block_tool(
        &store,
        &json!({"taskId": "kb-ready", "reason": "waiting on worker"}),
    )
    .unwrap();

    store
        .register_managed_process(ManagedProcess {
            id: "proc-kanban-worker".into(),
            label: "operator".into(),
            command: "hermes kanban worker kb-worker".into(),
            cwd: Some(dir.to_string_lossy().to_string()),
            pid: Some(4242),
            backend: "kanban".into(),
            env_type: "desktop".into(),
            status_command: Some(vec!["cmd".into(), "/C".into(), "exit".into(), "0".into()]),
            kill_command: Some(vec!["cmd".into(), "/C".into(), "exit".into(), "0".into()]),
            stdout_command: None,
            stderr_command: None,
            exit_command: None,
            cleanup_command: None,
            exit_code: None,
            task_id: Some("kb-worker".into()),
            conversation_id: "conv-kanban-worker".into(),
            run_id: "run-kanban-worker".into(),
            detached: true,
            pid_scope: "sandbox".into(),
            started_at: now_iso(),
            finished_at: None,
            finished_at_instant: None,
            notify_on_complete: false,
            watch_patterns: Vec::new(),
            tail_retention_lines: 200,
            notifications: std::sync::Arc::new(Mutex::new(
                ManagedProcessNotificationState::default(),
            )),
            stdout: std::sync::Arc::new(Mutex::new(vec![
                "worker claimed kb-worker".into(),
                "worker heartbeat".into(),
            ])),
            stderr: std::sync::Arc::new(Mutex::new(Vec::new())),
            stdin: std::sync::Arc::new(tokio::sync::Mutex::new(None)),
            child: None,
        })
        .unwrap();

    let workers: Value = serde_json::from_str(
        &dashboard_plugins_tool(&store, &json!({"action": "kanban-workers-active"})).unwrap(),
    )
    .unwrap();
    assert_eq!(workers["schema"], "hermes_kanban_dashboard_desktop_v1");
    assert_eq!(workers["count"], 1);
    assert_eq!(workers["workers"][0]["run_id"], "run-kanban-worker");
    assert_eq!(workers["workers"][0]["task_id"], "kb-worker");
    assert_eq!(workers["workers"][0]["worker_pid"], 4242);

    let run: Value = serde_json::from_str(
        &dashboard_plugins_tool(
            &store,
            &json!({"action": "kanban-run", "runId": "run-kanban-worker"}),
        )
        .unwrap(),
    )
    .unwrap();
    assert_eq!(run["status"], "ok");
    assert_eq!(run["run"]["task_id"], "kb-worker");

    let inspect: Value = serde_json::from_str(
        &dashboard_plugins_tool(
            &store,
            &json!({"action": "kanban-run-inspect", "runId": "run-kanban-worker"}),
        )
        .unwrap(),
    )
    .unwrap();
    assert_eq!(inspect["alive"], true);
    assert_eq!(inspect["pid"], 4242);

    let log: Value = serde_json::from_str(
        &dashboard_plugins_tool(
            &store,
            &json!({"action": "kanban-task-log", "taskId": "kb-worker", "limit": 10}),
        )
        .unwrap(),
    )
    .unwrap();
    assert_eq!(log["status"], "ok");
    assert!(log["content"]
        .as_str()
        .unwrap()
        .contains("worker claimed kb-worker"));

    let attachments: Value = serde_json::from_str(
        &dashboard_plugins_tool(
            &store,
            &json!({"action": "kanban-attachments", "taskId": "kb-worker"}),
        )
        .unwrap(),
    )
    .unwrap();
    assert_eq!(attachments["count"], 1);
    assert_eq!(attachments["attachments"][0]["filename"], "report.txt");
    assert_eq!(attachments["uploadSupported"], true);
    assert_eq!(attachments["downloadSupported"], true);
    assert_eq!(attachments["deleteSupported"], true);

    let diagnostics: Value = serde_json::from_str(
        &dashboard_plugins_tool(&store, &json!({"action": "kanban-diagnostics"})).unwrap(),
    )
    .unwrap();
    assert!(diagnostics["diagnostics"]
        .as_array()
        .unwrap()
        .iter()
        .any(|item| item["task_id"] == "kb-ready"));

    kanban_unblock_tool(&store, &json!({"taskId": "kb-ready", "note": "ready"})).unwrap();
    let dispatch: Value = serde_json::from_str(
        &dashboard_plugins_tool(&store, &json!({"action": "kanban-dispatch", "maxSpawn": 2}))
            .unwrap(),
    )
    .unwrap();
    assert_eq!(dispatch["dry_run"], true);
    assert_eq!(dispatch["candidates"][0]["task_id"], "kb-ready");

    let terminated: Value = serde_json::from_str(
        &dashboard_plugins_tool(
            &store,
            &json!({
                "action": "kanban-run-terminate",
                "runId": "run-kanban-worker",
                "reason": "test terminate"
            }),
        )
        .unwrap(),
    )
    .unwrap();
    assert_eq!(terminated["ok"], true);
    assert_eq!(terminated["stopped"]["count"], 1);

    let missing: Value = serde_json::from_str(
        &dashboard_plugins_tool(&store, &json!({"action": "kanban-run", "runId": "missing"}))
            .unwrap(),
    )
    .unwrap();
    assert_eq!(missing["status"], "not_found");

    let _ = fs::remove_dir_all(dir);
}

#[test]
fn dashboard_plugins_kanban_dispatch_claims_ready_tasks_as_desktop_workers() {
    let dir = std::env::temp_dir().join(format!(
        "synthchat-dashboard-kanban-dispatch-{}",
        new_id("test")
    ));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();

    kanban_create_tool(
        &store,
        &json!({
            "taskId": "kb-dispatch",
            "title": "Dispatch ready kanban work",
            "status": "ready",
            "assignee": "operator",
            "metadata": {"board": "alpha"}
        }),
    )
    .unwrap();
    kanban_create_tool(
        &store,
        &json!({
            "taskId": "kb-dispatch-other",
            "title": "Other board ready work",
            "status": "ready",
            "assignee": "operator",
            "metadata": {"board": "beta"}
        }),
    )
    .unwrap();

    let dispatch: Value = serde_json::from_str(
        &dashboard_plugins_tool(
            &store,
            &json!({"action": "kanban-dispatch", "dryRun": false, "maxSpawn": 2, "board": "alpha"}),
        )
        .unwrap(),
    )
    .unwrap();
    assert_eq!(dispatch["schema"], "hermes_kanban_dashboard_desktop_v1");
    assert_eq!(dispatch["dry_run"], false);
    assert_eq!(dispatch["nativeDispatcherClaim"], true);
    assert_eq!(dispatch["spawned"], 1);
    assert_eq!(dispatch["spawnedTasks"][0]["task_id"], "kb-dispatch");
    let run_id = dispatch["spawnedTasks"][0]["run_id"].as_str().unwrap();
    let process_id = dispatch["spawnedTasks"][0]["process"]["id"]
        .as_str()
        .unwrap();

    let detail: Value = serde_json::from_str(
        &dashboard_plugins_tool(
            &store,
            &json!({"action": "kanban-task", "taskId": "kb-dispatch"}),
        )
        .unwrap(),
    )
    .unwrap();
    assert_eq!(detail["task"]["status"], "running");
    assert_eq!(detail["task"]["synthChatStatus"], "running");
    assert_eq!(detail["runs"][0]["run_id"], run_id);
    assert_eq!(
        detail["events"].as_array().unwrap().last().unwrap()["kind"],
        "claimed"
    );

    let workers: Value = serde_json::from_str(
        &dashboard_plugins_tool(&store, &json!({"action": "kanban-workers-active"})).unwrap(),
    )
    .unwrap();
    assert_eq!(workers["count"], 1);
    assert_eq!(workers["workers"][0]["task_id"], "kb-dispatch");
    assert_eq!(workers["workers"][0]["run_id"], run_id);

    let run: Value = serde_json::from_str(
        &dashboard_plugins_tool(&store, &json!({"action": "kanban-run", "runId": run_id})).unwrap(),
    )
    .unwrap();
    assert_eq!(run["status"], "ok");
    assert_eq!(run["run"]["task_id"], "kb-dispatch");
    assert_eq!(run["run"]["queue_item_id"], "kb-dispatch");
    assert_eq!(
        run["run"]["workflowGraph"]["requestSource"],
        "dashboard_plugins.kanban-dispatch"
    );
    assert_eq!(
        run["run"]["workflowGraph"]["request_source"],
        "dashboard_plugins.kanban-dispatch"
    );
    assert_eq!(run["run"]["workflowGraph"]["toolContext"], "scheduled_job");
    assert_eq!(run["run"]["workflowGraph"]["tool_context"], "scheduled_job");
    assert!(run["run"]["workflowGraph"]["nodes"]
        .as_array()
        .unwrap()
        .iter()
        .any(|node| node["node"] == "queue"
            && node["status"] == "completed"
            && node["detail"]["queueItemId"] == "kb-dispatch"));
    let inspect: Value = serde_json::from_str(
        &dashboard_plugins_tool(
            &store,
            &json!({"action": "kanban-run-inspect", "runId": run_id}),
        )
        .unwrap(),
    )
    .unwrap();
    assert_eq!(
        inspect["run"]["workflowGraph"]["requestSource"],
        "dashboard_plugins.kanban-dispatch"
    );
    assert_eq!(
        inspect["run"]["workflowGraph"]["request_source"],
        "dashboard_plugins.kanban-dispatch"
    );
    assert_eq!(inspect["run"]["workflow_summary"]["currentNode"], "planner");

    let events: Value = serde_json::from_str(
        &dashboard_plugins_tool(
            &store,
            &json!({"action": "kanban-events", "board": "alpha"}),
        )
        .unwrap(),
    )
    .unwrap();
    assert!(events["events"]
        .as_array()
        .unwrap()
        .iter()
        .any(|event| event["task_id"] == "kb-dispatch" && event["kind"] == "claimed"));

    let terminated: Value = serde_json::from_str(
        &dashboard_plugins_tool(
            &store,
            &json!({"action": "kanban-run-terminate", "runId": run_id, "reason": "test"}),
        )
        .unwrap(),
    )
    .unwrap();
    assert_eq!(terminated["ok"], true);
    assert_eq!(terminated["stopped"]["count"], 1);
    assert!(store.managed_process_state(process_id).is_err());
    let workers_after: Value = serde_json::from_str(
        &dashboard_plugins_tool(&store, &json!({"action": "kanban-workers-active"})).unwrap(),
    )
    .unwrap();
    assert_eq!(workers_after["count"], 0);

    let other: Value = serde_json::from_str(
        &dashboard_plugins_tool(
            &store,
            &json!({"action": "kanban-task", "taskId": "kb-dispatch-other"}),
        )
        .unwrap(),
    )
    .unwrap();
    assert_eq!(other["task"]["status"], "ready");

    let _ = fs::remove_dir_all(dir);
}

