#[test]
fn browser_session_helpers_build_provider_requests() {
    let mut browserbase = BrowserProvider {
        id: "bb".into(),
        name: "Browserbase".into(),
        provider_type: "browserbase".into(),
        base_url: "https://api.browserbase.com/v1".into(),
        api_key_env: "BROWSERBASE_API_KEY".into(),
        api_key: Some("key".into()),
        project_id: "project".into(),
        record_sessions: false,
        enabled: true,
        timeout_seconds: 20,
    };
    assert_eq!(
        browser_session_create_url(&browserbase).unwrap().as_str(),
        "https://api.browserbase.com/v1/sessions"
    );
    let close = browser_session_close_request(&browserbase, "session-1").unwrap();
    assert_eq!(close.method, "PATCH");
    assert_eq!(
        close.url.as_str(),
        "https://api.browserbase.com/v1/sessions/session-1"
    );
    assert_eq!(close.body["status"], "REQUEST_RELEASE");

    browserbase.provider_type = "browser-use".into();
    browserbase.base_url = "https://api.browser-use.com/api/v3".into();
    assert_eq!(
        browser_session_create_url(&browserbase).unwrap().as_str(),
        "https://api.browser-use.com/api/v3/browsers"
    );
    let close = browser_session_close_request(&browserbase, "browser-1").unwrap();
    assert_eq!(close.method, "PATCH");
    assert_eq!(
        close.url.as_str(),
        "https://api.browser-use.com/api/v3/browsers/browser-1"
    );
    assert_eq!(close.body["action"].as_str(), Some("stop"));
    let direct_create = browser_session_create_request(&browserbase, "task-1", &json!({}));
    assert!(direct_create.body.get("timeout").is_none());
    assert!(direct_create.body.get("proxyCountryCode").is_none());
    assert_eq!(
        direct_create.features["managed_mode"].as_bool(),
        Some(false)
    );
    let managed_create =
        browser_session_create_request(&browserbase, "task-1", &json!({"managedMode": true}));
    assert_eq!(managed_create.body["timeout"].as_u64(), Some(5));
    assert_eq!(managed_create.body["proxyCountryCode"].as_str(), Some("us"));
    assert_eq!(
        managed_create.features["managed_mode"].as_bool(),
        Some(true)
    );

    browserbase.provider_type = "firecrawl".into();
    browserbase.base_url = "https://api.firecrawl.dev".into();
    browserbase.project_id.clear();
    assert_eq!(
        browser_session_create_url(&browserbase).unwrap().as_str(),
        "https://api.firecrawl.dev/v2/browser"
    );
    let firecrawl_create = browser_session_create_request(&browserbase, "task-1", &json!({}));
    assert_eq!(firecrawl_create.body["ttl"].as_u64(), Some(300));
    assert_eq!(firecrawl_create.features["firecrawl"].as_bool(), Some(true));
    let firecrawl_custom =
        browser_session_create_request(&browserbase, "task-1", &json!({"ttl": 120}));
    assert_eq!(firecrawl_custom.body["ttl"].as_u64(), Some(120));
    let close = browser_session_close_request(&browserbase, "firecrawl-session").unwrap();
    assert_eq!(close.method, "DELETE");
    assert_eq!(
        close.url.as_str(),
        "https://api.firecrawl.dev/v2/browser/firecrawl-session"
    );
}

