#[tokio::test]
async fn browserbase_session_create_retries_paid_feature_402_like_hermes() {
    let listener = TcpListener::bind("127.0.0.1:0").unwrap();
    let addr = listener.local_addr().unwrap();
    let requests = Arc::new(Mutex::new(Vec::<Value>::new()));
    let requests_for_thread = requests.clone();
    let handle = thread::spawn(move || {
        for (status, body) in [
            (402_u16, json!({"error": "keepAlive requires paid plan"})),
            (402_u16, json!({"error": "proxies require paid plan"})),
            (
                200_u16,
                json!({"id": "bb-session-1", "connectUrl": "wss://browser.example/cdp"}),
            ),
        ] {
            let Ok((mut stream, _)) = listener.accept() else {
                return;
            };
            let _ = stream.set_read_timeout(Some(Duration::from_secs(2)));
            let mut buffer = [0_u8; 8192];
            let mut request_bytes = Vec::new();
            loop {
                let bytes = stream.read(&mut buffer).unwrap_or(0);
                if bytes == 0 {
                    break;
                }
                request_bytes.extend_from_slice(&buffer[..bytes]);
                if request_bytes.windows(4).any(|window| window == b"\r\n\r\n") {
                    let request_text = String::from_utf8_lossy(&request_bytes);
                    let content_length = request_text
                        .lines()
                        .find_map(|line| {
                            line.strip_prefix("Content-Length:")
                                .or_else(|| line.strip_prefix("content-length:"))
                                .and_then(|value| value.trim().parse::<usize>().ok())
                        })
                        .unwrap_or(0);
                    let header_len = request_bytes
                        .windows(4)
                        .position(|window| window == b"\r\n\r\n")
                        .map(|index| index + 4)
                        .unwrap_or(request_bytes.len());
                    if request_bytes.len().saturating_sub(header_len) >= content_length {
                        let body_bytes = &request_bytes[header_len..];
                        let parsed = serde_json::from_slice::<Value>(body_bytes).unwrap();
                        requests_for_thread.lock().unwrap().push(parsed);
                        break;
                    }
                }
            }
            let body = body.to_string();
            let response = format!(
                "HTTP/1.1 {status} TEST\r\nContent-Type: application/json\r\nContent-Length: {}\r\nConnection: close\r\n\r\n{}",
                body.as_bytes().len(),
                body
            );
            stream.write_all(response.as_bytes()).unwrap();
        }
    });

    let dir = std::env::temp_dir().join(format!(
        "synthchat-browserbase-create-fallback-{}",
        new_id("test")
    ));
    let store = AppStore::new(dir.join("state.json")).unwrap();
    store
        .set_browser_providers(vec![BrowserProvider {
            id: "bb".into(),
            name: "Browserbase".into(),
            provider_type: "browserbase".into(),
            base_url: format!("http://{addr}/v1"),
            api_key_env: String::new(),
            api_key: Some("key".into()),
            project_id: "project".into(),
            record_sessions: false,
            enabled: true,
            timeout_seconds: 5,
        }])
        .unwrap();

    let text = browser_create_session_tool(&store, "run-browserbase-fallback", &json!({}))
        .await
        .unwrap();
    handle.join().unwrap();
    let value: Value = serde_json::from_str(&text).unwrap();
    assert_eq!(value["sessionId"].as_str(), Some("bb-session-1"));
    assert_eq!(value["cdpUrl"].as_str(), Some("wss://browser.example/cdp"));
    assert_eq!(value["features"]["keep_alive"].as_bool(), Some(false));
    assert_eq!(value["features"]["proxies"].as_bool(), Some(false));
    assert_eq!(value["fallbacks"].as_array().unwrap().len(), 2);

    let bodies = requests.lock().unwrap().clone();
    assert_eq!(bodies.len(), 3);
    assert_eq!(bodies[0]["projectId"].as_str(), Some("project"));
    assert_eq!(bodies[0]["keepAlive"].as_bool(), Some(true));
    assert_eq!(bodies[0]["proxies"].as_bool(), Some(true));
    assert!(bodies[1].get("keepAlive").is_none());
    assert_eq!(bodies[1]["proxies"].as_bool(), Some(true));
    assert!(bodies[2].get("keepAlive").is_none());
    assert!(bodies[2].get("proxies").is_none());
}

#[tokio::test]
async fn browser_use_session_create_preserves_direct_payload_and_external_call_id() {
    let listener = TcpListener::bind("127.0.0.1:0").unwrap();
    let addr = listener.local_addr().unwrap();
    let request = Arc::new(Mutex::new(String::new()));
    let request_for_thread = request.clone();
    let handle = thread::spawn(move || {
        let Ok((mut stream, _)) = listener.accept() else {
            return;
        };
        let _ = stream.set_read_timeout(Some(Duration::from_secs(2)));
        let mut buffer = [0_u8; 8192];
        let mut request_bytes = Vec::new();
        loop {
            let bytes = stream.read(&mut buffer).unwrap_or(0);
            if bytes == 0 {
                break;
            }
            request_bytes.extend_from_slice(&buffer[..bytes]);
            if request_bytes.windows(4).any(|window| window == b"\r\n\r\n") {
                let request_text = String::from_utf8_lossy(&request_bytes);
                let content_length = request_text
                    .lines()
                    .find_map(|line| {
                        line.strip_prefix("Content-Length:")
                            .or_else(|| line.strip_prefix("content-length:"))
                            .and_then(|value| value.trim().parse::<usize>().ok())
                    })
                    .unwrap_or(0);
                let header_len = request_bytes
                    .windows(4)
                    .position(|window| window == b"\r\n\r\n")
                    .map(|index| index + 4)
                    .unwrap_or(request_bytes.len());
                if request_bytes.len().saturating_sub(header_len) >= content_length {
                    break;
                }
            }
        }
        *request_for_thread.lock().unwrap() = String::from_utf8_lossy(&request_bytes).to_string();
        let body = json!({"id": "browser-use-session-1", "cdpUrl": "wss://browser.example/use"})
            .to_string();
        let response = format!(
            "HTTP/1.1 200 OK\r\nContent-Type: application/json\r\nx-external-call-id: call-123\r\nContent-Length: {}\r\nConnection: close\r\n\r\n{}",
            body.as_bytes().len(),
            body
        );
        stream.write_all(response.as_bytes()).unwrap();
    });

    let dir = std::env::temp_dir().join(format!("synthchat-browser-use-create-{}", new_id("test")));
    let store = AppStore::new(dir.join("state.json")).unwrap();
    store
        .set_browser_providers(vec![BrowserProvider {
            id: "browser-use-main".into(),
            name: "Browser Use".into(),
            provider_type: "browser-use".into(),
            base_url: format!("http://{addr}/api/v3"),
            api_key_env: String::new(),
            api_key: Some("browser-use-key".into()),
            project_id: String::new(),
            record_sessions: false,
            enabled: true,
            timeout_seconds: 5,
        }])
        .unwrap();

    let text = browser_create_session_tool(&store, "run-browser-use-create", &json!({}))
        .await
        .unwrap();
    handle.join().unwrap();
    let value: Value = serde_json::from_str(&text).unwrap();
    assert_eq!(value["sessionId"].as_str(), Some("browser-use-session-1"));
    assert_eq!(value["external_call_id"].as_str(), Some("call-123"));
    assert_eq!(value["features"]["managed_mode"].as_bool(), Some(false));

    let request_text = request.lock().unwrap().clone();
    assert!(request_text.starts_with("POST /api/v3/browsers "));
    assert!(request_text
        .to_ascii_lowercase()
        .contains("x-browser-use-api-key: browser-use-key"));
    let body_text = request_text.split("\r\n\r\n").nth(1).unwrap_or("");
    let body: Value = serde_json::from_str(body_text).unwrap();
    assert!(body.get("timeout").is_none());
    assert!(body.get("proxyCountryCode").is_none());
}

