#[test]
fn tool_search_and_describe_expose_available_tool_catalog() {
    let dir = std::env::temp_dir().join(format!("synthchat-tool-search-{}", new_id("test")));
    fs::create_dir_all(&dir).unwrap();
    let path = dir.join("state.json");
    let store = AppStore::new(path).unwrap();
    let agent = AgentDefinition::default();
    store
        .set_vision_providers(vec![VisionProvider {
            id: "vision".into(),
            name: "Vision".into(),
            provider_type: "openai-compatible".into(),
            base_url: "https://vision.example/v1".into(),
            api_key_env: String::new(),
            api_key: None,
            model: "vision-model".into(),
            enabled: true,
            timeout_seconds: 10,
        }])
        .unwrap();
    store
        .set_tool_definitions(vec![ToolDefinition {
            name: "ai.exa/exa.search-docs".into(),
            display_name: "search-docs".into(),
            description: "Search Exa docs".into(),
            source: "mcp".into(),
            server_id: "ai.exa/exa".into(),
            tool_name: "search-docs".into(),
            input_schema: json!({"type": "object", "properties": {"query": {"type": "string"}}}),
            requires_approval: false,
        }])
        .unwrap();

    let search = tool_search_tool(
        &store,
        &agent,
        &json!({"query": "visual browser screenshot", "limit": 5}),
        ToolExecutionContext::Interactive,
    )
    .unwrap();
    let search: Value = serde_json::from_str(&search).unwrap();
    assert_eq!(search["success"], true);
    assert!(search["total_available"].as_u64().unwrap() >= search["count"].as_u64().unwrap());
    assert_eq!(search["totalAvailable"], search["total_available"]);
    assert_eq!(search["searchMode"], "bm25");
    assert!(search["retrieval"]["queryTokens"]
        .as_array()
        .unwrap()
        .iter()
        .any(|term| term == "vision"));
    assert!(search["deferredTokens"].as_u64().unwrap() > 0);
    assert_eq!(
        search["retrieval"]["deferredTokens"],
        search["deferredTokens"]
    );
    assert_eq!(search["retrieval"]["thresholdTokens"], 20_000);
    let names = search["matches"]
        .as_array()
        .unwrap()
        .iter()
        .filter_map(|entry| entry["name"].as_str())
        .collect::<Vec<_>>();
    assert!(names.contains(&"browser_vision"));

    let description = tool_describe_tool(
        &store,
        &agent,
        &json!({"name": "tool_search"}),
        ToolExecutionContext::Interactive,
    )
    .unwrap();
    let description: Value = serde_json::from_str(&description).unwrap();
    assert_eq!(description["success"], true);
    assert_eq!(description["source"], "internal");
    assert_eq!(description["source_name"], "internal");
    assert_eq!(description["sourceName"], "internal");
    assert!(description["parameters"].is_object());
    assert_eq!(description["schema"], description["parameters"]);
    assert!(description["payloadShape"]
        .as_str()
        .unwrap()
        .contains("query"));
    let call_description = tool_describe_tool(
        &store,
        &agent,
        &json!({"name": "tool_call"}),
        ToolExecutionContext::Interactive,
    )
    .unwrap();
    let call_description: Value = serde_json::from_str(&call_description).unwrap();
    assert!(call_description["payloadShape"]
        .as_str()
        .unwrap()
        .contains("arguments"));
    assert_eq!(
        call_description["payloadSchema"]["properties"]["name"]["type"],
        "string"
    );
    assert_eq!(
        call_description["schema"],
        call_description["payloadSchema"]
    );
    let visible_tools =
        visible_tool_definitions_for_agent(&store, &agent, ToolExecutionContext::Interactive)
            .unwrap();
    assert!(visible_tools.iter().any(|tool| {
        tool.name == "ai.exa/exa.search-docs"
            && tool.source == "mcp"
            && tool.tool_name == "search-docs"
    }));
    let mcp_decision = parse_agent_decision(
        r#"{"action":"tool","tool":"ai.exa/exa.search-docs","payload":{"query":"planner validation"}}"#,
    );
    assert!(
        validated_tool_requests_from_decision_with_error(&mcp_decision, &visible_tools).is_ok()
    );
    let bridge_definition = visible_tools
        .iter()
        .find(|tool| tool.name == "tool_call")
        .unwrap();
    assert_eq!(
        bridge_definition.input_schema["properties"]["arguments"]["type"][0],
        "object"
    );
    let bridge_error = validated_tool_requests_from_decision_with_error(
        &parse_agent_decision(r#"{"action":"tool","tool":"tool_call","payload":{"arguments":{}}}"#),
        &visible_tools,
    )
    .unwrap_err();
    assert_eq!(
        bridge_error.kind(),
        ToolCallValidationErrorKind::SchemaValidation
    );
    assert!(bridge_error.message().contains("anyOf"));
    assert!(bridge_error.message().contains("payload.name is required"));
    assert_eq!(tool_event_kind("__internal", "tool_search", None), "search");
    assert_eq!(tool_event_kind("__internal", "tool_describe", None), "read");
    assert_eq!(tool_event_kind("__internal", "tool_call", None), "execute");

    let mcp_search = tool_search_tool(
        &store,
        &agent,
        &json!({"query": "mcp_ai_exa_exa_search_docs", "limit": 5}),
        ToolExecutionContext::Interactive,
    )
    .unwrap();
    let mcp_search: Value = serde_json::from_str(&mcp_search).unwrap();
    let mcp_entry = mcp_search["matches"]
        .as_array()
        .unwrap()
        .iter()
        .find(|entry| entry["name"] == "ai.exa/exa.search-docs")
        .unwrap();
    assert_eq!(mcp_entry["aliases"][0], "mcp_ai_exa_exa_search_docs");
    assert_eq!(mcp_entry["source_name"], "ai.exa/exa");

    let mcp_description = tool_describe_tool(
        &store,
        &agent,
        &json!({"name": "mcp_ai_exa_exa_search_docs"}),
        ToolExecutionContext::Interactive,
    )
    .unwrap();
    let mcp_description: Value = serde_json::from_str(&mcp_description).unwrap();
    assert_eq!(mcp_description["serverId"], "ai.exa/exa");
    assert_eq!(mcp_description["toolName"], "search-docs");
    assert_eq!(
        mcp_description["parameters"]["properties"]["query"]["type"],
        "string"
    );
    assert_eq!(mcp_description["schema"], mcp_description["parameters"]);

    let _ = fs::remove_dir_all(dir);
}

