#[tokio::test]
async fn x_search_uses_xai_responses_when_credentials_are_configured() {
    let _guard = CHANNEL_DIRECTORY_ENV_LOCK.lock().unwrap();
    let old_xai = env::var_os("XAI_API_KEY");
    let old_xai_base = env::var_os("XAI_BASE_URL");
    env::set_var("XAI_API_KEY", "xai-test-key");

    let (base_url, requests, server) = spawn_test_retaindb_http_server(vec![(
        200,
        json!({
            "output_text": "Launch week summary",
            "citations": [{"url": "https://x.com/openai/status/1"}],
            "output": [{
                "content": [{
                    "text": "Launch week summary",
                    "annotations": [{
                        "type": "url_citation",
                        "url": "https://x.com/openai/status/1"
                    }]
                }]
            }]
        }),
    )]);
    env::set_var("XAI_BASE_URL", base_url);
    let dir = std::env::temp_dir().join(format!("synthchat-x-search-responses-{}", new_id("test")));
    let store = AppStore::new(dir.join("state.json")).unwrap();

    let result: Value = serde_json::from_str(
        &x_search_tool(
            &store,
            &json!({
                "query": "launch week",
                "allowed_x_handles": ["@openai"],
                "from_date": "2026-06-01",
                "to_date": "2026-06-03",
                "enable_image_understanding": true
            }),
        )
        .await
        .unwrap(),
    )
    .unwrap();
    assert_eq!(result["success"], true);
    assert_eq!(result["mode"], "xai_responses");
    assert_eq!(result["answer"], "Launch week summary");
    assert_eq!(result["degraded"], false);
    assert_eq!(result["credential_source"], "env:XAI_API_KEY");
    assert_eq!(
        result["citations"][0]["url"],
        "https://x.com/openai/status/1"
    );
    assert_eq!(
        result["inline_citations"][0]["url"],
        "https://x.com/openai/status/1"
    );

    let captured = requests.lock().unwrap();
    let request = captured.first().unwrap();
    assert!(request.starts_with("POST /responses HTTP/1.1"));
    assert!(request.contains("authorization: Bearer xai-test-key"));
    assert!(request.contains("\"model\":\"grok-4.20-reasoning\""));
    assert!(request.contains("\"type\":\"x_search\""));
    assert!(request.contains("\"allowed_x_handles\":[\"openai\"]"));
    assert!(request.contains("\"from_date\":\"2026-06-01\""));
    assert!(request.contains("\"to_date\":\"2026-06-03\""));
    assert!(request.contains("\"enable_image_understanding\":true"));

    server.join().unwrap();
    restore_test_env("XAI_API_KEY", old_xai);
    restore_test_env("XAI_BASE_URL", old_xai_base);
    let _ = fs::remove_dir_all(dir);
}

#[test]
fn x_search_validates_date_ranges_before_http_call() {
    let invalid = xai_search_tool_definition(&json!({
        "query": "launch week",
        "from_date": "2026-13-01"
    }))
    .unwrap_err()
    .to_string();
    assert!(invalid.contains("from_date must be YYYY-MM-DD"));

    let inverted = xai_search_tool_definition(&json!({
        "query": "launch week",
        "from_date": "2026-06-03",
        "to_date": "2026-06-01"
    }))
    .unwrap_err()
    .to_string();
    assert!(inverted.contains("must be on or before"));

    let future = (chrono::Utc::now() + chrono::Duration::days(2))
        .date_naive()
        .format("%Y-%m-%d")
        .to_string();
    let future_error = xai_search_tool_definition(&json!({
        "query": "launch week",
        "from_date": future
    }))
    .unwrap_err()
    .to_string();
    assert!(future_error.contains("is in the future"));
    assert!(future_error.contains("X Search only indexes past posts"));
}

