#[test]
fn text_to_speech_helpers_normalize_url_format_and_json_audio() {
    let mut provider = LlmProvider {
        id: "openai".into(),
        name: "OpenAI".into(),
        provider_type: "openai-compatible".into(),
        preset: None,
        base_url: "https://api.example.test/v1/chat/completions".into(),
        append_chat_path: true,
        api_key_env: String::new(),
        api_key: Some("test".into()),
        model: "gpt-4o-mini-tts".into(),
        enabled: true,
        timeout_seconds: 10,
        request_timeout_seconds: None,
        stale_timeout_seconds: None,
        models: json!({}),
        prompt_cache_mode: "off".into(),
        prompt_cache_ttl: "5m".into(),
        prompt_cache_layout: "system_tools".into(),
    };
    assert_eq!(
        audio_speech_url(&provider).unwrap().as_str(),
        "https://api.example.test/v1/audio/speech"
    );
    provider.base_url = "https://api.example.test/v1/audio/speech".into();
    assert_eq!(
        audio_speech_url(&provider).unwrap().as_str(),
        "https://api.example.test/v1/audio/speech"
    );
    assert_eq!(
        mistral_audio_speech_url("https://api.mistral.ai/v1")
            .unwrap()
            .as_str(),
        "https://api.mistral.ai/v1/audio/speech"
    );
    assert_eq!(
        mistral_audio_speech_url("https://api.mistral.ai/v1/audio/transcriptions")
            .unwrap()
            .as_str(),
        "https://api.mistral.ai/v1/audio/speech"
    );
    assert_eq!(
        gemini_generate_content_url(
            "https://generativelanguage.googleapis.com/v1beta",
            "gemini-2.5-flash-preview-tts"
        )
        .unwrap()
        .as_str(),
        "https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash-preview-tts:generateContent"
    );
    assert_eq!(
        elevenlabs_text_to_speech_url("https://api.elevenlabs.io/v1", "voice-123")
            .unwrap()
            .as_str(),
        "https://api.elevenlabs.io/v1/text-to-speech/voice-123"
    );

    assert_eq!(tts_response_format(&json!({})).unwrap(), "mp3");
    assert_eq!(
        tts_response_format(&json!({"response_format": "WAV"})).unwrap(),
        "wav"
    );
    assert!(tts_response_format(&json!({"format": "exe"})).is_err());

    let audio = decode_tts_json_response(br#"{"audio":"AQID"}"#).unwrap();
    assert_eq!(audio, vec![1, 2, 3]);
    let mistral_audio = decode_mistral_tts_json_response(br#"{"audio_data":"BAUG"}"#).unwrap();
    assert_eq!(mistral_audio, vec![4, 5, 6]);
    let gemini_pcm = decode_gemini_tts_pcm_response(
        br#"{"candidates":[{"content":{"parts":[{"inlineData":{"mimeType":"audio/L16;codec=pcm;rate=24000","data":"AQIDBA=="}}]}}]}"#,
    )
    .unwrap();
    assert_eq!(gemini_pcm, vec![1, 2, 3, 4]);
    let wav = wrap_pcm_as_wav(&gemini_pcm, 24_000, 1, 2).unwrap();
    assert_eq!(&wav[0..4], b"RIFF");
    assert_eq!(&wav[8..12], b"WAVE");
    assert_eq!(&wav[36..40], b"data");
    assert_eq!(&wav[44..], &[1, 2, 3, 4]);
    let minimax_audio = decode_minimax_tts_json_response(
        br#"{"base_resp":{"status_code":0},"data":{"audio":"01020304"}}"#,
    )
    .unwrap();
    assert_eq!(minimax_audio, vec![1, 2, 3, 4]);
    assert!(ensure_tencent_silk_audio(b"\x02#!SILK_V3\"\0payload").is_ok());
    assert!(ensure_tencent_silk_audio(b"not silk").is_err());
}

