    provider.api_key = Some("xai-key".into());
    provider.model = "grok-stt".into();
    provider.timeout_seconds = 10;

    let result: Value = serde_json::from_str(
        &xai_transcribe_audio(
            &store,
            &AgentDefinition::default(),
            "run-xai-stt",
            &provider,
            "data:audio/wav;base64,AQID",
            &json!({
                "language": "en",
                "diarize": true
            }),
        )
        .await
        .unwrap(),
    )
    .unwrap();

    assert_eq!(result["success"], true);
