fn test_local_stt_stdout_command(text: &str) -> String {
    if cfg!(target_os = "windows") {
        format!(
            "powershell -NoProfile -Command Write-Output '{}'",
            text.replace('\'', "''")
        )
    } else {
        format!("printf '{}'", text.replace('\'', "'\\''"))
    }
}

fn test_local_tts_output_command() -> String {
    if cfg!(target_os = "windows") {
        "powershell -NoProfile -Command Copy-Item -LiteralPath {input_path} -Destination {output_path}"
            .into()
    } else {
        "test -s {input_path} && cp {input_path} {output_path}".into()
    }
}

#[test]
fn whisper_hallucination_filter_matches_hermes_silence_phrases() {
    assert!(is_whisper_hallucination("Thank you."));
    assert!(is_whisper_hallucination("Thank you. Thank you. You"));
    assert!(is_whisper_hallucination("ご視聴ありがとうございました"));
    assert!(!is_whisper_hallucination(
        "Please send the deployment report."
    ));
}

#[test]
fn split_wav_for_transcription_writes_valid_bounded_chunks() {
    let dir = std::env::temp_dir().join(format!("synthchat-wav-chunks-{}", new_id("test")));
    std::fs::create_dir_all(&dir).unwrap();
    let wav_path = dir.join("recording.wav");
    std::fs::write(&wav_path, test_pcm_wav_bytes(1_000)).unwrap();

    let chunks = split_wav_for_transcription(&wav_path, 144).unwrap();

    assert!(chunks.len() > 1);
    for chunk_path in &chunks {
        let bytes = std::fs::read(chunk_path).unwrap();
        assert!(bytes.len() <= 144);
        assert_eq!(&bytes[0..4], b"RIFF");
        assert_eq!(&bytes[8..12], b"WAVE");
        assert_eq!(test_wav_u32(&bytes, 4) as usize, bytes.len() - 8);
        assert_eq!(test_wav_u32(&bytes, 40) as usize, bytes.len() - 44);
        assert_eq!(test_wav_u32(&bytes, 40) % 2, 0);
        let _ = std::fs::remove_file(chunk_path);
    }
    let _ = std::fs::remove_dir_all(dir);
}

fn test_pcm_wav_bytes(data_len: usize) -> Vec<u8> {
    let mut bytes = Vec::new();
    bytes.extend_from_slice(b"RIFF");
    bytes.extend_from_slice(&(36u32 + data_len as u32).to_le_bytes());
    bytes.extend_from_slice(b"WAVE");
    bytes.extend_from_slice(b"fmt ");
    bytes.extend_from_slice(&16u32.to_le_bytes());
    bytes.extend_from_slice(&1u16.to_le_bytes());
    bytes.extend_from_slice(&1u16.to_le_bytes());
    bytes.extend_from_slice(&16_000u32.to_le_bytes());
    bytes.extend_from_slice(&32_000u32.to_le_bytes());
    bytes.extend_from_slice(&2u16.to_le_bytes());
    bytes.extend_from_slice(&16u16.to_le_bytes());
    bytes.extend_from_slice(b"data");
    bytes.extend_from_slice(&(data_len as u32).to_le_bytes());
    bytes.extend(std::iter::repeat(1u8).take(data_len));
    bytes
}

fn test_wav_u32(bytes: &[u8], offset: usize) -> u32 {
    u32::from_le_bytes([
        bytes[offset],
        bytes[offset + 1],
        bytes[offset + 2],
        bytes[offset + 3],
    ])
}

