#[test]
fn exported_run_bundle_includes_child_runs_and_artifacts() {
    let dir = std::env::temp_dir().join(format!("synthchat-agent-export-{}", new_id("test")));
    let path = dir.join("state.json");
    let store = AppStore::new(path).unwrap();
    let mut parent = AgentRunRecord::new("conv".into(), "persona".into(), "agent".into());
    parent.user_request = "parent task".into();
    store.save_agent_run(parent.clone()).unwrap();
    store
        .append_message(ChatMessage::new(
            "conv".into(),
            "user",
            "parent task".into(),
            "desktop",
        ))
        .unwrap();
    store
        .append_message(ChatMessage::new(
            "conv".into(),
            "assistant",
            "<REASONING_SCRATCHPAD>plan</REASONING_SCRATCHPAD>done".into(),
            "desktop-agent",
        ))
        .unwrap();

    let mut child = AgentRunRecord::new("conv".into(), "persona".into(), "agent".into());
    child.parent_run_id = Some(parent.run_id.clone());
    child.subagent_index = Some(1);
    store.save_agent_run(child).unwrap();
    store
        .save_tool_artifact(&parent.run_id, "notes", "artifact text")
        .unwrap();

    let bundle = export_agent_run_bundle(&store, parent.run_id.clone()).unwrap();
    let value: Value = serde_json::from_str(&bundle).unwrap();
    assert_eq!(value["run"]["runId"], parent.run_id);
    assert_eq!(value["childRuns"].as_array().unwrap().len(), 1);
    assert_eq!(value["artifacts"].as_array().unwrap().len(), 1);
    assert_eq!(value["trajectory"]["completed"], false);
    let trajectory = value["trajectory"]["conversations"].as_array().unwrap();
    assert_eq!(trajectory[0]["from"], "human");
    assert_eq!(trajectory[0]["value"], "parent task");
    assert_eq!(trajectory[1]["from"], "gpt");
    assert!(trajectory[1]["value"]
        .as_str()
        .unwrap()
        .contains("<think>plan</think>"));
    assert_eq!(
        list_agent_run_artifacts(&store, parent.run_id)
            .unwrap()
            .len(),
        1
    );

    let _ = fs::remove_dir_all(dir);
}

#[test]
fn artifact_index_filters_current_conversation_and_supports_global_scope() {
    let dir = std::env::temp_dir().join(format!("synthchat-artifact-index-{}", new_id("test")));
    let path = dir.join("state.json");
    let store = AppStore::new(path).unwrap();
    let persona = store.persona(None).unwrap();
    let current = store
        .create_conversation(Some("Current".into()), Some(persona.id.clone()))
        .unwrap();
    let other = store
        .create_conversation(Some("Other".into()), Some(persona.id.clone()))
        .unwrap();
    let current_run = AgentRunRecord::new(
        current.id.clone(),
        persona.id.clone(),
        current.agent_id.clone(),
    );
    let other_run =
        AgentRunRecord::new(other.id.clone(), persona.id.clone(), other.agent_id.clone());
    store.save_agent_run(current_run.clone()).unwrap();
    store.save_agent_run(other_run.clone()).unwrap();
    store
        .save_tool_artifact(&current_run.run_id, "notes", "current artifact")
        .unwrap();
    store
        .save_tool_artifact(&other_run.run_id, "notes", "other artifact")
        .unwrap();

    let current_index = list_agent_artifact_index(&store, Some(&current.id), 10).unwrap();
    assert_eq!(current_index.len(), 1);
    assert_eq!(current_index[0]["runId"], current_run.run_id);

    let current_text = handle_artifacts_control_command(&store, &current, "").unwrap();
    assert!(current_text.contains("current artifact"));
    assert!(!current_text.contains("other artifact"));

    let global_text = handle_artifacts_control_command(&store, &current, "all 10").unwrap();
    assert!(global_text.contains("current artifact"));
    assert!(global_text.contains("other artifact"));

    let _ = fs::remove_dir_all(dir);
}

#[test]
fn subagent_failure_diagnostic_artifact_captures_child_state() {
    let dir =
        std::env::temp_dir().join(format!("synthchat-subagent-diagnostic-{}", new_id("test")));
    let path = dir.join("state.json");
    let store = AppStore::new(path).unwrap();
    let persona = store.persona(None).unwrap();
    let parent_conversation = store
        .create_conversation(Some("Parent".into()), Some(persona.id.clone()))
        .unwrap();
    let child_conversation = store
        .create_conversation(Some("Child".into()), Some(persona.id.clone()))
        .unwrap();
    let parent_run = AgentRunRecord::new(
        parent_conversation.id.clone(),
        persona.id.clone(),
        parent_conversation.agent_id.clone(),
    );
    store.save_agent_run(parent_run.clone()).unwrap();
    let mut child_run = AgentRunRecord::new(
        child_conversation.id.clone(),
        persona.id.clone(),
        child_conversation.agent_id.clone(),
    );
    child_run.parent_run_id = Some(parent_run.run_id.clone());
    child_run.subagent_index = Some(1);
    child_run.state = "failed".into();
    child_run.error = Some("llm error: invalid llm response".into());
    child_run
        .tool_events
        .push(json!({"tool": "terminal", "status": "failed"}));
    child_run = store.save_agent_run(child_run).unwrap();
    store
        .append_message(ChatMessage::new(
            child_conversation.id.clone(),
            "assistant",
            "partial child answer".into(),
            "desktop-agent",
        ))
        .unwrap();
    let request = delegation::DelegateTaskRequest {
        task: "debug response body decoding".into(),
        role: "subagent".into(),
        toolsets: vec!["file".into()],
        can_delegate: false,
        max_iterations: 3,
        acp_command: String::new(),
        acp_args: Vec::new(),
        acp_session_id: String::new(),
        acp_session_mode: String::new(),
    };

    let artifact_path = delegation::save_subagent_failure_diagnostic_artifact(
        &store,
        &parent_run.run_id,
        &child_conversation.id,
        Some(&child_run),
        &request,
        "llm error: invalid llm response",
        "synthchat",
    )
    .unwrap()
    .unwrap();
    let content = fs::read_to_string(&artifact_path).unwrap();
    let diagnostic: Value = serde_json::from_str(&content).unwrap();

    assert_eq!(diagnostic["kind"], "subagentFailureDiagnostic");
    assert_eq!(diagnostic["parentRunId"], parent_run.run_id);
    assert_eq!(diagnostic["childRun"]["runId"], child_run.run_id);
    assert_eq!(diagnostic["childRun"]["state"], "failed");
    assert_eq!(
        diagnostic["request"]["task"],
        "debug response body decoding"
    );
    assert_eq!(
        diagnostic["recentMessages"][0]["content"],
        "partial child answer"
    );
    assert_eq!(
        store
            .tool_artifacts_for_run(&parent_run.run_id)
            .unwrap()
            .len(),
        1
    );

    let _ = fs::remove_dir_all(dir);
}

#[test]
fn llm_attempt_event_records_transport_diagnostics() {
    let dir = std::env::temp_dir().join(format!("synthchat-llm-attempt-{}", new_id("test")));
    let path = dir.join("state.json");
    let store = AppStore::new(path).unwrap();
    let run = AgentRunRecord::new("conv".into(), "persona".into(), "agent".into());
    store.save_agent_run(run.clone()).unwrap();
    let provider = LlmProvider {
        id: "provider-a".into(),
        name: "Provider A".into(),
        provider_type: "openai-compatible".into(),
        preset: None,
        base_url: "https://example.test/v1".into(),
        append_chat_path: true,
        api_key_env: String::new(),
        api_key: None,
        model: "model-a".into(),
        enabled: true,
        timeout_seconds: 30,
        request_timeout_seconds: None,
        stale_timeout_seconds: None,
        models: json!({}),
        prompt_cache_mode: "off".into(),
        prompt_cache_ttl: "5m".into(),
        prompt_cache_layout: "native".into(),
    };
    let reply = crate::llm::LlmReply {
        content: "ok".into(),
        prompt_tokens: 10,
        completion_tokens: 5,
        cache_read_tokens: 2,
        cache_write_tokens: 1,
        reasoning_tokens: 3,
        provider_id: Some(provider.id.clone()),
        provider_type: Some(provider.provider_type.clone()),
        model: Some(provider.model.clone()),
        base_url: Some(provider.base_url.clone()),
        estimated_cost_usd: Some(0.001),
        cost_status: Some("estimated".into()),
        cost_source: Some("test".into()),
        rate_limit_state: Some(json!({"requests": {"remaining": 9}})),
        transport_diagnostics: Some(json!({
            "transport": "openai_chat",
            "endpoint": "https://example.test/v1/chat/completions",
            "status": 200,
            "elapsedMs": 111,
            "headers": {
                "cf-ray": "ray-test",
                "x-openrouter-provider": "upstream-a"
            }
        })),
        finish_reason: Some("stop".into()),
        provider_data: None,
        failover_attempts: vec![],
    };

    append_llm_attempt_event(
        &store,
        &run.run_id,
        &provider,
        1,
        2,
        123,
        "success",
        None,
        None,
        Some(&reply),
    )
    .unwrap();
    append_llm_attempt_event(
        &store,
        &run.run_id,
        &provider,
        2,
        2,
        45,
        "error",
        Some("rate_limit"),
        Some("provider returned 429"),
        None,
    )
    .unwrap();

    let saved = store.agent_run(&run.run_id).unwrap();
    assert_eq!(saved.phase_events.len(), 2);
    assert_eq!(saved.phase_events[0].phase, "llm_attempt");
    assert_eq!(saved.phase_events[0].detail["outcome"], "success");
    assert_eq!(saved.phase_events[0].detail["elapsedMs"], 123);
    assert_eq!(saved.phase_events[0].detail["finishReason"], "stop");
    assert_eq!(saved.phase_events[0].detail["promptTokens"], 10);
    assert_eq!(
        saved.phase_events[0].detail["rateLimitState"]["requests"]["remaining"],
        9
    );
    assert_eq!(
        saved.phase_events[0].detail["transportDiagnostics"]["headers"]["cf-ray"],
        "ray-test"
    );
    assert_eq!(
        saved.phase_events[0].detail["runnerDiagnostics"]["mode"],
        "non_stream"
    );
    assert_eq!(
        saved.phase_events[0].detail["runnerDiagnostics"]["streaming"],
        false
    );
    assert_eq!(
        saved.phase_events[0].detail["runnerDiagnostics"]["chunks"],
        0
    );
    assert_eq!(
        saved.phase_events[0].detail["runnerDiagnostics"]["ttfbMs"],
        Value::Null
    );
    assert_eq!(
        saved.phase_events[0].detail["runnerDiagnostics"]["elapsedMs"],
        111
    );
    assert_eq!(
        saved.phase_events[0].detail["runnerDiagnostics"]["responseBytes"],
        2
    );
    assert_eq!(
        saved.phase_events[0].detail["runnerDiagnostics"]["staleTimeoutSeconds"],
        30
    );
    assert_eq!(
        saved.phase_events[0].detail["runnerDiagnostics"]["httpStatus"],
        200
    );
    assert_eq!(saved.phase_events[1].detail["outcome"], "error");
    assert_eq!(saved.phase_events[1].detail["kind"], "rate_limit");
    assert_eq!(
        saved.phase_events[1].detail["message"],
        "provider returned 429"
    );
    assert_eq!(
        saved.phase_events[1].detail["transportDiagnostics"]["httpStatus"],
        429
    );
    assert_eq!(
        saved.phase_events[1].detail["runnerDiagnostics"]["outcome"],
        "error"
    );
    assert_eq!(
        saved.phase_events[1].detail["runnerDiagnostics"]["httpStatus"],
        429
    );
    assert_eq!(
        saved.phase_events[1].detail["runnerDiagnostics"]["elapsedMs"],
        45
    );
    assert_eq!(
        saved.phase_events[1].detail["recoveryHints"]["action"],
        "backoff_or_rotate_credential"
    );
    assert_eq!(
        saved.phase_events[1].detail["recoveryHints"]["retryable"],
        true
    );
    assert_eq!(
        saved.phase_events[1].detail["classifiedError"]["reason"],
        "rate_limit"
    );
    assert_eq!(
        saved.phase_events[1].detail["classifiedError"]["statusCode"],
        429
    );
    assert_eq!(
        saved.phase_events[1].detail["classifiedError"]["model"],
        "model-a"
    );

    let _ = fs::remove_dir_all(dir);
}

#[test]
fn llm_failure_diagnostic_artifact_captures_failover_context() {
    let dir = std::env::temp_dir().join(format!("synthchat-llm-failure-diag-{}", new_id("test")));
    let path = dir.join("state.json");
    let store = AppStore::new(path).unwrap();
    let mut run = AgentRunRecord::new("conv".into(), "persona".into(), "agent".into());
    run.state = "running".into();
    store.save_agent_run(run.clone()).unwrap();
    append_parent_phase_event(
        &store,
        &run.run_id,
        "llm_attempt",
        json!({
            "providerId": "provider-a",
            "outcome": "error",
            "kind": "transport",
            "message": "invalid llm response"
        }),
    )
    .unwrap();
    let provider = LlmProvider {
        id: "provider-a".into(),
        name: "Provider A".into(),
        provider_type: "openai-compatible".into(),
        preset: Some("openai".into()),
        base_url: "https://example.test/v1".into(),
        append_chat_path: true,
        api_key_env: "OPENAI_API_KEY".into(),
        api_key: Some("sk-secret-test".into()),
        model: "model-a".into(),
        enabled: true,
        timeout_seconds: 30,
        request_timeout_seconds: None,
        stale_timeout_seconds: None,
        models: json!({}),
        prompt_cache_mode: "off".into(),
        prompt_cache_ttl: "5m".into(),
        prompt_cache_layout: "native".into(),
    };
    let attempts = vec![crate::llm::LlmFailoverAttempt {
        provider_id: provider.id.clone(),
        model: provider.model.clone(),
        kind: "transport".into(),
        message: "llm error: invalid llm response: error decoding response body sk-secret-test"
            .into(),
    }];
    let failed_providers = vec![json!({
        "providerId": provider.id,
        "providerType": provider.provider_type,
        "model": provider.model,
        "kind": "transport",
        "message": "invalid llm response"
    })];
    let error =
        AppError::Llm("invalid llm response: error decoding response body sk-secret-test".into());

    let artifact_path = llm_recovery::save_llm_failure_diagnostic_artifact(
        &store,
        &run.run_id,
        &[provider],
        &attempts,
        &failed_providers,
        &error,
    )
    .unwrap()
    .unwrap();
    let content = fs::read_to_string(&artifact_path).unwrap();
    let diagnostic: Value = serde_json::from_str(&content).unwrap();

    assert_eq!(diagnostic["kind"], "llmFailureDiagnostic");
    assert_eq!(diagnostic["runId"], run.run_id);
    assert_eq!(diagnostic["errorKind"], "transport");
    assert_eq!(diagnostic["attempts"][0]["providerId"], "provider-a");
    assert_eq!(diagnostic["recentPhaseEvents"][0]["phase"], "llm_attempt");
    assert_eq!(diagnostic["providers"][0]["apiKey"], Value::Null);
    assert!(!content.contains("sk-secret-test"));
    assert_eq!(store.tool_artifacts_for_run(&run.run_id).unwrap().len(), 1);

    let _ = fs::remove_dir_all(dir);
}

#[test]
fn workflow_graph_bootstrap_marks_queue_and_group_room_nodes() {
    let mut run = AgentRunRecord::new("conv".into(), "persona".into(), "agent".into());
    let request = SendChatRequest {
        conversation_id: Some("conv".into()),
        persona_id: Some("persona".into()),
        agent_id: None,
        content: "hello".into(),
        provider_data: Some(json!({
            "source": "matrix",
            "source_context": {
                "room_id": "!room:example.org",
                "thread_id": "thread-1",
                "conversation_type": "room"
            }
        })),
        queue_item_id: Some("queue-1".into()),
    };

    push_workflow_graph_bootstrap(
        &mut run,
        &request,
        "matrix",
        ToolExecutionContext::Interactive,
        WorkflowMode::ChatTurn,
    );

    let graph = run.workflow_graph.as_ref().unwrap();
    assert_eq!(graph["schema"], SYNTHGRAPH_WORKFLOW_SCHEMA);
    assert_eq!(graph["requestSource"], "matrix");
    assert_eq!(graph["request_source"], "matrix");
    assert_eq!(graph["toolContext"], "interactive");
    assert_eq!(graph["tool_context"], "interactive");
    assert_eq!(graph["currentNode"], "planner");
    assert_eq!(graph["current_node"], "planner");
    assert_eq!(graph["currentStatus"], "pending");
    assert_eq!(graph["current_status"], "pending");
    assert_eq!(graph["lastEventSequence"], 0);
    assert_eq!(graph["last_event_sequence"], 0);
    let transitions = graph["transitions"].as_array().unwrap();
    assert_eq!(transitions.len(), 2);
    assert_eq!(transitions[0]["from"], "queue");
    assert_eq!(transitions[0]["to"], "group_room");
    assert_eq!(transitions[0]["reason"], WORKFLOW_REASON_QUEUED_TURN);
    assert_eq!(transitions[0]["detail"]["mode"], "chat_turn");
    assert_eq!(transitions[0]["detail"]["requestSource"], "matrix");
    assert_eq!(transitions[0]["detail"]["request_source"], "matrix");
    assert_eq!(transitions[0]["detail"]["toolContext"], "interactive");
    assert_eq!(transitions[0]["detail"]["tool_context"], "interactive");
    assert_eq!(transitions[0]["detail"]["queueItemId"], "queue-1");
    assert_eq!(
        transitions[0]["detail"]["admission"],
        WORKFLOW_REASON_QUEUED_TURN
    );
    assert_eq!(transitions[0]["detail"]["queueStatus"], "claimed");
    assert_eq!(
        transitions[0]["detail"]["queueLifecycle"],
        "dequeued_for_run"
    );
    assert_eq!(transitions[0]["eventSequence"], 0);
    assert_eq!(transitions[1]["from"], "group_room");
    assert_eq!(transitions[1]["to"], "planner");
    assert_eq!(
        transitions[1]["reason"],
        WORKFLOW_REASON_GROUP_CONTEXT_READY
    );
    assert_eq!(transitions[1]["detail"]["groupRoom"], "context_ready");
    assert_eq!(transitions[1]["eventSequence"], 0);

    let event = run.phase_events.last().unwrap();
    assert_eq!(event.phase, WORKFLOW_PHASE_INITIALIZED);
    assert_eq!(event.detail["schema"], SYNTHGRAPH_WORKFLOW_SCHEMA);
    assert_eq!(event.detail["transitions"].as_array().unwrap().len(), 2);

    let nodes = event.detail["nodes"].as_array().unwrap();
    let queue = nodes.iter().find(|node| node["node"] == "queue").unwrap();
    assert_eq!(queue["status"], "completed");
    assert_eq!(queue["eventSequence"], 0);
    assert_eq!(queue["detail"]["mode"], "chat_turn");
    assert_eq!(queue["detail"]["requestSource"], "matrix");
    assert_eq!(queue["detail"]["request_source"], "matrix");
    assert_eq!(queue["detail"]["toolContext"], "interactive");
    assert_eq!(queue["detail"]["tool_context"], "interactive");
    assert_eq!(queue["detail"]["queueItemId"], "queue-1");
    assert_eq!(queue["detail"]["admission"], WORKFLOW_REASON_QUEUED_TURN);
    assert_eq!(queue["detail"]["queueStatus"], "claimed");
    assert_eq!(queue["detail"]["queueLifecycle"], "dequeued_for_run");

    let group_room = nodes
        .iter()
        .find(|node| node["node"] == "group_room")
        .unwrap();
    assert_eq!(group_room["status"], "completed");
    assert_eq!(group_room["eventSequence"], 0);
    assert_eq!(group_room["detail"]["mode"], "chat_turn");
    assert_eq!(group_room["detail"]["requestSource"], "matrix");
    assert_eq!(group_room["detail"]["request_source"], "matrix");
    assert_eq!(group_room["detail"]["toolContext"], "interactive");
    assert_eq!(group_room["detail"]["tool_context"], "interactive");
    assert_eq!(group_room["detail"]["roomId"], "!room:example.org");
    assert_eq!(group_room["detail"]["threadId"], "thread-1");

    let planner = nodes.iter().find(|node| node["node"] == "planner").unwrap();
    assert_eq!(planner["status"], "pending");
    assert_eq!(planner["eventSequence"], 0);
    assert_eq!(planner["detail"]["mode"], "chat_turn");
    assert_eq!(planner["detail"]["requestSource"], "matrix");
    assert_eq!(planner["detail"]["request_source"], "matrix");
    assert_eq!(planner["detail"]["toolContext"], "interactive");
    assert_eq!(planner["detail"]["tool_context"], "interactive");

    let reviewer = nodes
        .iter()
        .find(|node| node["node"] == "reviewer")
        .unwrap();
    assert_eq!(reviewer["status"], "pending");
    assert_eq!(reviewer["eventSequence"], 0);
    assert_eq!(reviewer["detail"]["mode"], "chat_turn");
    assert_eq!(reviewer["detail"]["requestSource"], "matrix");
    assert_eq!(reviewer["detail"]["request_source"], "matrix");
    assert_eq!(reviewer["detail"]["toolContext"], "interactive");
    assert_eq!(reviewer["detail"]["tool_context"], "interactive");
}

#[test]
fn queue_terminal_workflow_update_preserves_current_node() {
    let dir = std::env::temp_dir().join(format!(
        "synthchat-queue-terminal-workflow-{}",
        new_id("test")
    ));
    fs::create_dir_all(&dir).unwrap();
    let store = AppStore::new(dir.join("state.json")).unwrap();
    let message = ChatMessage::new("conv".into(), "user", "queued terminal".into(), "test");
    let mut queue_item = AgentQueuedRequest::new("conv".into(), "persona".into(), &message);
    queue_item.id = "queue-terminal".into();
    queue_item.status = "completed".into();
    queue_item.completed_at = Some(now_iso());

    let mut run = AgentRunRecord::new("conv".into(), "persona".into(), "agent".into());
    run.queue_item_id = Some(queue_item.id.clone());
    let request = SendChatRequest {
        conversation_id: Some("conv".into()),
        persona_id: Some("persona".into()),
        agent_id: None,
        content: "queued terminal".into(),
        provider_data: None,
        queue_item_id: Some(queue_item.id.clone()),
    };
    push_workflow_graph_bootstrap(
        &mut run,
        &request,
        "desktop",
        ToolExecutionContext::Interactive,
        WorkflowMode::ChatTurn,
    );
    let run = store.save_agent_run(run).unwrap();
    WorkflowDriver::new(WorkflowMode::ChatTurn)
        .reviewer()
        .completed(
            &store,
            &run.run_id,
            "msg-final",
            Some("model"),
            Some("provider"),
        )
        .unwrap();

    record_agent_queue_workflow_terminal(&store, &queue_item).unwrap();
    let updated = store.agent_run(&run.run_id).unwrap();
    let graph = updated.workflow_graph.as_ref().unwrap();
    assert_eq!(graph["currentNode"], "reviewer");
    assert_eq!(graph["currentStatus"], "completed");
    let queue = graph["nodes"]
        .as_array()
        .unwrap()
        .iter()
        .find(|node| node["node"] == "queue")
        .unwrap();
    assert_eq!(queue["status"], "completed");
    assert_eq!(queue["detail"]["queueItemId"], "queue-terminal");
    assert_eq!(queue["detail"]["queueStatus"], "completed");
    assert_eq!(queue["detail"]["queueLifecycle"], "turn_completed");
    assert_eq!(queue["detail"]["preserveCurrent"], true);

    queue_item.status = "failed".into();
    queue_item.error = Some("queue failed".into());
    record_agent_queue_workflow_terminal(&store, &queue_item).unwrap();
    let failed = store.agent_run(&run.run_id).unwrap();
    let graph = failed.workflow_graph.as_ref().unwrap();
    assert_eq!(graph["currentNode"], "reviewer");
    let queue = graph["nodes"]
        .as_array()
        .unwrap()
        .iter()
        .find(|node| node["node"] == "queue")
        .unwrap();
    assert_eq!(queue["status"], "failed");
    assert_eq!(queue["detail"]["queueStatus"], "failed");
    assert_eq!(queue["detail"]["queueLifecycle"], "turn_failed");
    assert_eq!(queue["detail"]["preserveCurrent"], true);
    assert_eq!(queue["detail"]["error"], "queue failed");

    queue_item.status = "canceled".into();
    queue_item.error = Some("Canceled by user.".into());
    record_agent_queue_workflow_terminal(&store, &queue_item).unwrap();
    let canceled = store.agent_run(&run.run_id).unwrap();
    let graph = canceled.workflow_graph.as_ref().unwrap();
    assert_eq!(graph["currentNode"], "queue");
    assert_eq!(graph["currentStatus"], "canceled");
    let queue = graph["nodes"]
        .as_array()
        .unwrap()
        .iter()
        .find(|node| node["node"] == "queue")
        .unwrap();
    assert_eq!(queue["status"], "canceled");
    assert_eq!(queue["detail"]["queueStatus"], "canceled");
    assert_eq!(queue["detail"]["queueLifecycle"], "canceled");
    assert_eq!(queue["detail"]["preserveCurrent"], false);

    let _ = fs::remove_dir_all(dir);
}

#[test]
fn workflow_driver_exposes_queue_group_room_and_checkpoint_nodes() {
    let dir = std::env::temp_dir().join(format!(
        "synthchat-workflow-driver-all-nodes-{}",
        new_id("test")
    ));
    let path = dir.join("state.json");
    let store = AppStore::new(path).unwrap();
    let mut run = AgentRunRecord::new("conv".into(), "persona".into(), "agent".into());
    run.state = "running".into();
    store.save_agent_run(run.clone()).unwrap();

    let driver = WorkflowDriver::new(WorkflowMode::ChatTurn);
    driver
        .queue()
        .completed(&store, &run.run_id, "queue-node-1")
        .unwrap();
    driver
        .group_room()
        .completed(
            &store,
            &run.run_id,
            json!({"roomId": "!room:example.org", "threadId": "thread-1"}),
        )
        .unwrap();
    driver
        .checkpoint()
        .future_wait_from_executor(
            &store,
            &run.run_id,
            "future_checkpoint_wait",
            "waiting for scheduled continuation",
            json!({"kind": "manual_test_waiting_checkpoint", "checkpointScope": "future"}),
        )
        .unwrap();
    driver
        .checkpoint()
        .completed(
            &store,
            &run.run_id,
            "pre_file_mutation",
            "checkpoint before write_file",
            json!({"kind": "manual_test_checkpoint"}),
        )
        .unwrap();
    driver
        .queue()
        .skipped(&store, &run.run_id, "already_dequeued")
        .unwrap();
    driver
        .group_room()
        .skipped(&store, &run.run_id, "not_group_context")
        .unwrap();

    let saved = store.agent_run(&run.run_id).unwrap();
    let graph = saved.workflow_graph.as_ref().unwrap();
    let nodes = graph["nodes"].as_array().unwrap();
    let queue = nodes.iter().find(|node| node["node"] == "queue").unwrap();
    assert_eq!(queue["status"], "skipped");
    assert_eq!(queue["detail"]["mode"], "chat_turn");
    assert_eq!(queue["detail"]["reason"], "already_dequeued");
    let group_room = nodes
        .iter()
        .find(|node| node["node"] == "group_room")
        .unwrap();
    assert_eq!(group_room["status"], "skipped");
    assert_eq!(group_room["detail"]["reason"], "not_group_context");
    let checkpoint = nodes
        .iter()
        .find(|node| node["node"] == "checkpoint")
        .unwrap();
    assert_eq!(checkpoint["status"], "completed");
    assert_eq!(checkpoint["detail"]["mode"], "chat_turn");
    assert_eq!(checkpoint["detail"]["state"], "pre_file_mutation");
    assert_eq!(checkpoint["detail"]["kind"], "manual_test_checkpoint");
    assert_eq!(graph["currentNode"], "checkpoint");
    assert_eq!(graph["currentStatus"], "completed");
    let checkpoint_waiting_event = saved
        .phase_events
        .iter()
        .find(|event| {
            event.phase == WORKFLOW_PHASE_NODE
                && event.detail["node"] == "checkpoint"
                && event.detail["status"] == "waiting"
        })
        .unwrap();
    assert_eq!(
        checkpoint_waiting_event.detail["detail"]["kind"],
        "manual_test_waiting_checkpoint"
    );
    assert_eq!(
        checkpoint_waiting_event.detail["detail"]["state"],
        "future_checkpoint_wait"
    );
    assert_eq!(
        checkpoint_waiting_event.detail["detail"]["checkpointScope"],
        "future"
    );
    let future_transition = graph["transitions"]
        .as_array()
        .unwrap()
        .iter()
        .find(|transition| transition["reason"] == WORKFLOW_REASON_FUTURE_CHECKPOINT_WAIT)
        .unwrap();
    assert_eq!(future_transition["from"], "executor");
    assert_eq!(future_transition["to"], "checkpoint");
    assert_eq!(
        future_transition["detail"]["summary"],
        "waiting for scheduled continuation"
    );

    let _ = fs::remove_dir_all(dir);
}

#[test]
fn workflow_planner_route_to_executor_updates_graph_snapshot() {
    let dir = std::env::temp_dir().join(format!("synthchat-workflow-route-{}", new_id("test")));
    let path = dir.join("state.json");
    let store = AppStore::new(path).unwrap();
    let mut run = AgentRunRecord::new("conv".into(), "persona".into(), "agent".into());
    run.state = "running".into();
    store.save_agent_run(run.clone()).unwrap();

    record_workflow_planner_to_executor(
        &store,
        &run.run_id,
        2,
        WorkflowMode::ChatTurn,
        3,
        &["terminal".into(), "read_file".into(), "write_file".into()],
        &[],
    )
    .unwrap();

    let saved = store.agent_run(&run.run_id).unwrap();
    assert_eq!(saved.phase_events.len(), 3);
    let graph = saved.workflow_graph.as_ref().unwrap();
    assert_eq!(graph["currentNode"], "executor");
    assert_eq!(graph["currentStatus"], "running");
    let nodes = graph["nodes"].as_array().unwrap();
    let planner = nodes.iter().find(|node| node["node"] == "planner").unwrap();
    assert_eq!(planner["status"], "completed");
    assert_eq!(planner["detail"]["action"], "tool");
    assert_eq!(planner["detail"]["toolCount"], 3);
    assert_eq!(
        planner["detail"]["tools"],
        json!(["terminal", "read_file", "write_file"])
    );
    let executor = nodes
        .iter()
        .find(|node| node["node"] == "executor")
        .unwrap();
    assert_eq!(executor["status"], "running");
    assert_eq!(executor["detail"]["toolCount"], 3);
    assert_eq!(
        executor["detail"]["tools"],
        json!(["terminal", "read_file", "write_file"])
    );
    let transitions = graph["transitions"].as_array().unwrap();
    assert_eq!(transitions.len(), 1);
    assert_eq!(transitions[0]["from"], "planner");
    assert_eq!(transitions[0]["to"], "executor");
    assert_eq!(transitions[0]["reason"], WORKFLOW_REASON_TOOL_CALLS);
    assert_eq!(
        transitions[0]["detail"]["tools"],
        json!(["terminal", "read_file", "write_file"])
    );

    let _ = fs::remove_dir_all(dir);
}

fn assert_workflow_planner_route_records_tool_call_origin(
    decision_text: &str,
    expected_origin: &str,
    expected_call_id: Option<&str>,
) {
    let dir = std::env::temp_dir().join(format!("synthchat-workflow-origin-{}", new_id("test")));
    let path = dir.join("state.json");
    let store = AppStore::new(path).unwrap();
    let mut run = AgentRunRecord::new("conv".into(), "persona".into(), "agent".into());
    run.state = "running".into();
    store.save_agent_run(run.clone()).unwrap();

    let decision = parse_agent_decision(decision_text);
    let route = resolve_workflow_planner_route(
        &store,
        &run.run_id,
        1,
        WorkflowMode::ChatTurn,
        &decision,
        decision_text,
        &[test_internal_tool("terminal")],
    )
    .unwrap();

    match route {
        WorkflowPlannerRoute::ExecuteTools {
            request_count,
            requests,
        } => {
            assert_eq!(request_count, 1);
            assert_eq!(requests[0].0, "terminal");
        }
        other => panic!("expected execute tools route, got {other:?}"),
    }

    let saved = store.agent_run(&run.run_id).unwrap();
    let graph = saved.workflow_graph.as_ref().unwrap();
    let nodes = graph["nodes"].as_array().unwrap();
    let planner = nodes.iter().find(|node| node["node"] == "planner").unwrap();
    assert_eq!(planner["detail"]["toolProtocol"], "canonical_tool_call_v1");
    assert_eq!(planner["detail"]["tool_protocol"], "canonical_tool_call_v1");
    assert_eq!(planner["detail"]["toolOrigins"], json!([expected_origin]));
    assert_eq!(planner["detail"]["tool_origins"], json!([expected_origin]));
    assert_eq!(planner["detail"]["toolCalls"][0]["name"], "terminal");
    assert_eq!(
        planner["detail"]["tool_calls"][0]["origin"],
        expected_origin
    );

    let executor = nodes
        .iter()
        .find(|node| node["node"] == "executor")
        .unwrap();
    assert_eq!(executor["detail"]["toolOrigins"], json!([expected_origin]));
    let transition = graph["transitions"]
        .as_array()
        .unwrap()
        .iter()
        .find(|transition| transition["reason"] == WORKFLOW_REASON_TOOL_CALLS)
        .unwrap();
    assert_eq!(
        transition["detail"]["toolOrigins"],
        json!([expected_origin])
    );

    match expected_call_id {
        Some(call_id) => {
            assert_eq!(planner["detail"]["toolCallIds"], json!([call_id]));
            assert_eq!(planner["detail"]["tool_call_ids"], json!([call_id]));
            assert_eq!(planner["detail"]["toolCalls"][0]["id"], call_id);
            assert_eq!(planner["detail"]["toolCalls"][0]["providerNative"], true);
            assert_eq!(planner["detail"]["tool_calls"][0]["provider_native"], true);
        }
        None => {
            assert_eq!(planner["detail"]["toolCallIds"], json!([]));
            assert_eq!(planner["detail"]["tool_call_ids"], json!([]));
            assert!(planner["detail"]["toolCalls"][0].get("id").is_none());
        }
    }

    let _ = fs::remove_dir_all(dir);
}

