#[test]
fn automatic_mutation_checkpoint_emits_workflow_checkpoint_event() {
    let dir = std::env::temp_dir().join(format!("synthchat-workflow-ckpt-{}", new_id("test")));
    let path = dir.join("state.json");
    let store = AppStore::new(path).unwrap();
    let mut run = AgentRunRecord::new("conv".into(), "persona".into(), "agent".into());
    run.state = "running".into();
    store.save_agent_run(run.clone()).unwrap();

    automatic_mutation_checkpoint(
        &store,
        &run.run_id,
        "write_file",
        &json!({"path": "src/main.rs"}),
    )
    .unwrap();

    let saved = store.agent_run(&run.run_id).unwrap();
    let workflow_checkpoint = saved
        .phase_events
        .iter()
        .find(|event| {
            event.phase == WORKFLOW_PHASE_NODE
                && event.detail["node"] == "checkpoint"
                && event.detail["detail"]["kind"] == "automatic_mutation_checkpoint"
        })
        .unwrap();
    assert_eq!(workflow_checkpoint.detail["status"], "completed");
    assert_eq!(workflow_checkpoint.detail["detail"]["mode"], "chat_turn");
    assert_eq!(
        workflow_checkpoint.detail["detail"]["checkpointScope"],
        "pre_mutation"
    );
    assert_eq!(workflow_checkpoint.detail["detail"]["mutationKind"], "file");
    assert_eq!(
        workflow_checkpoint.detail["detail"]["targetSummary"],
        "path=src/main.rs"
    );
    assert_eq!(
        workflow_checkpoint.detail["detail"]["toolName"],
        "write_file"
    );
    let graph = saved.workflow_graph.as_ref().unwrap();
    assert_eq!(graph["currentNode"], "checkpoint");
    assert_eq!(graph["nodes"][0]["node"], "checkpoint");
    assert_eq!(
        graph["nodes"][0]["detail"]["kind"],
        "automatic_mutation_checkpoint"
    );
    assert_eq!(graph["nodes"][0]["detail"]["mode"], "chat_turn");
    assert_eq!(
        graph["nodes"][0]["detail"]["checkpointScope"],
        "pre_mutation"
    );
    assert_eq!(
        graph["nodes"][0]["detail"]["targetSummary"],
        "path=src/main.rs"
    );

    let _ = fs::remove_dir_all(dir);
}

#[test]
fn manual_checkpoint_tool_emits_typed_workflow_checkpoint_event() {
    let dir =
        std::env::temp_dir().join(format!("synthchat-workflow-manual-ckpt-{}", new_id("test")));
    let path = dir.join("state.json");
    let store = AppStore::new(path).unwrap();
    let mut run = AgentRunRecord::new("conv".into(), "persona".into(), "agent".into());
    run.state = "running".into();
    store.save_agent_run(run.clone()).unwrap();

    checkpoint_tool(
        &store,
        &run.run_id,
        &json!({"state": "manual_review", "summary": "Review the edits"}),
    )
    .unwrap();

    let saved = store.agent_run(&run.run_id).unwrap();
    let graph = saved.workflow_graph.as_ref().unwrap();
    let checkpoint = graph["nodes"]
        .as_array()
        .unwrap()
        .iter()
        .find(|node| node["node"] == "checkpoint")
        .unwrap();
    assert_eq!(checkpoint["status"], "completed");
    assert_eq!(checkpoint["detail"]["mode"], "chat_turn");
    assert_eq!(checkpoint["detail"]["state"], "manual_review");
    assert_eq!(checkpoint["detail"]["kind"], "manual_checkpoint");

    let _ = fs::remove_dir_all(dir);
}

#[test]
fn env_probe_reports_workspace_and_command_availability() {
    let dir = std::env::temp_dir().join(format!("synthchat-env-probe-{}", new_id("test")));
    fs::create_dir_all(dir.join("src-tauri")).unwrap();
    fs::write(dir.join("Cargo.toml"), "[package]\nname = \"probe\"\n").unwrap();
    fs::write(dir.join("package.json"), "{}").unwrap();
    fs::write(dir.join("src-tauri").join("tauri.conf.json"), "{}").unwrap();
    let mut agent = AgentDefinition::default();
    agent.workspace_dir = dir.to_string_lossy().to_string();

    let output = env_probe::env_probe_tool(
        &agent,
        &json!({
            "commands": ["definitely_missing_synthchat_probe_command"]
        }),
    )
    .unwrap();
    let value: Value = serde_json::from_str(&output).unwrap();

    assert_eq!(value["workspace"]["signals"]["rust"], true);
    assert_eq!(value["workspace"]["signals"]["node"], true);
    assert_eq!(value["workspace"]["signals"]["tauri"], true);
    assert_eq!(value["terminal"]["envType"], "local");
    assert_eq!(
        value["commands"][0]["name"],
        "definitely_missing_synthchat_probe_command"
    );
    assert_eq!(value["commands"][0]["available"], false);
    assert!(is_internal_tool("env_probe"));

    let _ = fs::remove_dir_all(dir);
}
